import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle, Copy, FileWarning } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    successMessage?: string;
}

interface ErrorModalState {
    isOpen: boolean;
    message: string;
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Delete Confirmation Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });

  // Import Conflict Modal State
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);

  // Error Modal State
  const [errorModal, setErrorModal] = useState<ErrorModalState>({ isOpen: false, message: '' });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, [loadTags]);

  // Step 1: Initiate Import and Check for Duplicates
  const initiateImport = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;

    // Fetch latest sheets from DB
    const currentSheets = await storage.getAllSheets();

    // Check for duplicates
    const duplicates = newSheets.filter(newSheet => 
        currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
    );

    if (duplicates.length > 0) {
        // Trigger Modal
        setConflictData({ newSheets, duplicates, successMessage });
    } else {
        // No conflicts, proceed directly
        await finalizeImport(newSheets, false, successMessage);
    }
  };

  // Step 2: Finalize Import (Executed after conflict resolution or if no conflicts)
  const finalizeImport = async (newSheets: Sheet[], overwrite: boolean, successMessage?: string) => {
      const currentSheets = await storage.getAllSheets();
      let count = 0;

      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());

          let sheetToSave = sheet;

          if (existing && overwrite) {
              // Overwrite: Use existing ID, preserve tags/icons
              sheetToSave = {
                  ...sheet,
                  id: existing.id,
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }

          await storage.addSheet(sheetToSave);
          count++;
      }

      setConflictData(null); // Close modal if open

      if (successMessage) {
          // Small timeout to allow modal to close visually first
          setTimeout(() => alert(successMessage), 100);
      }
      onRefresh();
  };

  // Handle individual files
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = {
          blob: file,
          fileType: file.type as any
        };

        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        };
        newSheets.push(newSheet);
      }

      await initiateImport(newSheets);
    }
    // Reset input
    if (e.target) e.target.value = '';
  };

  // Handle Single Folder Import
  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;

      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";

      const pages: SheetPage[] = files.map(f => ({
          blob: f,
          fileType: f.type as any
      }));

      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };

      await initiateImport([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  // Handle Batch Import
  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            setErrorModal({ isOpen: true, message: result.error });
            if (e.target) e.target.value = '';
            return;
        }
        if (result.sheets.length > 0) {
            await initiateImport(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  // Initial Delete Click - Opens Modal
  const handleDeleteClick = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);

    setDeleteModal({
        isOpen: true,
        sheet: sheet,
        affectedSetlists: affected
    });
  };

  // Confirm Delete Action
  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName);
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };
      const tagExists = allTags.some(t => t.label === tagName);
      if (!tagExists) {
          const optimisticTags = [...allTags, newTagDef];
          setAllTags(optimisticTags);
          try {
            await storage.saveTag(newTagDef);
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            await loadTags();
          }
      }
      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) {
        setEditTags([...editTags, tag]);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const confirmDeleteTag = async (label: string) => {
      const newTags = allTags.filter(t => t.label !== label);
      setAllTags(newTags);
      setTagToDelete(null);
      try {
        await storage.deleteTag(label);
        const latestTags = await storage.getAllTags();
        setAllTags(latestTags);
      } catch (err) {
        console.error("Failed to delete tag", err);
        loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  const getTagIcon = (tag: string, sheet?: Sheet) => {
    if (sheet?.tagIcons?.[tag]) {
        return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    }
    if (editTagIcons[tag]) {
        return ICON_MAP[editTagIcons[tag]] || Tag;
    }
    const def = allTags.find(t => t.label === tag);
    if (def) return ICON_MAP[def.iconName] || Tag;
    return Tag;
  };

  const CurrentInputIcon = ICON_MAP[selectedIconName] || Tag;

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button 
                    onClick={() => batchInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap"
                    title="Import multiple sheets (folders or files) at once with verification"
                >
                    <LibraryIcon size={20} />
                    <span className="hidden sm:inline">Batch Import</span>
                </button>

                <div className="flex gap-2 w-full">
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95 whitespace-nowrap"
                    >
                        <Upload size={20} />
                        <span className="hidden sm:inline">File</span>
                    </button>

                    <button 
                        onClick={() => folderInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap"
                        title="Import a folder containing pages as ONE sheet"
                    >
                        <FolderUp size={20} />
                        <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>

        <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/jpeg, application/pdf" multiple onChange={handleFileChange} />
        <input type="file" ref={folderInputRef} className="hidden" 
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleFolderChange} 
        />
        <input type="file" ref={batchInputRef} className="hidden"
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleBatchImport} 
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const fileCount = sheet.pages.length;
             const firstPage = sheet.pages?.[0];
             const isPdf = firstPage?.fileType === 'application/pdf';
             return (
                <div 
                key={sheet.id}
                onClick={() => onSelect(sheet.id)}
                className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
                >
                <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />

                    <div className="flex flex-col items-center gap-2">
                        {isPdf ? (
                            <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                        ) : (
                            <Music size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                        )}
                        <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                            {fileCount > 1 ? `${fileCount} ${isPdf ? 'Files' : 'Pages'}` : (isPdf ? 'PDF' : 'Image')}
                        </span>
                    </div>

                    {fileCount > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {fileCount}
                        </div>
                    )}

                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const Icon = getTagIcon(tag, sheet);
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>
                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-100 z-30">
                    <button onClick={(e) => openEditModal(e, sheet)} className="p-2 bg-black/70 text-white rounded-full hover:bg-blue-600 backdrop-blur transition-colors" title="Edit Details"><PenLine size={14} /></button>
                    <button onClick={(e) => handleDeleteClick(e, sheet)} className="p-2 bg-black/70 text-white rounded-full hover:bg-red-500 backdrop-blur transition-colors" title="Delete"><Trash2 size={14} /></button>
                </div>
                </div>
             );
          })}
        </div>
      )}
      {/* Rest of component omitted for brevity as it remains unchanged */}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import, FileWarning, AlertTriangle, Copy, Save, ChevronUp, ChevronDown } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    setlistName?: string;
}

interface ErrorModalState {
    isOpen: boolean;
    message: string;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // Drag State for Touch/Pointer
  const [isDragging, setIsDragging] = useState(false);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  // Delete Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });

  // Import Conflict Modal State
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);

  // Error Modal State
  const [errorModal, setErrorModal] = useState<ErrorModalState>({ isOpen: false, message: '' });

  const importInputRef = useRef<HTMLInputElement>(null);

  // Search States
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setLibrarySearch('');
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;

    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;

    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };

    await storage.saveSetlist(setlist);
    closeEditor();
    onRefresh();
  };

  const closeEditor = () => {
    setIsEditing(false);
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  const moveItem = (fromIndex: number, toIndex: number) => {
    if (toIndex < 0 || toIndex >= selectedSheetIds.length) return;
    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(fromIndex, 1);
    newIds.splice(toIndex, 0, removed);
    setSelectedSheetIds(newIds);
  };

  // --- Improved Pointer-based Drag Logic ---

  const handlePointerDown = (index: number) => {
    setDraggedIndex(index);
    setIsDragging(true);
  };

  const handlePointerEnter = (targetIndex: number) => {
    if (isDragging && draggedIndex !== null && draggedIndex !== targetIndex) {
      moveItem(draggedIndex, targetIndex);
      setDraggedIndex(targetIndex);
    }
  };

  const handlePointerUp = () => {
    setIsDragging(false);
    setDraggedIndex(null);
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist: setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            setErrorModal({ isOpen: true, message: result.error });
            if (e.target) e.target.value = '';
            return;
        }

        if (result.sheets.length > 0) {
            const currentSheets = await storage.getAllSheets();
            const duplicates = result.sheets.filter(newSheet => 
                currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
            );

            if (duplicates.length > 0) {
                setConflictData({ newSheets: result.sheets, duplicates, setlistName: result.setlistName });
            } else {
                await finalizeSetlistImport(result.sheets, false, result.setlistName);
            }
        } else {
            alert("No valid files found for import.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const finalizeSetlistImport = async (newSheets: Sheet[], overwrite: boolean, setlistName?: string) => {
        const currentSheets = await storage.getAllSheets();
        const sheetsToSave = newSheets.map(sheet => {
            const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
            if (existing && overwrite) {
                return {
                    ...sheet,
                    id: existing.id,
                    tags: existing.tags,
                    tagIcons: existing.tagIcons,
                    dateAdded: Date.now()
                };
            }
            return sheet;
        });

        for (const sheet of sheetsToSave) {
            await storage.addSheet(sheet);
        }

        const sortedSheets = [...sheetsToSave].sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }));
        const sortedIds = sortedSheets.map(s => s.id);
        const name = setlistName || "Imported Setlist";

        const newSetlist: Setlist = {
            id: crypto.randomUUID(),
            name: name,
            sheetIds: sortedIds,
            dateCreated: Date.now()
        };

        await storage.saveSetlist(newSetlist);
        setConflictData(null);
        onRefresh();
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => 
        s.name.toLowerCase().includes(q) || 
        (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col" onPointerUp={handlePointerUp}>
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={closeEditor} className="p-2 text-slate-400 hover:text-white"><X /></button>
             <button 
                onClick={handleSave} 
                disabled={!newSetName || selectedSheetIds.length === 0}
                className="flex items-center gap-2 bg-green-600 hover:bg-green-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg"
             >
                <Check size={18} />
                <span>Save</span>
             </button>
           </div>
        </div>

        <input 
          type="text" 
          placeholder="Setlist Name (e.g., Wedding Gig)"
          className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
          value={newSetName}
          onChange={e => setNewSetName(e.target.value)}
        />

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Library (Tap to add)</h3>
                <div className="relative mb-3">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                    <input 
                        type="text" 
                        placeholder="Filter library..." 
                        className="w-full bg-slate-900 border border-slate-700 rounded-md pl-9 pr-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-blue-500"
                        value={librarySearch}
                        onChange={(e) => setLibrarySearch(e.target.value)}
                    />
                </div>
                <div className="overflow-y-auto space-y-2 flex-1">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div 
                                key={sheet.id}
                                onClick={() => !isSelected && toggleSelection(sheet.id)}
                                className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 cursor-not-allowed border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}
                            >
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 text-xs font-bold shrink-0 ${isSelected ? 'bg-slate-600 text-slate-400' : 'bg-blue-600 text-white'}`}>
                                    {isSelected ? <Check size={12}/> : <Plus size={12} />}
                                </div>
                                <div className="min-w-0">
                                    <div className="text-slate-200 truncate text-sm">{sheet.name}</div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-3">Selected Order (Drag handle to reorder)</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="text-slate-500 text-center py-8 italic">No sheets selected</div>
                ) : (
                    <div className="space-y-2 select-none">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isActive = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    onPointerEnter={() => handlePointerEnter(index)}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isActive ? 'scale-[1.02] border-blue-500 bg-slate-700 shadow-xl z-10' : 'border-slate-700'}`}
                                >
                                    <div 
                                        className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none"
                                        onPointerDown={() => handlePointerDown(index)}
                                    >
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-6 text-center text-slate-500 font-mono text-sm">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2 text-sm">{sheet.name}</span>

                                    <div className="flex items-center gap-1">
                                        <button 
                                            onClick={() => moveItem(index, index - 1)}
                                            disabled={index === 0}
                                            className="p-2 text-slate-400 hover:text-white disabled:opacity-20 hidden sm:block"
                                            title="Move Up"
                                        >
                                            <ChevronUp size={18} />
                                        </button>
                                        <button 
                                            onClick={() => moveItem(index, index + 1)}
                                            disabled={index === selectedSheetIds.length - 1}
                                            className="p-2 text-slate-400 hover:text-white disabled:opacity-20 hidden sm:block"
                                            title="Move Down"
                                        >
                                            <ChevronDown size={18} />
                                        </button>
                                        <button 
                                            onClick={() => toggleSelection(id)}
                                            className="p-2 text-red-400 hover:bg-red-500/20 rounded ml-1"
                                            title="Remove"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div>
           <h1 className="text-3xl font-bold text-white mb-1">Setlists</h1>
           <p className="text-slate-400 text-sm">Organize your repertoire</p>
        </div>
        <div className="flex gap-3 items-start">
            <div className="relative md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search setlists..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={listSearch}
                    onChange={(e) => setListSearch(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2">
                <button 
                    onClick={() => importInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                >
                    <Import size={20} />
                    <span className="hidden sm:inline">Import Setlist</span>
                </button>
                <button 
                    onClick={startCreate}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg active:scale-95 transition-all whitespace-nowrap"
                >
                    <Plus size={20} />
                    <span className="hidden sm:inline">New Setlist</span>
                </button>
            </div>

            <input type="file" ref={importInputRef} className="hidden" 
                // @ts-ignore
                webkitdirectory="" directory="" multiple onChange={handleImportSetlist} 
            />
        </div>
      </div>

      {setlists.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <ListMusic size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No setlists yet</p>
        </div>
      ) : filteredSetlists.length === 0 ? (
        <div className="text-center py-12 text-slate-500">
            <p>No setlists found matching "{listSearch}"</p>
        </div>
      ) : (
        <div className="space-y-4">
          {filteredSetlists.map((list) => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between group hover:bg-slate-750 transition-colors">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="w-12 h-12 bg-slate-700 rounded-lg flex items-center justify-center text-slate-400">
                     <ListMusic size={24} />
                  </div>
                  <div>
                      <h3 className="text-lg font-medium text-white">{list.name}</h3>
                      <p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p>
                  </div>
               </div>

               <div className="flex items-center gap-2">
                   <button 
                     onClick={() => onPlay(list)}
                     className="p-3 bg-green-600 text-white rounded-full hover:bg-green-500 transition-colors shadow-lg shadow-green-900/20"
                     title="Start Performance"
                   >
                       <Play size={20} fill="currentColor" />
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-2" />
                   <button onClick={() => startEdit(list)} className="p-2 text-slate-400 hover:text-blue-400 transition-colors bg-slate-900/50 rounded-lg"><Pencil size={18} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-2 text-slate-400 hover:text-red-400 transition-colors bg-slate-900/50 rounded-lg"><Trash2 size={18} /></button>
               </div>
            </div>
          ))}
        </div>
      )}
      {/* Modals omitted for brevity as they are unchanged */}
    </div>
  );
};

export default Setlists;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle, Copy, FileWarning } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    successMessage?: string;
}

interface ErrorModalState {
    isOpen: boolean;
    message: string;
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Delete Confirmation Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });

  // Import Conflict Modal State
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);

  // Error Modal State
  const [errorModal, setErrorModal] = useState<ErrorModalState>({ isOpen: false, message: '' });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, [loadTags]);

  // Step 1: Initiate Import and Check for Duplicates
  const initiateImport = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;

    // Fetch latest sheets from DB
    const currentSheets = await storage.getAllSheets();

    // Check for duplicates
    const duplicates = newSheets.filter(newSheet => 
        currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
    );

    if (duplicates.length > 0) {
        // Trigger Modal
        setConflictData({ newSheets, duplicates, successMessage });
    } else {
        // No conflicts, proceed directly
        await finalizeImport(newSheets, false, successMessage);
    }
  };

  // Step 2: Finalize Import (Executed after conflict resolution or if no conflicts)
  const finalizeImport = async (newSheets: Sheet[], overwrite: boolean, successMessage?: string) => {
      const currentSheets = await storage.getAllSheets();
      let count = 0;

      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());

          let sheetToSave = sheet;

          if (existing && overwrite) {
              // Overwrite: Use existing ID, preserve tags/icons
              sheetToSave = {
                  ...sheet,
                  id: existing.id,
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }

          await storage.addSheet(sheetToSave);
          count++;
      }

      setConflictData(null); // Close modal if open

      if (successMessage) {
          // Small timeout to allow modal to close visually first
          setTimeout(() => alert(successMessage), 100);
      }
      onRefresh();
  };

  // Handle individual files
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = {
          blob: file,
          fileType: file.type as any
        };

        const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        };
        newSheets.push(newSheet);
      }

      await initiateImport(newSheets);
    }
    // Reset input
    if (e.target) e.target.value = '';
  };

  // Handle Single Folder Import
  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      // Fix: Cast Array.from result to File[] to fix 'unknown' type errors for .name, .type, and .webkitRelativePath
      const files = (Array.from(e.target.files) as File[]).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;

      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";

      const pages: SheetPage[] = files.map(f => ({
          blob: f,
          fileType: f.type as any
      }));

      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };

      await initiateImport([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  // Handle Batch Import
  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            setErrorModal({ isOpen: true, message: result.error });
            if (e.target) e.target.value = '';
            return;
        }
        if (result.sheets.length > 0) {
            await initiateImport(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  // Initial Delete Click - Opens Modal
  const handleDeleteClick = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);

    setDeleteModal({
        isOpen: true,
        sheet: sheet,
        affectedSetlists: affected
    });
  };

  // Confirm Delete Action
  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName);
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };
      const tagExists = allTags.some(t => t.label === tagName);
      if (!tagExists) {
          const optimisticTags = [...allTags, newTagDef];
          setAllTags(optimisticTags);
          try {
            await storage.saveTag(newTagDef);
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            await loadTags();
          }
      }
      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) {
        setEditTags([...editTags, tag]);
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const confirmDeleteTag = async (label: string) => {
      const newTags = allTags.filter(t => t.label !== label);
      setAllTags(newTags);
      setTagToDelete(null);
      try {
        await storage.deleteTag(label);
        const latestTags = await storage.getAllTags();
        setAllTags(latestTags);
      } catch (err) {
        console.error("Failed to delete tag", err);
        loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  const getTagIcon = (tag: string, sheet?: Sheet) => {
    if (sheet?.tagIcons?.[tag]) {
        return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    }
    if (editTagIcons[tag]) {
        return ICON_MAP[editTagIcons[tag]] || Tag;
    }
    const def = allTags.find(t => t.label === tag);
    if (def) return ICON_MAP[def.iconName] || Tag;
    return Tag;
  };

  const CurrentInputIcon = ICON_MAP[selectedIconName] || Tag;

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button 
                    onClick={() => batchInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap"
                    title="Import multiple sheets (folders or files) at once with verification"
                >
                    <LibraryIcon size={20} />
                    <span className="hidden sm:inline">Batch Import</span>
                </button>

                <div className="flex gap-2 w-full">
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg shadow-blue-900/20 transition-all active:scale-95 whitespace-nowrap"
                    >
                        <Upload size={20} />
                        <span className="hidden sm:inline">File</span>
                    </button>

                    <button 
                        onClick={() => folderInputRef.current?.click()}
                        className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap"
                        title="Import a folder containing pages as ONE sheet"
                    >
                        <FolderUp size={20} />
                        <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>

        <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/jpeg, application/pdf" multiple onChange={handleFileChange} />
        <input type="file" ref={folderInputRef} className="hidden" 
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleFolderChange} 
        />
        <input type="file" ref={batchInputRef} className="hidden"
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleBatchImport} 
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <div className="bg-slate-800 p-4 rounded-full mb-4">
             <Upload size={32} className="text-slate-400" />
          </div>
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
          <p className="text-slate-500 text-sm mt-1">Import PDF, PNG or JPG files to start</p>
        </div>
      ) : filteredSheets.length === 0 ? (
          <div className="text-center py-12 text-slate-500">
              <p>No results found for "{searchQuery}"</p>
          </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const fileCount = sheet.pages.length;
             const firstPage = sheet.pages?.[0];
             const isPdf = firstPage?.fileType === 'application/pdf';
             return (
                <div 
                key={sheet.id}
                onClick={() => onSelect(sheet.id)}
                className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col"
                >
                <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />

                    <div className="flex flex-col items-center gap-2">
                        {isPdf ? (
                            <FileText size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                        ) : (
                            <Music size={48} className="text-slate-600 group-hover:text-slate-400 transition-colors" />
                        )}
                        <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                            {fileCount > 1 ? `${fileCount} ${isPdf ? 'Files' : 'Pages'}` : (isPdf ? 'PDF' : 'Image')}
                        </span>
                    </div>

                    {fileCount > 1 && (
                        <div className="absolute top-2 left-2 z-20 bg-black/60 text-white px-2 py-0.5 rounded text-xs flex items-center gap-1">
                            <Layers size={12} /> {fileCount}
                        </div>
                    )}

                    <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                        {(sheet.tags || []).slice(0, 4).map(tag => {
                            const Icon = getTagIcon(tag, sheet);
                            return (
                                <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30" title={tag}>
                                    <Icon size={12} />
                                </span>
                            );
                        })}
                    </div>
                </div>
                <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                    <h3 className="text-white font-medium text-sm truncate" title={sheet.name}>{sheet.name}</h3>
                    <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                </div>
                <div className="absolute top-2 right-2 flex flex-col gap-2 opacity-100 z-30">
                    <button onClick={(e) => openEditModal(e, sheet)} className="p-2 bg-black/70 text-white rounded-full hover:bg-blue-600 backdrop-blur transition-colors" title="Edit Details"><PenLine size={14} /></button>
                    <button onClick={(e) => handleDeleteClick(e, sheet)} className="p-2 bg-black/70 text-white rounded-full hover:bg-red-500 backdrop-blur transition-colors" title="Delete"><Trash2 size={14} /></button>
                </div>
                </div>
             );
          })}
        </div>
      )}
      {/* Rest of component omitted for brevity as it remains unchanged */}
    </div>
  );
};

export default Library;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle, Copy, FileWarning } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    successMessage?: string;
}

interface ErrorModalState {
    isOpen: boolean;
    message: string;
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Delete Confirmation Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });

  // Import Conflict Modal State
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);

  // Error Modal State
  const [errorModal, setErrorModal] = useState<ErrorModalState>({ isOpen: false, message: '' });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  // Load global tags on mount
  useEffect(() => {
    loadTags();
  }, [loadTags]);

  const initiateImport = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;
    const currentSheets = await storage.getAllSheets();
    const duplicates = newSheets.filter(newSheet => 
        currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
    );

    if (duplicates.length > 0) {
        setConflictData({ newSheets, duplicates, successMessage });
    } else {
        await finalizeImport(newSheets, false, successMessage);
    }
  };

  const finalizeImport = async (newSheets: Sheet[], overwrite: boolean, successMessage?: string) => {
      const currentSheets = await storage.getAllSheets();
      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
          let sheetToSave = sheet;
          if (existing && overwrite) {
              sheetToSave = {
                  ...sheet,
                  id: existing.id,
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }
          await storage.addSheet(sheetToSave);
      }
      setConflictData(null);
      if (successMessage) setTimeout(() => alert(successMessage), 100);
      onRefresh();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = { blob: file, fileType: file.type as any };
        newSheets.push({
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        });
      }
      await initiateImport(newSheets);
    }
    if (e.target) e.target.value = '';
  };

  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = (Array.from(e.target.files) as File[]).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;
      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";
      const pages: SheetPage[] = files.map(f => ({ blob: f, fileType: f.type as any }));
      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };
      await initiateImport([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            setErrorModal({ isOpen: true, message: result.error });
            if (e.target) e.target.value = '';
            return;
        }
        if (result.sheets.length > 0) {
            await initiateImport(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const handleDeleteClick = (e: React.MouseEvent | React.PointerEvent, sheet: Sheet) => {
    e.stopPropagation();
    if (e.cancelable) e.preventDefault();
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);
    setDeleteModal({ isOpen: true, sheet, affectedSetlists: affected });
  };

  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent | React.PointerEvent, sheet: Sheet) => {
    e.stopPropagation();
    if (e.cancelable) e.preventDefault();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      addTag(tagName);
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };
      if (!allTags.some(t => t.label === tagName)) {
          setAllTags(prev => [...prev, newTagDef]);
          try {
            await storage.saveTag(newTagDef);
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            await loadTags();
          }
      }
      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const addTag = (tag: string) => {
    if (!editTags.includes(tag)) setEditTags([...editTags, tag]);
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const confirmDeleteTag = async (label: string) => {
      setAllTags(prev => prev.filter(t => t.label !== label));
      setTagToDelete(null);
      try {
        await storage.deleteTag(label);
        const latestTags = await storage.getAllTags();
        setAllTags(latestTags);
      } catch (err) {
        console.error("Failed to delete tag", err);
        loadTags();
      }
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  const getTagIcon = (tag: string, sheet?: Sheet) => {
    if (sheet?.tagIcons?.[tag]) return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    if (editTagIcons[tag]) return ICON_MAP[editTagIcons[tag]] || Tag;
    const def = allTags.find(t => t.label === tag);
    return def ? ICON_MAP[def.iconName] || Tag : Tag;
  };

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button 
                    onClick={() => batchInputRef.current?.click()}
                    className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap"
                >
                    <LibraryIcon size={20} />
                    <span className="hidden sm:inline">Batch Import</span>
                </button>

                <div className="flex gap-2 w-full">
                    <button onClick={() => fileInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap">
                        <Upload size={20} /> <span className="hidden sm:inline">File</span>
                    </button>
                    <button onClick={() => folderInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap">
                        <FolderUp size={20} /> <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/jpeg, application/pdf" multiple onChange={handleFileChange} />
        <input type="file" ref={folderInputRef} className="hidden" 
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleFolderChange} 
        />
        <input type="file" ref={batchInputRef} className="hidden"
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleBatchImport} 
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <Upload size={32} className="text-slate-400 mb-4" />
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const fileCount = sheet.pages.length;
             const isPdf = sheet.pages?.[0]?.fileType === 'application/pdf';
             return (
                <div key={sheet.id} onClick={() => onSelect(sheet.id)} className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col">
                    <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />
                        <div className="flex flex-col items-center gap-2">
                            {isPdf ? <FileText size={48} className="text-slate-600" /> : <Music size={48} className="text-slate-600" />}
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {fileCount > 1 ? `${fileCount} ${isPdf ? 'Files' : 'Pages'}` : (isPdf ? 'PDF' : 'Image')}
                            </span>
                        </div>
                        <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                            {(sheet.tags || []).slice(0, 4).map(tag => {
                                const Icon = getTagIcon(tag, sheet);
                                return <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30"><Icon size={12} /></span>;
                            })}
                        </div>
                    </div>
                    <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                        <h3 className="text-white font-medium text-sm truncate">{sheet.name}</h3>
                        <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                    </div>
                    {/* Management buttons with high-priority touch handling */}
                    <div className="absolute top-2 right-2 flex flex-col gap-2 z-30">
                        <button 
                            onPointerDown={(e) => openEditModal(e, sheet)}
                            onClick={(e) => { e.stopPropagation(); e.preventDefault(); }} 
                            className="p-3 bg-black/80 text-white rounded-full hover:bg-blue-600 active:scale-95 transition-all shadow-xl"
                        >
                            <PenLine size={16} />
                        </button>
                        <button 
                            onPointerDown={(e) => handleDeleteClick(e, sheet)}
                            onClick={(e) => { e.stopPropagation(); e.preventDefault(); }}
                            className="p-3 bg-black/80 text-white rounded-full hover:bg-red-500 active:scale-95 transition-all shadow-xl"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Modals (Delete, Edit, etc) */}
      {deleteModal.isOpen && deleteModal.sheet && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-md shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
            <div className="p-6">
                <AlertTriangle size={24} className="text-red-500 mb-4" />
                <h2 className="text-xl font-bold text-white mb-2">Delete "{deleteModal.sheet.name}"?</h2>
                <p className="text-slate-400 text-sm mb-4">This will permanently remove the sheet and its annotations.</p>
            </div>
            <div className="p-4 bg-slate-950 border-t border-slate-800 flex gap-3">
                <button onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })} className="flex-1 px-4 py-2.5 bg-slate-800 text-white rounded-lg">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 px-4 py-2.5 bg-red-600 text-white rounded-lg">Delete</button>
            </div>
          </div>
        </div>
      )}

      {editingSheet && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={closeEditModal}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-lg shadow-2xl flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
                <h2 className="text-xl font-bold text-white">Edit Sheet</h2>
                <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X /></button>
            </div>
            <div className="p-6 space-y-6 overflow-y-auto">
                <input type="text" className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white" value={editName} onChange={e => setEditName(e.target.value)} />
                <div className="flex flex-wrap gap-2 mb-4">
                    {editTags.map(tag => (
                        <span key={tag} className="inline-flex items-center gap-2 px-3 py-1.5 bg-blue-600/20 text-blue-300 border border-blue-500/30 rounded-full text-sm">
                            {React.createElement(getTagIcon(tag), { size: 14 })}
                            {tag} <button onClick={() => handleRemoveTag(tag)}><X size={14}/></button>
                        </span>
                    ))}
                </div>
                <div className="flex gap-2">
                    <input type="text" className="flex-1 bg-slate-800 border border-slate-700 rounded-lg px-4 text-white" placeholder="Add tag..." value={tagInput} onChange={e => setTagInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAddTag()} />
                    <button onClick={handleAddTag} className="px-4 bg-blue-600 text-white rounded-lg"><Plus size={20} /></button>
                </div>
            </div>
            <div className="p-4 bg-slate-950 border-t border-slate-800 flex gap-3">
                <button onClick={closeEditModal} className="flex-1 px-4 py-2.5 bg-slate-800 text-white rounded-lg">Cancel</button>
                <button onClick={saveEdits} className="flex-1 px-4 py-2.5 bg-blue-600 text-white rounded-lg">Save</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import, FileWarning, AlertTriangle, Copy, Save, ChevronUp, ChevronDown } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // Drag State for Touch/Pointer
  const [isDragging, setIsDragging] = useState(false);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });
  const importInputRef = useRef<HTMLInputElement>(null);
  const listSearchRef = useRef<string>('');
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;
    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;
    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };
    await storage.saveSetlist(setlist);
    setIsEditing(false);
    onRefresh();
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  const moveItem = (fromIndex: number, toIndex: number) => {
    if (toIndex < 0 || toIndex >= selectedSheetIds.length) return;
    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(fromIndex, 1);
    newIds.splice(toIndex, 0, removed);
    setSelectedSheetIds(newIds);
  };

  // --- Spatial Pointer-based Drag Logic ---

  const handlePointerDown = (e: React.PointerEvent, index: number) => {
    const target = e.currentTarget as HTMLElement;
    target.setPointerCapture(e.pointerId);
    setDraggedIndex(index);
    setIsDragging(true);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging || draggedIndex === null) return;

    // Perform hit test to find which item we are over
    const element = document.elementFromPoint(e.clientX, e.clientY);
    const item = element?.closest('[data-reorder-index]');
    if (item) {
        const targetIndex = parseInt(item.getAttribute('data-reorder-index') || '-1');
        if (targetIndex !== -1 && targetIndex !== draggedIndex) {
            moveItem(draggedIndex, targetIndex);
            setDraggedIndex(targetIndex);
        }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const target = e.currentTarget as HTMLElement;
    target.releasePointerCapture(e.pointerId);
    setIsDragging(false);
    setDraggedIndex(null);
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.sheets.length > 0) {
            for (const sheet of result.sheets) await storage.addSheet(sheet);
            const sortedIds = [...result.sheets].sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true })).map(s => s.id);
            await storage.saveSetlist({ id: crypto.randomUUID(), name: result.setlistName || "Imported", sheetIds: sortedIds, dateCreated: Date.now() });
            onRefresh();
        }
    }
    if (e.target) e.target.value = '';
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => s.name.toLowerCase().includes(q) || (s.tags && s.tags.some(t => t.toLowerCase().includes(q))));
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={() => setIsEditing(false)} className="p-2 text-slate-400"><X /></button>
             <button onClick={handleSave} disabled={!newSetName || selectedSheetIds.length === 0} className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg">
                <Check size={18} /> <span>Save</span>
             </button>
           </div>
        </div>
        <input type="text" placeholder="Setlist Name" className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6" value={newSetName} onChange={e => setNewSetName(e.target.value)} />
        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase mb-3">Library</h3>
                <input type="text" placeholder="Filter..." className="w-full bg-slate-900 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-200 mb-3" value={librarySearch} onChange={(e) => setLibrarySearch(e.target.value)} />
                <div className="overflow-y-auto space-y-2 flex-1">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div key={sheet.id} onClick={() => !isSelected && toggleSelection(sheet.id)} className={`flex items-center p-3 rounded-lg border ${isSelected ? 'opacity-50 border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent'}`}>
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 ${isSelected ? 'bg-slate-600' : 'bg-blue-600'}`}>{isSelected ? <Check size={12}/> : <Plus size={12} />}</div>
                                <span className="text-slate-200 text-sm truncate">{sheet.name}</span>
                            </div>
                        );
                    })}
                </div>
            </div>
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-sm font-bold text-slate-500 uppercase mb-3">Reorder Setlist</h3>
                <div className="space-y-2 select-none">
                    {selectedSheetIds.map((id, index) => {
                        const sheet = sheets.find(s => s.id === id);
                        if (!sheet) return null;
                        return (
                            <div 
                                key={`${id}-${index}`} 
                                data-reorder-index={index}
                                className={`flex items-center bg-slate-800 p-2 rounded-lg border border-slate-700 transition-all ${draggedIndex === index ? 'scale-[1.02] border-blue-500 bg-slate-700 shadow-xl' : ''}`}
                            >
                                <div 
                                    className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none"
                                    onPointerDown={(e) => handlePointerDown(e, index)}
                                    onPointerMove={handlePointerMove}
                                    onPointerUp={handlePointerUp}
                                >
                                    <GripVertical size={20} />
                                </div>
                                <span className="flex-1 truncate mx-2 text-sm">{sheet.name}</span>
                                <button onClick={() => toggleSelection(id)} className="p-2 text-red-400"><Trash2 size={18} /></button>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div><h1 className="text-3xl font-bold text-white mb-1">Setlists</h1><p className="text-slate-400 text-sm">Organize repertoire</p></div>
        <div className="flex gap-3">
            <input type="text" placeholder="Search..." className="bg-slate-800 border border-slate-700 rounded-lg px-4 py-2 text-white" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
            <button onClick={startCreate} className="bg-blue-600 text-white px-4 py-2 rounded-lg">New Setlist</button>
        </div>
      </div>
      <div className="space-y-4">
          {filteredSetlists.map(list => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <ListMusic size={24} className="text-slate-400" />
                  <div><h3 className="text-lg font-medium text-white">{list.name}</h3><p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p></div>
               </div>
               <div className="flex items-center gap-2">
                   <button onClick={() => onPlay(list)} className="p-3 bg-green-600 text-white rounded-full"><Play size={20} fill="currentColor" /></button>
                   <button onClick={() => startEdit(list)} className="p-2 text-slate-400"><Pencil size={18} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-2 text-slate-400"><Trash2 size={18} /></button>
               </div>
            </div>
          ))}
      </div>
      {deleteModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 w-full max-w-md" onClick={e => e.stopPropagation()}>
            <h2 className="text-xl font-bold text-white mb-2">Delete Setlist?</h2>
            <div className="flex gap-3 mt-6">
                <button onClick={() => setDeleteModal({ isOpen: false, setlist: null })} className="flex-1 py-2 bg-slate-800 text-white rounded-lg">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 py-2 bg-red-600 text-white rounded-lg">Delete</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle, Copy, FileWarning } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    successMessage?: string;
}

interface ErrorModalState {
    isOpen: boolean;
    message: string;
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Global Tags State
  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [tagToDelete, setTagToDelete] = useState<string | null>(null);

  // Edit Modal State
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  // Custom Tag Icon Picker
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');

  // Delete Confirmation Modal State
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });

  // Import Conflict Modal State
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);

  // Error Modal State
  const [errorModal, setErrorModal] = useState<ErrorModalState>({ isOpen: false, message: '' });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  useEffect(() => {
    loadTags();
  }, [loadTags]);

  const initiateImport = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;
    const currentSheets = await storage.getAllSheets();
    const duplicates = newSheets.filter(newSheet => 
        currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
    );
    if (duplicates.length > 0) {
        setConflictData({ newSheets, duplicates, successMessage });
    } else {
        await finalizeImport(newSheets, false, successMessage);
    }
  };

  const finalizeImport = async (newSheets: Sheet[], overwrite: boolean, successMessage?: string) => {
      const currentSheets = await storage.getAllSheets();
      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
          let sheetToSave = sheet;
          if (existing && overwrite) {
              sheetToSave = {
                  ...sheet,
                  id: existing.id,
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }
          await storage.addSheet(sheetToSave);
      }
      setConflictData(null);
      if (successMessage) setTimeout(() => alert(successMessage), 100);
      onRefresh();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = { blob: file, fileType: file.type as any };
        newSheets.push({
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        });
      }
      await initiateImport(newSheets);
    }
    if (e.target) e.target.value = '';
  };

  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = (Array.from(e.target.files) as File[]).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;
      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";
      const pages: SheetPage[] = files.map(f => ({ blob: f, fileType: f.type as any }));
      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };
      await initiateImport([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            setErrorModal({ isOpen: true, message: result.error });
            if (e.target) e.target.value = '';
            return;
        }
        if (result.sheets.length > 0) {
            await initiateImport(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const handleDeleteClick = (e: React.MouseEvent | React.PointerEvent, sheet: Sheet) => {
    e.stopPropagation();
    if (e.cancelable) e.preventDefault();
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);
    setDeleteModal({ isOpen: true, sheet, affectedSetlists: affected });
  };

  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent | React.PointerEvent, sheet: Sheet) => {
    e.stopPropagation();
    if (e.cancelable) e.preventDefault();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
    setShowIconPicker(false);
    setTagToDelete(null);
  };

  const closeEditModal = () => {
    setEditingSheet(null);
    setTagToDelete(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      if (!editTags.includes(tagName)) setEditTags([...editTags, tagName]);
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };
      if (!allTags.some(t => t.label === tagName)) {
          setAllTags(prev => [...prev, newTagDef]);
          try {
            await storage.saveTag(newTagDef);
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            await loadTags();
          }
      }
      setTagInput('');
      setSelectedIconName('Tag');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  const getTagIcon = (tag: string, sheet?: Sheet) => {
    if (sheet?.tagIcons?.[tag]) return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    if (editTagIcons[tag]) return ICON_MAP[editTagIcons[tag]] || Tag;
    const def = allTags.find(t => t.label === tag);
    return def ? ICON_MAP[def.iconName] || Tag : Tag;
  };

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button onClick={() => batchInputRef.current?.click()} className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap">
                    <LibraryIcon size={20} /> <span className="hidden sm:inline">Batch Import</span>
                </button>
                <div className="flex gap-2 w-full">
                    <button onClick={() => fileInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap">
                        <Upload size={20} /> <span className="hidden sm:inline">File</span>
                    </button>
                    <button onClick={() => folderInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap">
                        <FolderUp size={20} /> <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/jpeg, application/pdf" multiple onChange={handleFileChange} />
        <input type="file" ref={folderInputRef} className="hidden" 
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleFolderChange} 
        />
        <input type="file" ref={batchInputRef} className="hidden"
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleBatchImport} 
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <Upload size={32} className="text-slate-400 mb-4" />
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const fileCount = sheet.pages.length;
             const isPdf = sheet.pages?.[0]?.fileType === 'application/pdf';
             return (
                <div key={sheet.id} onClick={() => onSelect(sheet.id)} className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col">
                    <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />
                        <div className="flex flex-col items-center gap-2">
                            {isPdf ? <FileText size={48} className="text-slate-600" /> : <Music size={48} className="text-slate-600" />}
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {fileCount > 1 ? `${fileCount} ${isPdf ? 'Files' : 'Pages'}` : (isPdf ? 'PDF' : 'Image')}
                            </span>
                        </div>
                        <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                            {(sheet.tags || []).slice(0, 4).map(tag => {
                                const Icon = getTagIcon(tag, sheet);
                                return <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30"><Icon size={12} /></span>;
                            })}
                        </div>
                    </div>
                    <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                        <h3 className="text-white font-medium text-sm truncate">{sheet.name}</h3>
                        <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                    </div>
                    {/* Explicitly responsive management buttons for touch devices */}
                    <div className="absolute top-2 right-2 flex flex-col gap-2 z-30">
                        <button 
                            onPointerDown={(e) => openEditModal(e, sheet)}
                            onClick={(e) => { e.stopPropagation(); e.preventDefault(); }} 
                            className="p-3 bg-black/80 text-white rounded-full hover:bg-blue-600 active:scale-95 transition-all shadow-xl"
                        >
                            <PenLine size={16} />
                        </button>
                        <button 
                            onPointerDown={(e) => handleDeleteClick(e, sheet)}
                            onClick={(e) => { e.stopPropagation(); e.preventDefault(); }}
                            className="p-3 bg-black/80 text-white rounded-full hover:bg-red-500 active:scale-95 transition-all shadow-xl"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </div>
             );
          })}
        </div>
      )}

      {deleteModal.isOpen && deleteModal.sheet && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-md shadow-2xl" onClick={e => e.stopPropagation()}>
            <div className="p-6 text-center">
                <AlertTriangle size={48} className="text-red-500 mx-auto mb-4" />
                <h2 className="text-xl font-bold text-white mb-2">Delete "{deleteModal.sheet.name}"?</h2>
                <p className="text-slate-400 text-sm">This action cannot be undone.</p>
            </div>
            <div className="p-4 bg-slate-950 border-t border-slate-800 flex gap-3 rounded-b-2xl">
                <button onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })} className="flex-1 px-4 py-2.5 bg-slate-800 text-white rounded-lg">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 px-4 py-2.5 bg-red-600 text-white rounded-lg">Delete</button>
            </div>
          </div>
        </div>
      )}

      {editingSheet && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={closeEditModal}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-lg shadow-2xl flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
                <h2 className="text-xl font-bold text-white">Edit Sheet</h2>
                <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X /></button>
            </div>
            <div className="p-6 space-y-6 overflow-y-auto">
                <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Sheet Name</label>
                    <input type="text" className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none" value={editName} onChange={e => setEditName(e.target.value)} />
                </div>
                <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Tags</label>
                    <div className="flex flex-wrap gap-2 mb-4">
                        {editTags.map(tag => (
                            <span key={tag} className="inline-flex items-center gap-2 px-3 py-1.5 bg-blue-600/20 text-blue-300 border border-blue-500/30 rounded-full text-sm">
                                {React.createElement(getTagIcon(tag), { size: 14 })}
                                {tag} <button onClick={() => handleRemoveTag(tag)} className="hover:text-red-400 transition-colors"><X size={14}/></button>
                            </span>
                        ))}
                    </div>
                    <div className="flex gap-2">
                        <input type="text" className="flex-1 bg-slate-800 border border-slate-700 rounded-lg px-4 text-white" placeholder="Add tag..." value={tagInput} onChange={e => setTagInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAddTag()} />
                        <button onClick={handleAddTag} className="p-3 bg-blue-600 text-white rounded-lg hover:bg-blue-500"><Plus size={20} /></button>
                    </div>
                </div>
            </div>
            <div className="p-4 bg-slate-950 border-t border-slate-800 flex gap-3 rounded-b-2xl">
                <button onClick={closeEditModal} className="flex-1 px-4 py-2.5 bg-slate-800 text-white rounded-lg">Cancel</button>
                <button onClick={saveEdits} className="flex-1 px-4 py-2.5 bg-blue-600 text-white rounded-lg">Save Changes</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import, FileWarning, AlertTriangle, Copy, Save, ChevronUp, ChevronDown } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // Drag State for Touch/Pointer
  const [isDragging, setIsDragging] = useState(false);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });
  const importInputRef = useRef<HTMLInputElement>(null);
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;
    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;
    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };
    await storage.saveSetlist(setlist);
    setIsEditing(false);
    onRefresh();
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  const moveItem = (fromIndex: number, toIndex: number) => {
    if (toIndex < 0 || toIndex >= selectedSheetIds.length) return;
    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(fromIndex, 1);
    newIds.splice(toIndex, 0, removed);
    setSelectedSheetIds(newIds);
  };

  // --- Spatial Pointer-based Drag Logic for Touch Devices ---

  const handlePointerDown = (e: React.PointerEvent, index: number) => {
    const target = e.currentTarget as HTMLElement;
    target.setPointerCapture(e.pointerId);
    setDraggedIndex(index);
    setIsDragging(true);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging || draggedIndex === null) return;

    // Find item under finger using coordinates
    const element = document.elementFromPoint(e.clientX, e.clientY);
    const item = element?.closest('[data-reorder-index]');
    if (item) {
        const targetIndex = parseInt(item.getAttribute('data-reorder-index') || '-1');
        if (targetIndex !== -1 && targetIndex !== draggedIndex) {
            moveItem(draggedIndex, targetIndex);
            setDraggedIndex(targetIndex);
        }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const target = e.currentTarget as HTMLElement;
    if (target.hasPointerCapture(e.pointerId)) {
        target.releasePointerCapture(e.pointerId);
    }
    setIsDragging(false);
    setDraggedIndex(null);
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => s.name.toLowerCase().includes(q) || (s.tags && s.tags.some(t => t.toLowerCase().includes(q))));
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={() => setIsEditing(false)} className="p-2 text-slate-400 hover:text-white transition-colors"><X /></button>
             <button onClick={handleSave} disabled={!newSetName || selectedSheetIds.length === 0} className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-500 disabled:opacity-50 transition-colors shadow-lg">
                <Check size={18} /> <span>Save</span>
             </button>
           </div>
        </div>
        <input type="text" placeholder="Setlist Name" className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none" value={newSetName} onChange={e => setNewSetName(e.target.value)} />
        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3">Add Library Sheets</h3>
                <input type="text" placeholder="Search library..." className="w-full bg-slate-900 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-200 mb-3" value={librarySearch} onChange={(e) => setLibrarySearch(e.target.value)} />
                <div className="overflow-y-auto space-y-2 flex-1 no-scrollbar">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div key={sheet.id} onClick={() => !isSelected && toggleSelection(sheet.id)} className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}>
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 shrink-0 ${isSelected ? 'bg-slate-600' : 'bg-blue-600'}`}>{isSelected ? <Check size={12}/> : <Plus size={12} />}</div>
                                <span className="text-slate-200 text-sm truncate">{sheet.name}</span>
                            </div>
                        );
                    })}
                </div>
            </div>
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4 no-scrollbar">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3">Reorder & Organize</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-12 text-slate-500 italic">No pieces added yet</div>
                ) : (
                    <div className="space-y-2 select-none">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragged = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    data-reorder-index={index}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragged ? 'scale-[1.02] border-blue-500 bg-slate-700 shadow-xl z-50' : 'border-slate-700'}`}
                                >
                                    <div 
                                        className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none"
                                        onPointerDown={(e) => handlePointerDown(e, index)}
                                        onPointerMove={handlePointerMove}
                                        onPointerUp={handlePointerUp}
                                    >
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-5 text-center text-xs text-slate-600 font-mono">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2 text-sm">{sheet.name}</span>
                                    <button onClick={() => toggleSelection(id)} className="p-2 text-slate-500 hover:text-red-400 transition-colors"><Trash2 size={18} /></button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div><h1 className="text-3xl font-bold text-white mb-1">Setlists</h1><p className="text-slate-400 text-sm">Organize your repertoire</p></div>
        <div className="flex gap-3 items-center">
            <div className="relative">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
                <input type="text" placeholder="Search..." className="bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2 text-white focus:ring-1 focus:ring-blue-500 outline-none" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
            </div>
            <button onClick={startCreate} className="bg-blue-600 text-white px-5 py-2 rounded-lg hover:bg-blue-500 transition-colors shadow-lg active:scale-95">New Setlist</button>
        </div>
      </div>
      <div className="grid grid-cols-1 gap-4">
          {filteredSetlists.map(list => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between hover:bg-slate-750 transition-colors shadow-sm">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="p-3 bg-slate-900 rounded-lg text-slate-400"><ListMusic size={24} /></div>
                  <div><h3 className="text-lg font-medium text-white">{list.name}</h3><p className="text-sm text-slate-400">{list.sheetIds.length} pieces</p></div>
               </div>
               <div className="flex items-center gap-2">
                   <button onClick={() => onPlay(list)} className="p-4 bg-green-600 text-white rounded-full hover:bg-green-500 transition-all shadow-lg shadow-green-900/20 active:scale-90"><Play size={24} fill="currentColor" /></button>
                   <div className="w-px h-10 bg-slate-700 mx-2" />
                   <button onClick={() => startEdit(list)} className="p-3 text-slate-400 hover:text-blue-400 transition-colors"><Pencil size={20} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-3 text-slate-400 hover:text-red-400 transition-colors"><Trash2 size={20} /></button>
               </div>
            </div>
          ))}
      </div>
      {deleteModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-8 w-full max-w-md shadow-2xl" onClick={e => e.stopPropagation()}>
            <AlertTriangle size={48} className="text-red-500 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-white text-center mb-6">Delete Setlist?</h2>
            <div className="flex gap-3">
                <button onClick={() => setDeleteModal({ isOpen: false, setlist: null })} className="flex-1 py-3 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-colors">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 py-3 bg-red-600 text-white rounded-lg hover:bg-red-500 transition-colors">Delete</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle, Copy, FileWarning } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    successMessage?: string;
}

interface ErrorModalState {
    isOpen: boolean;
    message: string;
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);
  const [errorModal, setErrorModal] = useState<ErrorModalState>({ isOpen: false, message: '' });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  useEffect(() => {
    loadTags();
  }, [loadTags]);

  const initiateImport = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;
    const currentSheets = await storage.getAllSheets();
    const duplicates = newSheets.filter(newSheet => 
        currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
    );
    if (duplicates.length > 0) {
        setConflictData({ newSheets, duplicates, successMessage });
    } else {
        await finalizeImport(newSheets, false, successMessage);
    }
  };

  const finalizeImport = async (newSheets: Sheet[], overwrite: boolean, successMessage?: string) => {
      const currentSheets = await storage.getAllSheets();
      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
          let sheetToSave = sheet;
          if (existing && overwrite) {
              sheetToSave = {
                  ...sheet,
                  id: existing.id,
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }
          await storage.addSheet(sheetToSave);
      }
      setConflictData(null);
      if (successMessage) setTimeout(() => alert(successMessage), 100);
      onRefresh();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = { blob: file, fileType: file.type as any };
        newSheets.push({
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        });
      }
      await initiateImport(newSheets);
    }
    if (e.target) e.target.value = '';
  };

  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = (Array.from(e.target.files) as File[]).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;
      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";
      const pages: SheetPage[] = files.map(f => ({ blob: f, fileType: f.type as any }));
      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };
      await initiateImport([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            setErrorModal({ isOpen: true, message: result.error });
            if (e.target) e.target.value = '';
            return;
        }
        if (result.sheets.length > 0) {
            await initiateImport(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const handleDeleteClick = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    e.preventDefault();
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);
    setDeleteModal({ isOpen: true, sheet, affectedSetlists: affected });
  };

  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    e.preventDefault();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
  };

  const closeEditModal = () => {
    setEditingSheet(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      if (!editTags.includes(tagName)) setEditTags([...editTags, tagName]);
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };
      if (!allTags.some(t => t.label === tagName)) {
          setAllTags(prev => [...prev, newTagDef]);
          try {
            await storage.saveTag(newTagDef);
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            await loadTags();
          }
      }
      setTagInput('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  const getTagIcon = (tag: string, sheet?: Sheet) => {
    if (sheet?.tagIcons?.[tag]) return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    if (editTagIcons[tag]) return ICON_MAP[editTagIcons[tag]] || Tag;
    const def = allTags.find(t => t.label === tag);
    return def ? ICON_MAP[def.iconName] || Tag : Tag;
  };

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button onClick={() => batchInputRef.current?.click()} className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap">
                    <LibraryIcon size={20} /> <span className="hidden sm:inline">Batch Import</span>
                </button>
                <div className="flex gap-2 w-full">
                    <button onClick={() => fileInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap">
                        <Upload size={20} /> <span className="hidden sm:inline">File</span>
                    </button>
                    <button onClick={() => folderInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap">
                        <FolderUp size={20} /> <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/jpeg, application/pdf" multiple onChange={handleFileChange} />
        <input type="file" ref={folderInputRef} className="hidden" 
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleFolderChange} 
        />
        <input type="file" ref={batchInputRef} className="hidden"
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleBatchImport} 
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <Upload size={32} className="text-slate-400 mb-4" />
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const fileCount = sheet.pages.length;
             const isPdf = sheet.pages?.[0]?.fileType === 'application/pdf';
             return (
                <div key={sheet.id} onClick={() => onSelect(sheet.id)} className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col">
                    <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />
                        <div className="flex flex-col items-center gap-2">
                            {isPdf ? <FileText size={48} className="text-slate-600" /> : <Music size={48} className="text-slate-600" />}
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {fileCount > 1 ? `${fileCount} ${isPdf ? 'Files' : 'Pages'}` : (isPdf ? 'PDF' : 'Image')}
                            </span>
                        </div>
                        <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                            {(sheet.tags || []).slice(0, 4).map(tag => {
                                const Icon = getTagIcon(tag, sheet);
                                return <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30"><Icon size={12} /></span>;
                            })}
                        </div>
                    </div>
                    <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                        <h3 className="text-white font-medium text-sm truncate">{sheet.name}</h3>
