import React, { useState, useMemo, useRef } from 'react';
import { Plus, ListMusic, Trash2, Play, MoveVertical, X, Check, Pencil, GripVertical, Search, Import, FileWarning, AlertTriangle, Copy, Save, ChevronUp, ChevronDown } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // Drag State for Touch/Pointer
  const [isDragging, setIsDragging] = useState(false);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });
  const importInputRef = useRef<HTMLInputElement>(null);
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;
    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;
    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };
    await storage.saveSetlist(setlist);
    setIsEditing(false);
    onRefresh();
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  const moveItem = (fromIndex: number, toIndex: number) => {
    if (toIndex < 0 || toIndex >= selectedSheetIds.length) return;
    const newIds = [...selectedSheetIds];
    const [removed] = newIds.splice(fromIndex, 1);
    newIds.splice(toIndex, 0, removed);
    setSelectedSheetIds(newIds);
  };

  // --- Spatial Pointer-based Drag Logic for Touch Devices ---

  const handlePointerDown = (e: React.PointerEvent, index: number) => {
    const target = e.currentTarget as HTMLElement;
    target.setPointerCapture(e.pointerId);
    setDraggedIndex(index);
    setIsDragging(true);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging || draggedIndex === null) return;

    // Find item under finger using coordinates
    const element = document.elementFromPoint(e.clientX, e.clientY);
    const item = element?.closest('[data-reorder-index]');
    if (item) {
        const targetIndex = parseInt(item.getAttribute('data-reorder-index') || '-1');
        if (targetIndex !== -1 && targetIndex !== draggedIndex) {
            moveItem(draggedIndex, targetIndex);
            setDraggedIndex(targetIndex);
        }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const target = e.currentTarget as HTMLElement;
    if (target.hasPointerCapture(e.pointerId)) {
        target.releasePointerCapture(e.pointerId);
    }
    setIsDragging(false);
    setDraggedIndex(null);
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.sheets.length > 0) {
            // Add all sheets from the folder to library
            for (const sheet of result.sheets) {
                await storage.addSheet(sheet);
            }
            // Create a setlist from these new sheet IDs
            const sortedIds = [...result.sheets]
                .sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }))
                .map(s => s.id);

            const newSetlist: Setlist = {
                id: crypto.randomUUID(),
                name: result.setlistName || "Imported Setlist",
                sheetIds: sortedIds,
                dateCreated: Date.now()
            };

            await storage.saveSetlist(newSetlist);
            onRefresh();
            alert(`Imported "${newSetlist.name}" with ${result.sheets.length} pieces.`);
        } else if (result.error) {
            alert(result.error);
        }
    }
    if (e.target) e.target.value = '';
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => s.name.toLowerCase().includes(q) || (s.tags && s.tags.some(t => t.toLowerCase().includes(q))));
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={() => setIsEditing(false)} className="p-2 text-slate-400 hover:text-white transition-colors"><X size={24} /></button>
             <button onClick={handleSave} disabled={!newSetName || selectedSheetIds.length === 0} className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-500 disabled:opacity-50 transition-colors shadow-lg">
                <Check size={18} /> <span>Save</span>
             </button>
           </div>
        </div>
        <input type="text" placeholder="Setlist Name" className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white mb-6 focus:ring-2 focus:ring-blue-500 outline-none" value={newSetName} onChange={e => setNewSetName(e.target.value)} />
        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/50 rounded-xl p-4 border border-slate-700/50">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3">Add Library Sheets</h3>
                <input type="text" placeholder="Search library..." className="w-full bg-slate-900 border border-slate-700 rounded-md px-3 py-2 text-sm text-slate-200 mb-3" value={librarySearch} onChange={(e) => setLibrarySearch(e.target.value)} />
                <div className="overflow-y-auto space-y-2 flex-1 no-scrollbar">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <div key={sheet.id} onClick={() => !isSelected && toggleSelection(sheet.id)} className={`flex items-center p-3 rounded-lg border transition-all ${isSelected ? 'opacity-50 border-slate-700' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700'}`}>
                                <div className={`w-6 h-6 rounded-full flex items-center justify-center mr-3 shrink-0 ${isSelected ? 'bg-slate-600' : 'bg-blue-600'}`}>{isSelected ? <Check size={12}/> : <Plus size={12} />}</div>
                                <span className="text-slate-200 text-sm truncate">{sheet.name}</span>
                            </div>
                        );
                    })}
                </div>
            </div>
            <div className="flex-1 overflow-y-auto min-h-0 bg-slate-800/50 rounded-xl p-4 no-scrollbar border border-slate-700/50">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3">Performance Order</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-12 text-slate-500 italic">No pieces added yet</div>
                ) : (
                    <div className="space-y-2 select-none">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isDragged = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    data-reorder-index={index}
                                    className={`flex items-center bg-slate-800 p-2 rounded-lg border transition-all ${isDragged ? 'scale-[1.02] border-blue-500 bg-slate-700 shadow-xl z-50' : 'border-slate-700'}`}
                                >
                                    <div 
                                        className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none"
                                        onPointerDown={(e) => handlePointerDown(e, index)}
                                        onPointerMove={handlePointerMove}
                                        onPointerUp={handlePointerUp}
                                    >
                                        <GripVertical size={20} />
                                    </div>
                                    <span className="w-5 text-center text-xs text-slate-600 font-mono">{index + 1}</span>
                                    <span className="flex-1 truncate mx-2 text-sm text-white">{sheet.name}</span>
                                    <button onClick={(e) => { e.stopPropagation(); toggleSelection(id); }} className="p-2 text-slate-500 hover:text-red-400 transition-colors"><Trash2 size={18} /></button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div><h1 className="text-3xl font-bold text-white mb-1">Setlists</h1><p className="text-slate-400 text-sm">Organize your repertoire for gigging</p></div>
        <div className="flex gap-3 items-center flex-wrap">
            <div className="relative">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
                <input type="text" placeholder="Search..." className="bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2 text-white focus:ring-1 focus:ring-blue-500 outline-none" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
            </div>

            <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 bg-indigo-600 text-white px-5 py-2 rounded-lg hover:bg-indigo-500 transition-colors shadow-lg active:scale-95">
                <Import size={18} />
                <span>Import Playlist</span>
            </button>

            <button onClick={startCreate} className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2 rounded-lg hover:bg-blue-500 transition-colors shadow-lg active:scale-95">
                <Plus size={18} />
                <span>New Setlist</span>
            </button>

            <input type="file" ref={importInputRef} className="hidden" 
                // @ts-ignore
                webkitdirectory="" directory="" multiple onChange={handleImportSetlist} 
            />
        </div>
      </div>
      <div className="grid grid-cols-1 gap-4">
          {filteredSetlists.map(list => (
            <div key={list.id} className="bg-slate-800 rounded-xl p-4 flex items-center justify-between hover:bg-slate-750 transition-colors shadow-sm border border-slate-700/30">
               <div className="flex items-center gap-4 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="p-3 bg-slate-900 rounded-lg text-slate-400"><ListMusic size={24} /></div>
                  <div><h3 className="text-lg font-medium text-white">{list.name}</h3><p className="text-sm text-slate-400">{list.sheetIds.length} pieces • Created {new Date(list.dateCreated).toLocaleDateString()}</p></div>
               </div>
               <div className="flex items-center gap-2">
                   <button onClick={() => onPlay(list)} className="p-4 bg-green-600 text-white rounded-full hover:bg-green-500 transition-all shadow-lg shadow-green-900/20 active:scale-90"><Play size={24} fill="currentColor" /></button>
                   <div className="w-px h-10 bg-slate-700 mx-2" />
                   <button onClick={() => startEdit(list)} className="p-3 text-slate-400 hover:text-blue-400 transition-colors"><Pencil size={20} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-3 text-slate-400 hover:text-red-400 transition-colors"><Trash2 size={20} /></button>
               </div>
            </div>
          ))}
      </div>
      {deleteModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-8 w-full max-w-md shadow-2xl" onClick={e => e.stopPropagation()}>
            <AlertTriangle size={48} className="text-red-500 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-white text-center mb-2">Delete Setlist?</h2>
            <p className="text-slate-400 text-center text-sm mb-6">This only deletes the performance order. Your sheet music files in the library will not be affected.</p>
            <div className="flex gap-3">
                <button onClick={() => setDeleteModal({ isOpen: false, setlist: null })} className="flex-1 py-3 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-colors">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 py-3 bg-red-600 text-white rounded-lg hover:bg-red-500 transition-colors">Delete</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

