  const getItemStyle = (index: number) => {
    if (draggedIndex === null || hoverIndex === null) return {};

    // The item actually being dragged
    if (index === draggedIndex) {
        return {
            transform: `translateY(${dragOffset}px) scale(1.02)`,
            zIndex: 50,
            boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.5), 0 8px 10px -6px rgb(0 0 0 / 0.5)',
            borderColor: '#3b82f6', // blue-500
            backgroundColor: '#1e293b', // slate-800
            transition: 'none',
        };
    }

    // Shifting items between dragged and hover positions
    let shift = 0;
    const height = itemHeights.current[draggedIndex] || 60;

    if (draggedIndex < hoverIndex) {
        // Dragging DOWN: Items between original and new position shift UP
        if (index > draggedIndex && index <= hoverIndex) {
            shift = -height;
        }
    } else if (draggedIndex > hoverIndex) {
        // Dragging UP: Items between original and new position shift DOWN
        if (index < draggedIndex && index >= hoverIndex) {
            shift = height;
        }
    }

    return {
        transform: `translateY(${shift}px)`,
        transition: 'transform 0.2s cubic-bezier(0.2, 0, 0, 1)',
    };
  };

