                                    <button onClick={(e) => { e.stopPropagation(); toggleSelection(id); }} className={`p-2 text-slate-500 hover:text-red-400 transition-colors ${isBeingDragged ? 'pointer-events-none' : ''}`}><Trash2 size={18} /></button>
                                </div>
