  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-4">
        <div><h1 className="text-3xl font-bold text-white mb-1">Setlists</h1><p className="text-slate-400 text-sm">Organize your repertoire for gigging</p></div>
        <div className="flex gap-3 items-center flex-wrap">
            <div className="relative">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
                <input type="text" placeholder="Search..." className="bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2 text-white focus:ring-1 focus:ring-blue-500 outline-none" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
