import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { PAGE_TURN_KEYS, COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
  initialDirection?: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo, initialDirection = 'forward'
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [workerReady, setWorkerReady] = useState(false);
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 }); // Default aspect
  const [transitioning, setTransitioning] = useState<'next' | 'prev' | null>(null);

  // Prefetch & Cache Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());

  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // UI States
  const [showPageNav, setShowPageNav] = useState(false);

  useEffect(() => {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // 1. Load Sheet & Initial Annotations
  useEffect(() => {
    let active = true;
    const load = async () => {
      setLoading(true);
      // Clear document cache when moving to a new song to save memory
      pdfDocCache.current.clear();

      const loaded = await storage.getSheet(sheetId);
      if (loaded && active) {
        setSheet(loaded);
        const startIdx = initialDirection === 'backward' ? loaded.pages.length - 1 : 0;
        setActiveFileIndex(startIdx);
        // CRITICAL: Reset sub-page index when switching pieces
        setSubPageIndex(0);

        const stored = await storage.getAnnotation(sheetId);
        setAllStrokes(stored ? stored.strokes : []);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  // 2. Optimized PDF Loader
  const getPdfDoc = async (fileIdx: number) => {
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (!sheet || !sheet.pages[fileIdx] || sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
    const loadingTask = pdfjs.getDocument({
        data: new Uint8Array(arrayBuffer),
        cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
        cMapPacked: true,
    });
    const doc = await loadingTask.promise;
    pdfDocCache.current.set(fileIdx, doc);
    return doc;
  };

  // 3. Strategic Pre-rendering Logic
  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number) => {
    // Key MUST include sheetId to prevent collisions between pieces in a setlist
    const key = `${sheetId}-${fIdx}-${pIdx}`;
    if (canvasCache.current.has(key) || renderTasks.current.has(key)) return;

    try {
        const doc = await getPdfDoc(fIdx);
        if (!doc) return;

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const { clientWidth, clientHeight } = container;
        const unscaledViewport = page.getViewport({ scale: 1 });
        const scale = Math.min(clientWidth / unscaledViewport.width, clientHeight / unscaledViewport.height) * 0.98;
        const viewport = page.getViewport({ scale });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;
        canvasCache.current.set(key, offscreenCanvas);
        renderTasks.current.delete(key);

        // Force re-render if this is exactly the page we are waiting for
        if (fIdx === activeFileIndex && pIdx === subPageIndex) {
            drawCurrentPage();
        }
    } catch (e) {
        console.error("Prefetch error", e);
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex]);

  const drawCurrentPage = useCallback(() => {
    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
        const ctx = mainCanvas.getContext('2d');
        ctx?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        // Not in cache, start high-priority render
        renderPageToCache(activeFileIndex, subPageIndex);
    }
  }, [sheetId, activeFileIndex, subPageIndex, renderPageToCache]);

  // Handle page turns and prefetching coordination
  useEffect(() => {
    if (!sheet || !workerReady) return;

    const current = sheet.pages[activeFileIndex];
    if (current?.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            setNumSubPages(doc.numPages);
            setFileType('application/pdf');
            drawCurrentPage();

            // PREFETCH NEXT
            if (subPageIndex < doc.numPages - 1) {
                renderPageToCache(activeFileIndex, subPageIndex + 1);
            } else if (activeFileIndex < sheet.pages.length - 1) {
                renderPageToCache(activeFileIndex + 1, 0);
            }

            // PREFETCH PREVIOUS
            if (subPageIndex > 0) {
                renderPageToCache(activeFileIndex, subPageIndex - 1);
            }
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setLoading(false);
    }

    // Advanced Memory Cleanup: Evict cache entries from OTHER sheets
    if (canvasCache.current.size > 15) {
        for (const [key] of canvasCache.current) {
            if (!key.startsWith(sheetId)) {
                canvasCache.current.delete(key);
            }
        }
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, drawCurrentPage, renderPageToCache]);

  const handlePageNext = () => {
    if (transitioning) return;
    setTransitioning('next');

    setTimeout(() => {
        if (subPageIndex < numSubPages - 1) {
            setSubPageIndex(prev => prev + 1);
        } else {
            if (sheet && activeFileIndex < sheet.pages.length - 1) {
                setActiveFileIndex(prev => prev + 1);
                setSubPageIndex(0);
            } else if (hasNext) {
                onNext();
            }
        }
        setTransitioning(null);
    }, 150);
  };

  const handlePagePrev = () => {
    if (transitioning) return;
    setTransitioning('prev');

    setTimeout(() => {
        if (subPageIndex > 0) {
            setSubPageIndex(prev => prev - 1);
        } else {
            if (activeFileIndex > 0) {
                setActiveFileIndex(prev => prev - 1);
                setSubPageIndex(0);
            } else if (hasPrev) {
                onPrev();
            }
        }
        setTransitioning(null);
    }, 150);
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden">
      {/* Top Bar */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/90 to-transparent transition-opacity duration-300 ${(isDrawingMode || showPageNav) ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white shadow-xl"><X size={20} /></button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-bold tracking-tight truncate max-w-[200px]">{title}</h2>
                    <span className="bg-blue-600/30 text-blue-400 text-[10px] font-bold px-2 py-0.5 rounded uppercase border border-blue-500/20">
                        {activeFileIndex + 1}/{sheet?.pages.length}
                    </span>
                </div>
                <div className="text-[10px] text-slate-400 font-mono">Page {subPageIndex + 1} of {numSubPages}</div>
            </div>
        </div>

        <div className="flex items-center gap-2">
            <button onClick={() => setIsDrawingMode(!isDrawingMode)} className={`p-2.5 rounded-full transition-all ${isDrawingMode ? 'bg-blue-600 text-white scale-110 shadow-blue-500/40' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                <PenTool size={20} />
            </button>
        </div>
      </div>

      {/* Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">

        {loading && (
            <div className="absolute inset-0 z-40 bg-black/20 backdrop-blur-[2px] pointer-events-none flex items-center justify-center">
                 <Loader2 className="animate-spin text-blue-500" size={48} />
            </div>
        )}

        <div 
            ref={containerRef}
            className={`relative w-full h-full flex items-center justify-center transition-all duration-200 ease-out transform ${transitioning === 'next' ? '-translate-x-8 opacity-40' : transitioning === 'prev' ? 'translate-x-8 opacity-40' : 'translate-x-0 opacity-100'}`}
            style={{ touchAction: 'none' }}
        >
            <canvas 
                ref={pdfCanvasRef} 
                className="shadow-[0_0_100px_rgba(0,0,0,0.5)] select-none pointer-events-none"
                style={{ maxWidth: '100%', maxHeight: '100%', display: fileType === 'application/pdf' ? 'block' : 'none' }}
            />

            {fileType === 'image' && sheet?.pages[activeFileIndex] && (
                <img 
                    src={URL.createObjectURL(sheet.pages[activeFileIndex].blob)} 
                    className="max-w-full max-h-full object-contain pointer-events-none" 
                    alt="Current Page" 
                />
            )}

            {/* Annotation Layer */}
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10" 
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes.filter(isStrokeOnCurrentPage).map((stroke, i) => (
                    <path 
                        key={i}
                        d={getSvgPath(stroke.points)}
                        stroke={stroke.color}
                        strokeWidth={stroke.width}
                        fill="none"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                    />
                ))}
            </svg>
        </div>

        {/* Interaction Zones */}
        {!isDrawingMode && (
          <>
            <div className="absolute inset-y-0 left-0 w-1/4 z-20 cursor-pointer active:bg-white/5 transition-colors" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-1/4 z-20 cursor-pointer active:bg-white/5 transition-colors" onClick={handlePageNext} />
            <div className="absolute inset-y-0 left-1/4 right-1/4 z-10 cursor-pointer" onClick={() => setShowPageNav(!showPageNav)} />
          </>
        )}
      </div>

      {/* Floating Indicators */}
      {!isDrawingMode && !loading && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur rounded-full text-[10px] font-bold tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase">
              {activeFileIndex + 1}.{subPageIndex + 1}
          </div>
      )}

      {/* Annotation Toolbar */}
      {isDrawingMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-4 p-2 bg-slate-900/90 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl z-50">
               <button onClick={() => setTool('pen')} className={`p-3 rounded-xl ${tool === 'pen' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}><PenTool size={20}/></button>
               <button onClick={() => setTool('eraser')} className={`p-3 rounded-xl ${tool === 'eraser' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}><Eraser size={20}/></button>
               <div className="w-px h-8 bg-white/10 mx-1" />
               <button onClick={() => setIsDrawingMode(false)} className="p-3 text-slate-400 hover:text-white">Done</button>
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2 } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
  initialDirection?: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    initialDirection = 'forward'
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [workerReady, setWorkerReady] = useState(false);
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Buffering Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());

  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const currentSheetIdRef = useRef(sheetId);

  useEffect(() => {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // Synchronous State Reset on Song Change
  useEffect(() => {
    let active = true;
    const load = async () => {
      currentSheetIdRef.current = sheetId;
      setLoading(true);
      pdfDocCache.current.clear(); // Important: Release memory of the previous song

      const loaded = await storage.getSheet(sheetId);
      if (loaded && active) {
        setSheet(loaded);
        const startIdx = initialDirection === 'backward' ? loaded.pages.length - 1 : 0;
        setActiveFileIndex(startIdx);
        setSubPageIndex(0); // Reset page to 1 whenever song changes

        const stored = await storage.getAnnotation(sheetId);
        setAllStrokes(stored ? stored.strokes : []);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  const getPdfDoc = async (fileIdx: number) => {
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (!sheet || !sheet.pages[fileIdx] || sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
    const loadingTask = pdfjs.getDocument({
        data: new Uint8Array(arrayBuffer),
        cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
        cMapPacked: true,
    });
    const doc = await loadingTask.promise;
    pdfDocCache.current.set(fileIdx, doc);
    return doc;
  };

  const drawCurrentPage = useCallback(() => {
    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        // Instant Bit-Blt transfer
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
        const ctx = mainCanvas.getContext('2d', { alpha: false });
        ctx?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        // Start high-priority render if cache miss
        renderPageToCache(activeFileIndex, subPageIndex, true);
    }
  }, [sheetId, activeFileIndex, subPageIndex]);

  // UseLayoutEffect ensures we draw BEFORE the browser paints the new frame
  useLayoutEffect(() => {
    if (sheet && workerReady) {
        drawCurrentPage();
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, drawCurrentPage]);

  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number, isHighPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;
    if (canvasCache.current.has(key) || renderTasks.current.has(key)) return;

    try {
        const doc = await getPdfDoc(fIdx);
        if (!doc || sheetId !== currentSheetIdRef.current) return;

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const { clientWidth, clientHeight } = container;
        const unscaledViewport = page.getViewport({ scale: 1 });
        const scale = Math.min(clientWidth / unscaledViewport.width, clientHeight / unscaledViewport.height) * 1.5; // High-res scale
        const viewport = page.getViewport({ scale });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d', { alpha: false })!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        // Final safety check: are we still on the same song/page?
        if (sheetId === currentSheetIdRef.current) {
            canvasCache.current.set(key, offscreenCanvas);
            renderTasks.current.delete(key);
            if (isHighPriority && fIdx === activeFileIndex && pIdx === subPageIndex) {
                drawCurrentPage();
            }
        }
    } catch (e) {
        console.error("Render error", e);
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, drawCurrentPage]);

  // Background Prefetcher
  useEffect(() => {
    if (!sheet || !workerReady) return;

    const current = sheet.pages[activeFileIndex];
    if (current?.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentSheetIdRef.current) return;
            setNumSubPages(doc.numPages);
            setFileType('application/pdf');

            // PREFETCH WINDOW: Next 2 pages and Previous 1 page
            if (subPageIndex < doc.numPages - 1) {
                renderPageToCache(activeFileIndex, subPageIndex + 1);
            } else if (activeFileIndex < sheet.pages.length - 1) {
                renderPageToCache(activeFileIndex + 1, 0);
            }
            if (subPageIndex > 0) renderPageToCache(activeFileIndex, subPageIndex - 1);
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setLoading(false);
    }

    // Cache cleanup for other songs
    if (canvasCache.current.size > 20) {
        for (const [key] of canvasCache.current) {
            if (!key.startsWith(sheetId)) canvasCache.current.delete(key);
        }
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, renderPageToCache]);

  const handlePageNext = () => {
    if (subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
    } else {
        if (sheet && activeFileIndex < sheet.pages.length - 1) {
            setActiveFileIndex(prev => prev + 1);
            setSubPageIndex(0);
        } else if (hasNext) {
            onNext();
        }
    }
  };

  const handlePagePrev = () => {
    if (subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
    } else {
        if (activeFileIndex > 0) {
            setActiveFileIndex(prev => prev - 1);
            setSubPageIndex(0);
        } else if (hasPrev) {
            onPrev();
        }
    }
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden">
      {/* HUD (Top Bar) - Auto hides */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/90 to-transparent transition-opacity duration-200 ${isDrawingMode ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white shadow-xl"><X size={20} /></button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-bold tracking-tight truncate max-w-[200px]">{title}</h2>
                    <span className="bg-blue-600/30 text-blue-400 text-[10px] font-bold px-2 py-0.5 rounded uppercase border border-blue-500/20">
                        {activeFileIndex + 1}/{sheet?.pages.length}
                    </span>
                </div>
                <div className="text-[10px] text-slate-400 font-mono">Page {subPageIndex + 1} of {numSubPages}</div>
            </div>
        </div>

        <div className="flex items-center gap-2">
            <button onClick={() => setIsDrawingMode(!isDrawingMode)} className={`p-2.5 rounded-full transition-all ${isDrawingMode ? 'bg-blue-600 text-white scale-110 shadow-blue-500/40' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                <PenTool size={20} />
            </button>
        </div>
      </div>

      {/* Main Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {loading && <Loader2 className="animate-spin text-blue-500 absolute z-50" size={48} />}

        <div 
            ref={containerRef}
            className="relative w-full h-full flex items-center justify-center"
            style={{ touchAction: 'none' }}
        >
            <canvas 
                ref={pdfCanvasRef} 
                className="shadow-2xl select-none pointer-events-none"
                style={{ maxWidth: '100%', maxHeight: '100%', display: fileType === 'application/pdf' ? 'block' : 'none', imageRendering: 'crisp-edges' }}
            />

            {fileType === 'image' && sheet?.pages[activeFileIndex] && (
                <img 
                    src={URL.createObjectURL(sheet.pages[activeFileIndex].blob)} 
                    className="max-w-full max-h-full object-contain pointer-events-none" 
                    alt="Current Page" 
                />
            )}

            {/* Annotation Overlay */}
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10" 
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes.filter(isStrokeOnCurrentPage).map((stroke, i) => (
                    <path 
                        key={i}
                        d={getSvgPath(stroke.points)}
                        stroke={stroke.color}
                        strokeWidth={stroke.width}
                        fill="none"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                    />
                ))}
            </svg>
        </div>

        {/* Interaction Zones (Hotspots) */}
        {!isDrawingMode && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors" onClick={handlePagePrev} />
            <div className="absolute inset-y-0 right-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors" onClick={handlePageNext} />
          </>
        )}
      </div>

      {/* Page Badge */}
      {!isDrawingMode && !loading && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur rounded-full text-[10px] font-bold tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase">
              {activeFileIndex + 1}.{subPageIndex + 1}
          </div>
      )}

      {/* Drawing Controls */}
      {isDrawingMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-4 p-2 bg-slate-900/90 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl z-50">
               <button onClick={() => setTool('pen')} className={`p-3 rounded-xl ${tool === 'pen' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}><PenTool size={20}/></button>
               <button onClick={() => setIsDrawingMode(false)} className="p-3 text-slate-400 hover:text-white font-medium px-4">Done</button>
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
  initialDirection?: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo,
    initialDirection = 'forward'
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [workerReady, setWorkerReady] = useState(false);
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [showPlaylist, setShowPlaylist] = useState(false);

  // Buffering Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());

  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const currentSheetIdRef = useRef(sheetId);

  useEffect(() => {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // Synchronous State Reset on Song Change
  useEffect(() => {
    let active = true;
    const load = async () => {
      // CLEAR PREVIOUS STATE IMMEDIATELY to prevent "title vs content" mismatch
      currentSheetIdRef.current = sheetId;
      setSheet(null); 
      setLoading(true);
      pdfDocCache.current.clear(); 

      const loaded = await storage.getSheet(sheetId);
      if (!active) return;

      if (loaded) {
        setSheet(loaded);
        const startIdx = initialDirection === 'backward' ? loaded.pages.length - 1 : 0;
        setActiveFileIndex(startIdx);
        setSubPageIndex(0); 

        const stored = await storage.getAnnotation(sheetId);
        setAllStrokes(stored ? stored.strokes : []);
      } else {
        // Handle sheet not found
        setLoading(false);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  const getPdfDoc = async (fileIdx: number) => {
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (!sheet || !sheet.pages[fileIdx] || sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const loadingTask = pdfjs.getDocument({
            data: new Uint8Array(arrayBuffer),
            cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
            cMapPacked: true,
        });
        const doc = await loadingTask.promise;
        pdfDocCache.current.set(fileIdx, doc);
        return doc;
    } catch (e) {
        console.error("PDF Load Error", e);
        return null;
    }
  };

  const drawCurrentPage = useCallback(() => {
    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
        const ctx = mainCanvas.getContext('2d', { alpha: false });
        ctx?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        renderPageToCache(activeFileIndex, subPageIndex, true);
    }
  }, [sheetId, activeFileIndex, subPageIndex]);

  useLayoutEffect(() => {
    if (sheet && workerReady) {
        drawCurrentPage();
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, drawCurrentPage]);

  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number, isHighPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;
    if (canvasCache.current.has(key) || renderTasks.current.has(key)) {
        if (isHighPriority && canvasCache.current.has(key)) setLoading(false);
        return;
    }

    try {
        const doc = await getPdfDoc(fIdx);
        if (!doc || sheetId !== currentSheetIdRef.current) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const { clientWidth, clientHeight } = container;
        const unscaledViewport = page.getViewport({ scale: 1 });
        const scale = Math.min(clientWidth / unscaledViewport.width, clientHeight / unscaledViewport.height) * 2.0; 
        const viewport = page.getViewport({ scale });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d', { alpha: false })!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentSheetIdRef.current) {
            canvasCache.current.set(key, offscreenCanvas);
            renderTasks.current.delete(key);
            if (isHighPriority && fIdx === activeFileIndex && pIdx === subPageIndex) {
                drawCurrentPage();
            }
        }
    } catch (e) {
        console.error("Render error", e);
        if (isHighPriority) setLoading(false);
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, drawCurrentPage]);

  useEffect(() => {
    if (!sheet || !workerReady) return;

    const current = sheet.pages[activeFileIndex];
    if (current?.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentSheetIdRef.current) return;
            setNumSubPages(doc.numPages);
            setFileType('application/pdf');

            // PREFETCH
            if (subPageIndex < doc.numPages - 1) {
                renderPageToCache(activeFileIndex, subPageIndex + 1);
            } else if (activeFileIndex < sheet.pages.length - 1) {
                renderPageToCache(activeFileIndex + 1, 0);
            }
            if (subPageIndex > 0) renderPageToCache(activeFileIndex, subPageIndex - 1);
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setLoading(false);
    }

    if (canvasCache.current.size > 30) {
        for (const [key] of canvasCache.current) {
            if (!key.startsWith(sheetId)) canvasCache.current.delete(key);
        }
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, renderPageToCache]);

  const handlePageNext = () => {
    if (subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
    } else {
        if (sheet && activeFileIndex < sheet.pages.length - 1) {
            setActiveFileIndex(prev => prev + 1);
            setSubPageIndex(0);
        } else if (hasNext) {
            onNext();
        }
    }
  };

  const handlePagePrev = () => {
    if (subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
    } else {
        if (activeFileIndex > 0) {
            setActiveFileIndex(prev => prev - 1);
            setSubPageIndex(0);
        } else if (hasPrev) {
            onPrev();
        }
    }
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden">
      {/* HUD (Top Bar) */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/95 to-transparent transition-opacity duration-200 ${isDrawingMode || showPlaylist ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2.5 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white shadow-xl"><X size={20} /></button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-bold tracking-tight truncate max-w-[180px] sm:max-w-xs">{title}</h2>
                    <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded uppercase border border-blue-400/20">
                        {activeFileIndex + 1}/{sheet?.pages.length}
                    </span>
                </div>
                <div className="text-[10px] text-slate-400 font-mono">Page {subPageIndex + 1} of {numSubPages}</div>
            </div>
        </div>

        <div className="flex items-center gap-2">
            {queue && queue.length > 1 && (
                <button onClick={() => setShowPlaylist(!showPlaylist)} className={`p-2.5 rounded-full transition-all ${showPlaylist ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                    <List size={20} />
                </button>
            )}
            <button onClick={() => setIsDrawingMode(!isDrawingMode)} className={`p-2.5 rounded-full transition-all ${isDrawingMode ? 'bg-blue-600 text-white scale-110 shadow-blue-500/40' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                <PenTool size={20} />
            </button>
        </div>
      </div>

      {/* Playlist Drawer */}
      {showPlaylist && queue && (
          <div className="absolute top-20 right-4 z-[100] w-72 max-h-[70vh] bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 fade-in duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Setlist Queue</h3>
                  <button onClick={() => setShowPlaylist(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2">
                  {queue.map((item, idx) => (
                      <button 
                        key={item.id + idx} 
                        onClick={() => { onJumpTo?.(idx); setShowPlaylist(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                          {idx === currentQueueIndex && <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />}
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Main Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {loading && (
            <div className="absolute z-50 inset-0 flex items-center justify-center pointer-events-none">
                 <Loader2 className="animate-spin text-blue-500" size={48} />
            </div>
        )}

        <div 
            ref={containerRef}
            className="relative w-full h-full flex items-center justify-center"
            style={{ touchAction: 'none' }}
        >
            <canvas 
                ref={pdfCanvasRef} 
                className="shadow-2xl select-none pointer-events-none transition-opacity duration-150"
                style={{ maxWidth: '100%', maxHeight: '100%', display: fileType === 'application/pdf' ? 'block' : 'none', imageRendering: 'auto', opacity: loading ? 0 : 1 }}
            />

            {fileType === 'image' && sheet?.pages[activeFileIndex] && (
                <img 
                    src={URL.createObjectURL(sheet.pages[activeFileIndex].blob)} 
                    className="max-w-full max-h-full object-contain pointer-events-none" 
                    alt="Current Page" 
                    onLoad={() => setLoading(false)}
                />
            )}

            {/* Annotation Overlay */}
            {!loading && (
                <svg 
                    className="absolute inset-0 w-full h-full pointer-events-none z-10" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {allStrokes.filter(isStrokeOnCurrentPage).map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                </svg>
            )}
        </div>

        {/* Interaction Zones */}
        {!isDrawingMode && !showPlaylist && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-start pl-4" onClick={handlePagePrev}>
                <ChevronLeft className="text-white/0 group-active:text-white/40 transition-colors" size={48} />
            </div>
            <div className="absolute inset-y-0 right-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-end pr-4" onClick={handlePageNext}>
                <ChevronRight className="text-white/0 group-active:text-white/40 transition-colors" size={48} />
            </div>
          </>
        )}
      </div>

      {/* Page Badge */}
      {!isDrawingMode && !loading && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur rounded-full text-[10px] font-bold tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase">
              {activeFileIndex + 1}.{subPageIndex + 1}
          </div>
      )}

      {/* Drawing Controls */}
      {isDrawingMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-4 p-2 bg-slate-900/90 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl z-50 animate-in slide-in-from-bottom-4 duration-300">
               <button onClick={() => setTool('pen')} className={`p-3 rounded-xl transition-all ${tool === 'pen' ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' : 'text-slate-400 hover:text-slate-200'}`}><PenTool size={20}/></button>
               <button onClick={() => setTool('eraser')} className={`p-3 rounded-xl transition-all ${tool === 'eraser' ? 'bg-red-600 text-white shadow-lg shadow-red-500/30' : 'text-slate-400 hover:text-slate-200'}`}><Eraser size={20}/></button>
               <div className="w-px h-8 bg-white/10 mx-1" />
               <button onClick={() => setIsDrawingMode(false)} className="p-3 text-slate-400 hover:text-white font-medium px-4">Done</button>
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, ListMusic, Trash2, Play, X, Check, Pencil, GripVertical, Search, Import, AlertTriangle } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // DRAG STATE
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [hoverIndex, setHoverIndex] = useState<number | null>(null);
  const [dragOffset, setDragOffset] = useState(0);
  const startPointerY = useRef(0);
  const itemHeights = useRef<number[]>([]);
  const containerRect = useRef<DOMRect | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });
  const importInputRef = useRef<HTMLInputElement>(null);
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;
    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;
    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };
    await storage.saveSetlist(setlist);
    setIsEditing(false);
    onRefresh();
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // --- REORDERING LOGIC ---

  const handlePointerDown = (e: React.PointerEvent, index: number) => {
    const target = e.currentTarget as HTMLElement;
    target.setPointerCapture(e.pointerId);

    if (containerRef.current) {
        containerRect.current = containerRef.current.getBoundingClientRect();
        const children = Array.from(containerRef.current.children);
        itemHeights.current = children.map(child => child.getBoundingClientRect().height + 8); 
    }

    startPointerY.current = e.clientY;
    setDraggedIndex(index);
    setHoverIndex(index);
    setDragOffset(0);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (draggedIndex === null || !containerRect.current) return;

    const currentY = e.clientY;
    const deltaY = currentY - startPointerY.current;
    setDragOffset(deltaY);

    const relativeY = currentY - containerRect.current.top + (containerRef.current?.scrollTop || 0);

    let currentTotalHeight = 0;
    let newHoverIndex = 0;

    for (let i = 0; i < itemHeights.current.length; i++) {
        const h = itemHeights.current[i];
        if (relativeY > currentTotalHeight + h / 2) {
            newHoverIndex = i;
        }
        currentTotalHeight += h;
    }

    const clampedIndex = Math.max(0, Math.min(newHoverIndex, selectedSheetIds.length - 1));
    if (clampedIndex !== hoverIndex) {
        setHoverIndex(clampedIndex);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (draggedIndex !== null && hoverIndex !== null && draggedIndex !== hoverIndex) {
        const newIds = [...selectedSheetIds];
        const [removed] = newIds.splice(draggedIndex, 1);
        newIds.splice(hoverIndex, 0, removed);
        setSelectedSheetIds(newIds);
    }

    const target = e.currentTarget as HTMLElement;
    if (target.hasPointerCapture(e.pointerId)) {
        target.releasePointerCapture(e.pointerId);
    }
    setDraggedIndex(null);
    setHoverIndex(null);
    setDragOffset(0);
  };

  const getItemStyle = (index: number) => {
    if (draggedIndex === null || hoverIndex === null) return {};

    if (index === draggedIndex) {
        return {
            transform: `translateY(${dragOffset}px) scale(1.03)`,
            zIndex: 50,
            boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.8)',
            borderColor: '#3b82f6', 
            backgroundColor: '#1e293b', 
            transition: 'none',
        };
    }

    let shift = 0;
    const height = itemHeights.current[draggedIndex] || 64;

    if (draggedIndex < hoverIndex) {
        if (index > draggedIndex && index <= hoverIndex) shift = -height;
    } else if (draggedIndex > hoverIndex) {
        if (index < draggedIndex && index >= hoverIndex) shift = height;
    }

    return {
        transform: `translateY(${shift}px)`,
        transition: 'transform 0.25s cubic-bezier(0.2, 0, 0, 1)',
    };
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.sheets.length > 0) {
            for (const sheet of result.sheets) {
                await storage.addSheet(sheet);
            }
            const sortedIds = [...result.sheets]
                .sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }))
                .map(s => s.id);

            const newSetlist: Setlist = {
                id: crypto.randomUUID(),
                name: result.setlistName || "Imported Setlist",
                sheetIds: sortedIds,
                dateCreated: Date.now()
            };

            await storage.saveSetlist(newSetlist);
            onRefresh();
        } else if (result.error) {
            alert(result.error);
        }
    }
    if (e.target) e.target.value = '';
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => s.name.toLowerCase().includes(q) || (s.tags && s.tags.some(t => t.toLowerCase().includes(q))));
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white tracking-tight">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={() => setIsEditing(false)} className="px-4 py-2 text-slate-400 hover:text-white transition-colors font-medium">Cancel</button>
             <button onClick={handleSave} disabled={!newSetName || selectedSheetIds.length === 0} className="flex items-center gap-2 bg-green-600 text-white px-5 py-2.5 rounded-xl hover:bg-green-500 disabled:opacity-50 transition-all shadow-lg shadow-green-900/20 active:scale-95">
                <Check size={18} /> <span className="font-bold">Save Setlist</span>
             </button>
           </div>
        </div>

        <div className="relative mb-6">
            <input 
                type="text" 
                placeholder="Ex: Tonight's Performance, Jazz Set, etc." 
                className="w-full bg-slate-800 border-2 border-slate-700 rounded-xl p-4 text-xl text-white focus:border-blue-500 outline-none transition-colors" 
                value={newSetName} 
                onChange={e => setNewSetName(e.target.value)} 
            />
        </div>

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/40 rounded-2xl p-4 border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Add Library Pieces</h3>
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                    <input type="text" placeholder="Search library..." className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-sm text-slate-200 outline-none focus:ring-1 focus:ring-blue-500" value={librarySearch} onChange={(e) => setLibrarySearch(e.target.value)} />
                </div>
                <div className="overflow-y-auto space-y-2 flex-1 no-scrollbar">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <button 
                                key={sheet.id} 
                                onClick={() => !isSelected && toggleSelection(sheet.id)} 
                                className={`w-full flex items-center p-3 rounded-xl border-2 transition-all text-left ${isSelected ? 'opacity-40 border-slate-700 bg-transparent grayscale' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700 hover:border-blue-500/30'}`}
                            >
                                <div className={`w-7 h-7 rounded-lg flex items-center justify-center mr-3 shrink-0 transition-colors ${isSelected ? 'bg-slate-700' : 'bg-blue-600'}`}>
                                    {isSelected ? <Check size={14}/> : <Plus size={14} />}
                                </div>
                                <span className="text-slate-200 text-sm font-medium truncate">{sheet.name}</span>
                            </button>
                        );
                    })}
                </div>
            </div>

            <div className="flex-[1.5] overflow-y-auto min-h-0 bg-slate-800/40 rounded-2xl p-4 no-scrollbar border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Performance Order</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-48 text-slate-500 italic text-sm">
                        <ListMusic size={32} className="mb-2 opacity-20" />
                        Select pieces from the library to build your set
                    </div>
                ) : (
                    <div ref={containerRef} className="space-y-2 select-none relative pb-10">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isBeingDragged = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    style={getItemStyle(index)}
                                    className="flex items-center bg-slate-800 p-2 rounded-xl border border-slate-700 relative group"
                                >
                                    <div 
                                        className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none transition-colors hover:text-white"
                                        onPointerDown={(e) => handlePointerDown(e, index)}
                                        onPointerMove={handlePointerMove}
                                        onPointerUp={handlePointerUp}
                                    >
                                        <GripVertical size={20} />
                                    </div>
                                    <div className={`flex items-center flex-1 min-w-0 ${isBeingDragged ? 'pointer-events-none' : ''}`}>
                                        <div className="w-6 h-6 flex items-center justify-center text-[10px] font-black text-slate-600 bg-slate-900 rounded-md shrink-0">
                                            {index + 1}
                                        </div>
                                        <span className="flex-1 truncate mx-3 text-sm font-semibold text-white">{sheet.name}</span>
                                    </div>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); toggleSelection(id); }} 
                                        className={`p-3 text-slate-500 hover:text-red-500 transition-all ${isBeingDragged ? 'pointer-events-none opacity-0' : 'opacity-0 group-hover:opacity-100'}`}
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-6">
        <div>
            <h1 className="text-4xl font-black text-white mb-2">Setlists</h1>
            <p className="text-slate-400 text-sm">Performance ready repertoire lists</p>
        </div>
        <div className="flex gap-3 items-center flex-wrap">
            <div className="relative group">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-500 transition-colors" />
                <input type="text" placeholder="Search sets..." className="bg-slate-800 border border-slate-700 rounded-xl pl-10 pr-4 py-2.5 text-white focus:border-blue-500 outline-none transition-all w-full md:w-48 lg:w-64" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
            </div>

            <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 px-5 py-2.5 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-lg active:scale-95">
                <Import size={18} />
                <span className="font-bold text-sm">Import Set</span>
            </button>

            <button onClick={startCreate} className="flex items-center gap-2 bg-blue-600 text-white px-6 py-2.5 rounded-xl hover:bg-blue-500 transition-all shadow-xl shadow-blue-900/20 active:scale-95">
                <Plus size={20} />
                <span className="font-bold text-sm">Create New</span>
            </button>

            <input type="file" ref={importInputRef} className="hidden" 
                // @ts-ignore
                webkitdirectory="" directory="" multiple onChange={handleImportSetlist} 
            />
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
          {filteredSetlists.map(list => (
            <div key={list.id} className="bg-slate-800/80 rounded-2xl p-5 flex items-center justify-between hover:bg-slate-800 hover:shadow-2xl hover:scale-[1.01] transition-all border border-slate-700/50 group">
               <div className="flex items-center gap-5 cursor-pointer flex-1" onClick={() => onPlay(list)}>
                  <div className="p-4 bg-slate-900 rounded-2xl text-slate-500 group-hover:text-blue-400 transition-colors"><ListMusic size={28} /></div>
                  <div>
                      <h3 className="text-xl font-bold text-white group-hover:text-blue-400 transition-colors">{list.name}</h3>
                      <div className="flex items-center gap-2 mt-1">
                          <span className="text-xs font-black text-slate-500 uppercase tracking-widest">{list.sheetIds.length} pieces</span>
                          <span className="w-1 h-1 rounded-full bg-slate-700" />
                          <span className="text-xs text-slate-500">{new Date(list.dateCreated).toLocaleDateString()}</span>
                      </div>
                  </div>
               </div>
               <div className="flex items-center gap-3">
                   <button onClick={() => onPlay(list)} className="p-4 bg-green-600 text-white rounded-2xl hover:bg-green-500 transition-all shadow-xl shadow-green-900/20 active:scale-90 flex items-center gap-3 px-6 group/play">
                       <Play size={24} fill="currentColor" />
                       <span className="font-black text-xs uppercase tracking-widest hidden sm:block">Start Gig</span>
                   </button>
                   <div className="w-px h-10 bg-slate-700 mx-2 hidden sm:block" />
                   <button onClick={() => startEdit(list)} className="p-3 text-slate-500 hover:text-blue-400 hover:bg-blue-400/10 rounded-xl transition-all"><Pencil size={20} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-3 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"><Trash2 size={20} /></button>
               </div>
            </div>
          ))}

          {filteredSetlists.length === 0 && (
              <div className="py-24 text-center">
                  <p className="text-slate-500 font-medium">No setlists found matching "{listSearch}"</p>
              </div>
          )}
      </div>

      {deleteModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 w-full max-w-md shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle size={32} className="text-red-500" />
            </div>
            <h2 className="text-2xl font-bold text-white text-center mb-2">Delete Setlist?</h2>
            <p className="text-slate-400 text-center text-sm mb-8 px-4 leading-relaxed">This will remove the "{deleteModal.setlist?.name}" playlist. Your library files and annotations are safe.</p>
            <div className="flex gap-3">
                <button onClick={() => setDeleteModal({ isOpen: false, setlist: null })} className="flex-1 py-3.5 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 py-3.5 bg-red-600 text-white rounded-2xl hover:bg-red-500 transition-all font-bold shadow-lg shadow-red-900/20">Delete List</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
  initialDirection?: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo,
    initialDirection = 'forward'
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [workerReady, setWorkerReady] = useState(false);
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [showPlaylist, setShowPlaylist] = useState(false);

  // Buffering Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());

  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const currentSheetIdRef = useRef(sheetId);

  useEffect(() => {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // Synchronous State Reset on Song Change
  useEffect(() => {
    let active = true;
    const load = async () => {
      // 1. Immediately update ref and clear state to prevent stale content
      currentSheetIdRef.current = sheetId;
      setSheet(null); 
      setLoading(true);

      // 2. Clear caches for the new song
      pdfDocCache.current.clear(); 
      // Note: We don't clear canvasCache here because its keys are unique (sheetId-file-page)

      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || currentSheetIdRef.current !== sheetId) return;

        if (loaded) {
          setSheet(loaded);
          const startIdx = initialDirection === 'backward' ? loaded.pages.length - 1 : 0;
          setActiveFileIndex(startIdx);
          setSubPageIndex(0); 

          const stored = await storage.getAnnotation(sheetId);
          setAllStrokes(stored ? stored.strokes : []);
        } else {
          setLoading(false);
        }
      } catch (err) {
        console.error("Failed to load sheet data", err);
        setLoading(false);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  const getPdfDoc = async (fileIdx: number) => {
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (!sheet || !sheet.pages[fileIdx] || sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const loadingTask = pdfjs.getDocument({
            data: new Uint8Array(arrayBuffer),
            cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
            cMapPacked: true,
        });
        const doc = await loadingTask.promise;
        pdfDocCache.current.set(fileIdx, doc);
        return doc;
    } catch (e) {
        console.error("PDF Load Error", e);
        return null;
    }
  };

  const drawCurrentPage = useCallback(() => {
    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
        const ctx = mainCanvas.getContext('2d', { alpha: false });
        ctx?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        // Not in cache, trigger high-priority render
        renderPageToCache(activeFileIndex, subPageIndex, true);
    }
  }, [sheetId, activeFileIndex, subPageIndex]);

  // UseLayoutEffect ensures we draw BEFORE the browser paints the new frame
  useLayoutEffect(() => {
    if (sheet && workerReady) {
        drawCurrentPage();
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, drawCurrentPage]);

  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number, isHighPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    // Safety check: already cached or already rendering
    if (canvasCache.current.has(key) || renderTasks.current.has(key)) {
        if (isHighPriority && canvasCache.current.has(key)) setLoading(false);
        return;
    }

    try {
        const doc = await getPdfDoc(fIdx);
        // CRITICAL: Ensure we still care about this document/song
        if (!doc || sheetId !== currentSheetIdRef.current) {
            if (isHighPriority) setLoading(false);
            return;
        }

        // BOUNDS CHECK: Prevent 'Invalid page request' error
        if (pIdx < 0 || pIdx >= doc.numPages) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const { clientWidth, clientHeight } = container;
        const unscaledViewport = page.getViewport({ scale: 1 });
        const scale = Math.min(clientWidth / unscaledViewport.width, clientHeight / unscaledViewport.height) * 2.0; 
        const viewport = page.getViewport({ scale });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d', { alpha: false })!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        // Final sanity check before putting into cache and potentially drawing
        if (sheetId === currentSheetIdRef.current) {
            canvasCache.current.set(key, offscreenCanvas);
            renderTasks.current.delete(key);

            // If this was exactly what we needed to show right now, draw it!
            if (isHighPriority && fIdx === activeFileIndex && pIdx === subPageIndex) {
                drawCurrentPage();
            }
        }
    } catch (e) {
        console.error("Render error at page", pIdx, e);
        if (isHighPriority) setLoading(false);
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, drawCurrentPage]);

  // Handle document metadata and prefetching
  useEffect(() => {
    if (!sheet || !workerReady) return;

    const current = sheet.pages[activeFileIndex];
    if (current?.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentSheetIdRef.current) return;

            setNumSubPages(doc.numPages);
            setFileType('application/pdf');

            // PREFETCH Logic: Forward-looking and boundary-aware
            // Next page in current file
            if (subPageIndex < doc.numPages - 1) {
                renderPageToCache(activeFileIndex, subPageIndex + 1);
            } 
            // First page of next file in this sheet
            else if (activeFileIndex < sheet.pages.length - 1) {
                renderPageToCache(activeFileIndex + 1, 0);
            }

            // Previous page in current file
            if (subPageIndex > 0) {
                renderPageToCache(activeFileIndex, subPageIndex - 1);
            }
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setLoading(false);
    }

    // Memory management: clear old canvases from different sheets
    if (canvasCache.current.size > 30) {
        const keys = Array.from(canvasCache.current.keys());
        for (const key of keys) {
            if (!key.startsWith(sheetId)) {
                canvasCache.current.delete(key);
            }
        }
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, renderPageToCache]);

  const handlePageNext = () => {
    if (subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
    } else {
        if (sheet && activeFileIndex < sheet.pages.length - 1) {
            setActiveFileIndex(prev => prev + 1);
            setSubPageIndex(0);
        } else if (hasNext) {
            onNext();
        }
    }
  };

  const handlePagePrev = () => {
    if (subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
    } else {
        if (activeFileIndex > 0) {
            setActiveFileIndex(prev => prev - 1);
            setSubPageIndex(0);
        } else if (hasPrev) {
            onPrev();
        }
    }
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden">
      {/* HUD (Top Bar) */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/95 to-transparent transition-opacity duration-200 ${isDrawingMode || showPlaylist ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2.5 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white shadow-xl"><X size={20} /></button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-bold tracking-tight truncate max-w-[180px] sm:max-w-xs">{title}</h2>
                    <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded uppercase border border-blue-400/20">
                        {activeFileIndex + 1}/{sheet?.pages.length}
                    </span>
                </div>
                <div className="text-[10px] text-slate-400 font-mono">Page {subPageIndex + 1} of {numSubPages}</div>
            </div>
        </div>

        <div className="flex items-center gap-2">
            {queue && queue.length > 1 && (
                <button onClick={() => setShowPlaylist(!showPlaylist)} className={`p-2.5 rounded-full transition-all ${showPlaylist ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                    <List size={20} />
                </button>
            )}
            <button onClick={() => setIsDrawingMode(!isDrawingMode)} className={`p-2.5 rounded-full transition-all ${isDrawingMode ? 'bg-blue-600 text-white scale-110 shadow-blue-500/40' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                <PenTool size={20} />
            </button>
        </div>
      </div>

      {/* Playlist Drawer */}
      {showPlaylist && queue && (
          <div className="absolute top-20 right-4 z-[100] w-72 max-h-[70vh] bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 fade-in duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Setlist Queue</h3>
                  <button onClick={() => setShowPlaylist(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2">
                  {queue.map((item, idx) => (
                      <button 
                        key={item.id + idx} 
                        onClick={() => { onJumpTo?.(idx); setShowPlaylist(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                          {idx === currentQueueIndex && <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />}
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Main Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {loading && (
            <div className="absolute z-50 inset-0 flex items-center justify-center pointer-events-none">
                 <Loader2 className="animate-spin text-blue-500" size={48} />
            </div>
        )}

        <div 
            ref={containerRef}
            className="relative w-full h-full flex items-center justify-center"
            style={{ touchAction: 'none' }}
        >
            <canvas 
                ref={pdfCanvasRef} 
                className="shadow-2xl select-none pointer-events-none transition-opacity duration-150"
                style={{ maxWidth: '100%', maxHeight: '100%', display: fileType === 'application/pdf' ? 'block' : 'none', imageRendering: 'auto', opacity: (loading && !canvasCache.has(`${sheetId}-${activeFileIndex}-${subPageIndex}`)) ? 0 : 1 }}
            />

            {fileType === 'image' && sheet?.pages[activeFileIndex] && (
                <img 
                    src={URL.createObjectURL(sheet.pages[activeFileIndex].blob)} 
                    className="max-w-full max-h-full object-contain pointer-events-none" 
                    alt="Current Page" 
                    onLoad={() => setLoading(false)}
                />
            )}

            {/* Annotation Overlay */}
            {!loading && (
                <svg 
                    className="absolute inset-0 w-full h-full pointer-events-none z-10" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {allStrokes.filter(isStrokeOnCurrentPage).map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                </svg>
            )}
        </div>

        {/* Interaction Zones */}
        {!isDrawingMode && !showPlaylist && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-start pl-4" onClick={handlePagePrev}>
                <ChevronLeft className="text-white/0 group-active:text-white/40 transition-colors" size={48} />
            </div>
            <div className="absolute inset-y-0 right-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-end pr-4" onClick={handlePageNext}>
                <ChevronRight className="text-white/0 group-active:text-white/40 transition-colors" size={48} />
            </div>
          </>
        )}
      </div>

      {/* Page Badge */}
      {!isDrawingMode && !loading && (
