export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
  initialDirection?: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo,
    initialDirection = 'forward'
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [workerReady, setWorkerReady] = useState(false);
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [showPlaylist, setShowPlaylist] = useState(false);

  // Buffering Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());

  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const currentSheetIdRef = useRef(sheetId);

  useEffect(() => {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // Synchronous State Reset on Song Change
  useEffect(() => {
    let active = true;
    const load = async () => {
      // 1. Immediately update ref and clear state to prevent stale content
      currentSheetIdRef.current = sheetId;
      setSheet(null); 
      setLoading(true);

      // 2. Clear caches for the new song
      pdfDocCache.current.clear(); 
      // Note: We don't clear canvasCache here because its keys are unique (sheetId-file-page)

      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || currentSheetIdRef.current !== sheetId) return;

        if (loaded) {
          setSheet(loaded);
          const startIdx = initialDirection === 'backward' ? loaded.pages.length - 1 : 0;
          setActiveFileIndex(startIdx);
          setSubPageIndex(0); 

          const stored = await storage.getAnnotation(sheetId);
          setAllStrokes(stored ? stored.strokes : []);
        } else {
          setLoading(false);
        }
      } catch (err) {
        console.error("Failed to load sheet data", err);
        setLoading(false);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  const getPdfDoc = async (fileIdx: number) => {
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (!sheet || !sheet.pages[fileIdx] || sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const loadingTask = pdfjs.getDocument({
            data: new Uint8Array(arrayBuffer),
            cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
            cMapPacked: true,
        });
        const doc = await loadingTask.promise;
        pdfDocCache.current.set(fileIdx, doc);
        return doc;
    } catch (e) {
        console.error("PDF Load Error", e);
        return null;
    }
  };

  const drawCurrentPage = useCallback(() => {
    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
        const ctx = mainCanvas.getContext('2d', { alpha: false });
        ctx?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        // Not in cache, trigger high-priority render
        renderPageToCache(activeFileIndex, subPageIndex, true);
    }
  }, [sheetId, activeFileIndex, subPageIndex, renderPageToCache]);

  // UseLayoutEffect ensures we draw BEFORE the browser paints the new frame
  useLayoutEffect(() => {
    if (sheet && workerReady) {
        drawCurrentPage();
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, drawCurrentPage]);

  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number, isHighPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    // Safety check: already cached or already rendering
    if (canvasCache.current.has(key) || renderTasks.current.has(key)) {
        if (isHighPriority && canvasCache.current.has(key)) setLoading(false);
        return;
    }

    try {
        const doc = await getPdfDoc(fIdx);
        // CRITICAL: Ensure we still care about this document/song
        if (!doc || sheetId !== currentSheetIdRef.current) {
            if (isHighPriority) setLoading(false);
            return;
        }

        // BOUNDS CHECK: Prevent 'Invalid page request' error
        if (pIdx < 0 || pIdx >= doc.numPages) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const { clientWidth, clientHeight } = container;
        const unscaledViewport = page.getViewport({ scale: 1 });
        const scale = Math.min(clientWidth / unscaledViewport.width, clientHeight / unscaledViewport.height) * 2.0; 
        const viewport = page.getViewport({ scale });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d', { alpha: false })!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        // Final sanity check before putting into cache and potentially drawing
        if (sheetId === currentSheetIdRef.current) {
            canvasCache.current.set(key, offscreenCanvas);
            renderTasks.current.delete(key);

            // If this was exactly what we needed to show right now, draw it!
            if (isHighPriority && fIdx === activeFileIndex && pIdx === subPageIndex) {
                drawCurrentPage();
            }
        }
    } catch (e) {
        console.error("Render error at page", pIdx, e);
        if (isHighPriority) setLoading(false);
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, drawCurrentPage]);

  // Handle document metadata and prefetching
  useEffect(() => {
    if (!sheet || !workerReady) return;

    const current = sheet.pages[activeFileIndex];
    if (current?.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentSheetIdRef.current) return;

            setNumSubPages(doc.numPages);
            setFileType('application/pdf');

            // PREFETCH Logic: Forward-looking and boundary-aware
            // Next page in current file
            if (subPageIndex < doc.numPages - 1) {
                renderPageToCache(activeFileIndex, subPageIndex + 1);
            } 
            // First page of next file in this sheet
            else if (activeFileIndex < sheet.pages.length - 1) {
                renderPageToCache(activeFileIndex + 1, 0);
            }

            // Previous page in current file
            if (subPageIndex > 0) {
                renderPageToCache(activeFileIndex, subPageIndex - 1);
            }
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setLoading(false);
    }

    // Memory management: clear old canvases from different sheets
    if (canvasCache.current.size > 30) {
        const keys = Array.from(canvasCache.current.keys());
        for (const key of keys) {
            if (!key.startsWith(sheetId)) {
                canvasCache.current.delete(key);
            }
        }
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, renderPageToCache]);

  const handlePageNext = () => {
    if (subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
    } else {
        if (sheet && activeFileIndex < sheet.pages.length - 1) {
            setActiveFileIndex(prev => prev + 1);
            setSubPageIndex(0);
        } else if (hasNext) {
            onNext();
        }
    }
  };

  const handlePagePrev = () => {
    if (subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
    } else {
        if (activeFileIndex > 0) {
            setActiveFileIndex(prev => prev - 1);
            setSubPageIndex(0);
        } else if (hasPrev) {
            onPrev();
        }
    }
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden">
      {/* HUD (Top Bar) */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/95 to-transparent transition-opacity duration-200 ${isDrawingMode || showPlaylist ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2.5 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white shadow-xl"><X size={20} /></button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-bold tracking-tight truncate max-w-[180px] sm:max-w-xs">{title}</h2>
                    <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded uppercase border border-blue-400/20">
                        {activeFileIndex + 1}/{sheet?.pages.length}
                    </span>
                </div>
                <div className="text-[10px] text-slate-400 font-mono">Page {subPageIndex + 1} of {numSubPages}</div>
            </div>
        </div>

        <div className="flex items-center gap-2">
            {queue && queue.length > 1 && (
                <button onClick={() => setShowPlaylist(!showPlaylist)} className={`p-2.5 rounded-full transition-all ${showPlaylist ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                    <List size={20} />
                </button>
            )}
            <button onClick={() => setIsDrawingMode(!isDrawingMode)} className={`p-2.5 rounded-full transition-all ${isDrawingMode ? 'bg-blue-600 text-white scale-110 shadow-blue-500/40' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                <PenTool size={20} />
            </button>
        </div>
      </div>

      {/* Playlist Drawer */}
      {showPlaylist && queue && (
          <div className="absolute top-20 right-4 z-[100] w-72 max-h-[70vh] bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 fade-in duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Setlist Queue</h3>
                  <button onClick={() => setShowPlaylist(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2">
                  {queue.map((item, idx) => (
                      <button 
                        key={item.id + idx} 
                        onClick={() => { onJumpTo?.(idx); setShowPlaylist(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                          {idx === currentQueueIndex && <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />}
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Main Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {loading && (
            <div className="absolute z-50 inset-0 flex items-center justify-center pointer-events-none">
                 <Loader2 className="animate-spin text-blue-500" size={48} />
            </div>
        )}

        <div 
            ref={containerRef}
            className="relative w-full h-full flex items-center justify-center"
            style={{ touchAction: 'none' }}
        >
            <canvas 
                ref={pdfCanvasRef} 
                className="shadow-2xl select-none pointer-events-none transition-opacity duration-150"
                /* Corrected canvasCache access by adding .current */
                style={{ maxWidth: '100%', maxHeight: '100%', display: fileType === 'application/pdf' ? 'block' : 'none', imageRendering: 'auto', opacity: (loading && !canvasCache.current.has(`${sheetId}-${activeFileIndex}-${subPageIndex}`)) ? 0 : 1 }}
            />

            {fileType === 'image' && sheet?.pages[activeFileIndex] && (
                <img 
                    src={URL.createObjectURL(sheet.pages[activeFileIndex].blob)} 
                    className="max-w-full max-h-full object-contain pointer-events-none" 
                    alt="Current Page" 
                    onLoad={() => setLoading(false)}
                />
            )}

            {/* Annotation Overlay */}
            {!loading && (
                <svg 
                    className="absolute inset-0 w-full h-full pointer-events-none z-10" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {allStrokes.filter(isStrokeOnCurrentPage).map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                </svg>
            )}
        </div>

        {/* Interaction Zones */}
        {!isDrawingMode && !showPlaylist && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-start pl-4" onClick={handlePagePrev}>
                <ChevronLeft className="text-white/0 group-active:text-white/40 transition-colors" size={48} />
            </div>
            <div className="absolute inset-y-0 right-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-end pr-4" onClick={handlePageNext}>
                <ChevronRight className="text-white/0 group-active:text-white/40 transition-colors" size={48} />
            </div>
          </>
        )}
      </div>

      {/* Page Badge */}
      {!isDrawingMode && !loading && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur rounded-full text-[10px] font-bold tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase">
              {activeFileIndex + 1}.{subPageIndex + 1}
          </div>
      )}

      {/* Drawing Controls */}
      {isDrawingMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-4 p-2 bg-slate-900/90 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl z-50 animate-in slide-in-from-bottom-4 duration-300">
               <button onClick={() => setTool('pen')} className={`p-3 rounded-xl transition-all ${tool === 'pen' ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' : 'text-slate-400 hover:text-slate-200'}`}><PenTool size={20}/></button>
               <button onClick={() => setTool('eraser')} className={`p-3 rounded-xl transition-all ${tool === 'eraser' ? 'bg-red-600 text-white shadow-lg shadow-red-500/30' : 'text-slate-400 hover:text-slate-200'}`}><Eraser size={20}/></button>
               <div className="w-px h-8 bg-white/10 mx-1" />
               <button onClick={() => setIsDrawingMode(false)} className="p-3 text-slate-400 hover:text-white font-medium px-4">Done</button>
          </div>
      )}
    </div>
  );
};

