            renderTasks.current.delete(key);

            // If this was exactly what we needed to show right now, draw it directly!
            // This replaces the recursive call to drawCurrentPage and breaks the circular dependency.
            if (isHighPriority && fIdx === activeFileIndex && pIdx === subPageIndex) {
                const mainCanvas = pdfCanvasRef.current;
