export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
  initialDirection?: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo,
    initialDirection = 'forward'
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [workerReady, setWorkerReady] = useState(false);
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [showPlaylist, setShowPlaylist] = useState(false);

  // Buffering Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());

  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const currentSheetIdRef = useRef(sheetId);

  useEffect(() => {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // Synchronous State Reset on Song Change
  // This is critical to prevent "Old Page Indices" appearing under "New Song Title"
  useEffect(() => {
    currentSheetIdRef.current = sheetId;

    // reset UI state immediately and synchronously
    setSheet(null);
    setLoading(true);
    setSubPageIndex(0);
    setNumSubPages(0);
    pdfDocCache.current.clear();
    // Clear current canvas to black while loading
    const mainCanvas = pdfCanvasRef.current;
    if (mainCanvas) {
      const ctx = mainCanvas.getContext('2d');
      ctx?.clearRect(0, 0, mainCanvas.width, mainCanvas.height);
    }

    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || currentSheetIdRef.current !== sheetId) return;

        if (loaded) {
          // If moving backward, we want to start at the end of the song
          const startFileIdx = initialDirection === 'backward' ? loaded.pages.length - 1 : 0;

          setSheet(loaded);
          setActiveFileIndex(startFileIdx);

          const stored = await storage.getAnnotation(sheetId);
          if (active) setAllStrokes(stored ? stored.strokes : []);
        } else {
          setLoading(false);
        }
      } catch (err) {
        console.error("Failed to load sheet data", err);
        setLoading(false);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  // Memoize getPdfDoc to prevent cascading recreation of downstream callbacks
  const getPdfDoc = useCallback(async (fileIdx: number) => {
    // Check if sheet is actually ready
    if (!sheet || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const loadingTask = pdfjs.getDocument({
            data: new Uint8Array(arrayBuffer),
            cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
            cMapPacked: true,
        });
        const doc = await loadingTask.promise;
        pdfDocCache.current.set(fileIdx, doc);
        return doc;
    } catch (e) {
        console.error("PDF Load Error", e);
        return null;
    }
  }, [sheet]);

  // RENDER TO CACHE: Handle high-priority drawing internally to break loops
  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number, isHighPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key) || renderTasks.current.has(key)) {
        if (isHighPriority && canvasCache.current.has(key)) setLoading(false);
        return;
    }

    try {
        const doc = await getPdfDoc(fIdx);
        if (!doc || sheetId !== currentSheetIdRef.current) {
            if (isHighPriority) setLoading(false);
            return;
        }

        if (pIdx < 0 || pIdx >= doc.numPages) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const { clientWidth, clientHeight } = container;
        const unscaledViewport = page.getViewport({ scale: 1 });
        const scale = Math.min(clientWidth / unscaledViewport.width, clientHeight / unscaledViewport.height) * 2.0; 
        const viewport = page.getViewport({ scale });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d', { alpha: false })!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentSheetIdRef.current) {
            canvasCache.current.set(key, offscreenCanvas);
            renderTasks.current.delete(key);

            if (isHighPriority && fIdx === activeFileIndex && pIdx === subPageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions(prev => {
                      if (prev.width === offscreenCanvas.width && prev.height === offscreenCanvas.height) return prev;
                      return { width: offscreenCanvas.width, height: offscreenCanvas.height };
                    });
                    const ctx = mainCanvas.getContext('2d', { alpha: false });
                    ctx?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        console.error("Render error at page", pIdx, e);
        if (isHighPriority) setLoading(false);
    }
  }, [sheetId, activeFileIndex, subPageIndex, getPdfDoc]);

  // DRAW CURRENT PAGE
  const drawCurrentPage = useCallback(() => {
    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions(prev => {
          if (prev.width === cachedCanvas.width && prev.height === cachedCanvas.height) return prev;
          return { width: cachedCanvas.width, height: cachedCanvas.height };
        });
        const ctx = mainCanvas.getContext('2d', { alpha: false });
        ctx?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        renderPageToCache(activeFileIndex, subPageIndex, true);
    }
  }, [sheetId, activeFileIndex, subPageIndex, renderPageToCache]);

  useLayoutEffect(() => {
    if (sheet && workerReady) {
        drawCurrentPage();
    }
  }, [sheet, workerReady, drawCurrentPage]);

  // Prefetching and Metadata Update
  useEffect(() => {
    if (!sheet || !workerReady) return;

    const current = sheet.pages[activeFileIndex];
    if (current?.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentSheetIdRef.current) return;

            // If we just loaded a document and we're moving backward, 
            // we should set the subPageIndex to the last page of this document.
            if (initialDirection === 'backward' && numSubPages === 0) {
              setSubPageIndex(doc.numPages - 1);
            }

            setNumSubPages(doc.numPages);
            setFileType('application/pdf');

            // Forward prefetch
            if (subPageIndex < doc.numPages - 1) {
                renderPageToCache(activeFileIndex, subPageIndex + 1);
            } else if (activeFileIndex < sheet.pages.length - 1) {
                renderPageToCache(activeFileIndex + 1, 0);
            }
            // Backward prefetch
            if (subPageIndex > 0) {
                renderPageToCache(activeFileIndex, subPageIndex - 1);
            }
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setLoading(false);
    }

    // Cache size management
    if (canvasCache.current.size > 30) {
        const keys = Array.from(canvasCache.current.keys());
        for (const key of keys) {
            if (!key.startsWith(sheetId)) {
                canvasCache.current.delete(key);
            }
        }
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, renderPageToCache, getPdfDoc, initialDirection, numSubPages]);

  const handlePageNext = () => {
    if (subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
    } else {
        if (sheet && activeFileIndex < sheet.pages.length - 1) {
            setActiveFileIndex(prev => prev + 1);
            setSubPageIndex(0);
        } else if (hasNext) {
            onNext();
        }
    }
  };

  const handlePagePrev = () => {
    if (subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
    } else {
        if (activeFileIndex > 0) {
            setActiveFileIndex(prev => prev - 1);
            // This is handled by directional logic in the prefetch effect, 
            // but for instant feedback we'd ideally know the page count of the prev doc.
            // Since we don't always know it yet, we just trigger the index change.
            setNumSubPages(0); // Force re-fetch of doc count
            setSubPageIndex(0); // Will be corrected by initialDirection: backward logic
        } else if (hasPrev) {
            onPrev();
        }
    }
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden">
      {/* HUD (Top Bar) */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/95 to-transparent transition-opacity duration-200 ${isDrawingMode || showPlaylist ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2.5 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white shadow-xl"><X size={20} /></button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-bold tracking-tight truncate max-w-[180px] sm:max-w-xs">{title}</h2>
                    <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded uppercase border border-blue-400/20">
                        {sheet ? `${activeFileIndex + 1}/${sheet.pages.length}` : '-/-'}
                    </span>
                </div>
                <div className="text-[10px] text-slate-400 font-mono">
                    {numSubPages > 0 ? `Page ${subPageIndex + 1} of ${numSubPages}` : 'Loading...'}
                </div>
            </div>
        </div>

        <div className="flex items-center gap-2">
            {queue && queue.length > 1 && (
                <button onClick={() => setShowPlaylist(!showPlaylist)} className={`p-2.5 rounded-full transition-all ${showPlaylist ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                    <List size={20} />
                </button>
            )}
            <button onClick={() => setIsDrawingMode(!isDrawingMode)} className={`p-2.5 rounded-full transition-all ${isDrawingMode ? 'bg-blue-600 text-white scale-110 shadow-blue-500/40' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                <PenTool size={20} />
            </button>
        </div>
      </div>

      {/* Playlist Drawer */}
      {showPlaylist && queue && (
          <div className="absolute top-20 right-4 z-[100] w-72 max-h-[70vh] bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 fade-in duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Setlist Queue</h3>
                  <button onClick={() => setShowPlaylist(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2">
                  {queue.map((item, idx) => (
                      <button 
                        key={item.id + idx} 
                        onClick={() => { onJumpTo?.(idx); setShowPlaylist(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                          {idx === currentQueueIndex && <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />}
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Main Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {loading && (
            <div className="absolute z-50 inset-0 flex items-center justify-center pointer-events-none">
                 <Loader2 className="animate-spin text-blue-500" size={48} />
            </div>
        )}

        <div 
            ref={containerRef}
            className="relative w-full h-full flex items-center justify-center"
            style={{ touchAction: 'none' }}
        >
            <canvas 
                ref={pdfCanvasRef} 
                className="shadow-2xl select-none pointer-events-none transition-opacity duration-150"
                style={{ maxWidth: '100%', maxHeight: '100%', display: fileType === 'application/pdf' ? 'block' : 'none', imageRendering: 'auto', opacity: (loading && !canvasCache.current.has(`${sheetId}-${activeFileIndex}-${subPageIndex}`)) ? 0 : 1 }}
            />

            {fileType === 'image' && sheet?.pages[activeFileIndex] && (
                <img 
                    src={URL.createObjectURL(sheet.pages[activeFileIndex].blob)} 
                    className="max-w-full max-h-full object-contain pointer-events-none" 
                    alt="Current Page" 
                    onLoad={() => setLoading(false)}
                />
            )}

            {/* Annotation Overlay */}
            {!loading && (
                <svg 
                    className="absolute inset-0 w-full h-full pointer-events-none z-10" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {allStrokes.filter(isStrokeOnCurrentPage).map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                </svg>
            )}
        </div>

        {/* Interaction Zones */}
        {!isDrawingMode && !showPlaylist && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-start pl-4" onClick={handlePagePrev}>
                <ChevronLeft className="text-white/0 group-active:text-white/40 transition-colors" size={48} />
            </div>
            <div className="absolute inset-y-0 right-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-end pr-4" onClick={handlePageNext}>
                <ChevronRight className="text-white/0 group-active:text-white/40 transition-colors" size={48} />
            </div>
          </>
        )}
      </div>

      {/* Page Badge */}
      {!isDrawingMode && !loading && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur rounded-full text-[10px] font-bold tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase">
              {activeFileIndex + 1}.{subPageIndex + 1}
          </div>
      )}

      {/* Drawing Controls */}
      {isDrawingMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-4 p-2 bg-slate-900/90 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl z-50 animate-in slide-in-from-bottom-4 duration-300">
               <button onClick={() => setTool('pen')} className={`p-3 rounded-xl transition-all ${tool === 'pen' ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' : 'text-slate-400 hover:text-slate-200'}`}><PenTool size={20}/></button>
               <button onClick={() => setTool('eraser')} className={`p-3 rounded-xl transition-all ${tool === 'eraser' ? 'bg-red-600 text-white shadow-lg shadow-red-500/30' : 'text-slate-400 hover:text-slate-200'}`}><Eraser size={20}/></button>
               <div className="w-px h-8 bg-white/10 mx-1" />
               <button onClick={() => setIsDrawingMode(false)} className="p-3 text-slate-400 hover:text-white font-medium px-4">Done</button>
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
  initialDirection?: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo,
    initialDirection = 'forward'
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [workerReady, setWorkerReady] = useState(false);
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [showPlaylist, setShowPlaylist] = useState(false);

  // Refs for async stability
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const targetLastPageRef = useRef(false); // Flag to snap to end of song/file

  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const currentSheetIdRef = useRef(sheetId);

  useEffect(() => {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // Sync state reset on song change
  useEffect(() => {
    currentSheetIdRef.current = sheetId;
    targetLastPageRef.current = initialDirection === 'backward';

    // Clear state immediately to prevent "Page Order Mismatch" flickers
    setSheet(null);
    setLoading(true);
    setSubPageIndex(0);
    setNumSubPages(0);
    pdfDocCache.current.clear();

    const mainCanvas = pdfCanvasRef.current;
    if (mainCanvas) {
      const ctx = mainCanvas.getContext('2d');
      ctx?.clearRect(0, 0, mainCanvas.width, mainCanvas.height);
    }

    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || currentSheetIdRef.current !== sheetId) return;

        if (loaded) {
          // Determine target file (last file if navigating backward)
          const startFileIdx = targetLastPageRef.current ? loaded.pages.length - 1 : 0;

          setSheet(loaded);
          setActiveFileIndex(startFileIdx);

          const stored = await storage.getAnnotation(sheetId);
          if (active) setAllStrokes(stored ? stored.strokes : []);
        } else {
          setLoading(false);
        }
      } catch (err) {
        console.error("Failed to load sheet", err);
        setLoading(false);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({
            data: new Uint8Array(arrayBuffer),
            cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
            cMapPacked: true,
        }).promise;
        pdfDocCache.current.set(fileIdx, doc);
        return doc;
    } catch (e) {
        return null;
    }
  }, [sheet]);

  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number, isHighPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;
    if (canvasCache.current.has(key) || renderTasks.current.has(key)) {
        if (isHighPriority && canvasCache.current.has(key)) setLoading(false);
        return;
    }

    try {
        const doc = await getPdfDoc(fIdx);
        if (!doc || sheetId !== currentSheetIdRef.current) {
            if (isHighPriority) setLoading(false);
            return;
        }

        if (pIdx < 0 || pIdx >= doc.numPages) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const { clientWidth, clientHeight } = container;
        const viewport = page.getViewport({ 
            scale: Math.min(clientWidth / page.getViewport({ scale: 1 }).width, clientHeight / page.getViewport({ scale: 1 }).height) * 2.0 
        });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d', { alpha: false })!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentSheetIdRef.current) {
            canvasCache.current.set(key, offscreenCanvas);
            renderTasks.current.delete(key);

            if (isHighPriority && fIdx === activeFileIndex && pIdx === subPageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions(prev => prev.width === offscreenCanvas.width ? prev : { width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d', { alpha: false })?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isHighPriority) setLoading(false);
    }
  }, [sheetId, activeFileIndex, subPageIndex, getPdfDoc]);

  const drawCurrentPage = useCallback(() => {
    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions(prev => prev.width === cachedCanvas.width ? prev : { width: cachedCanvas.width, height: cachedCanvas.height });
        mainCanvas.getContext('2d', { alpha: false })?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        renderPageToCache(activeFileIndex, subPageIndex, true);
    }
  }, [sheetId, activeFileIndex, subPageIndex, renderPageToCache]);

  useLayoutEffect(() => {
    if (sheet && workerReady && numSubPages > 0) {
        drawCurrentPage();
    }
  }, [sheet, workerReady, drawCurrentPage, numSubPages]);

  // Handle Metadata & Target Page Snapping
  useEffect(() => {
    if (!sheet || !workerReady) return;

    const current = sheet.pages[activeFileIndex];
    if (current?.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentSheetIdRef.current) return;

            const total = doc.numPages;
            setNumSubPages(total);
            setFileType('application/pdf');

            // SNAP TO LAST PAGE: If we are navigating backward, we need to show the last page of the file
            if (targetLastPageRef.current) {
              setSubPageIndex(total - 1);
              targetLastPageRef.current = false; // Reset flag after snapping
            }

            // Prefetching logic with boundary safety
            if (subPageIndex < total - 1) renderPageToCache(activeFileIndex, subPageIndex + 1);
            else if (activeFileIndex < sheet.pages.length - 1) renderPageToCache(activeFileIndex + 1, 0);

            if (subPageIndex > 0) renderPageToCache(activeFileIndex, subPageIndex - 1);
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setLoading(false);
        targetLastPageRef.current = false;
    }
  }, [sheet, sheetId, activeFileIndex, subPageIndex, workerReady, renderPageToCache, getPdfDoc]);

  const handlePageNext = () => {
    if (subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
    } else {
        if (sheet && activeFileIndex < sheet.pages.length - 1) {
            setActiveFileIndex(prev => prev + 1);
            setSubPageIndex(0);
            setNumSubPages(0); // Mark as unknown to trigger metadata fetch
        } else if (hasNext) {
            onNext();
        }
    }
  };

  const handlePagePrev = () => {
    if (subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
    } else {
        if (activeFileIndex > 0) {
            // Target the PREVIOUS file in the same sheet
            const nextFileIdx = activeFileIndex - 1;
            setActiveFileIndex(nextFileIdx);
            setNumSubPages(0);
            targetLastPageRef.current = true; // Tell metadata effect to snap to end of this file
        } else if (hasPrev) {
            onPrev();
        }
    }
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden select-none">
      {/* Top HUD */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/95 to-transparent transition-opacity duration-200 ${isDrawingMode || showPlaylist ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2.5 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white shadow-xl"><X size={20} /></button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-bold tracking-tight truncate max-w-[150px] sm:max-w-xs">{title}</h2>
                    <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded uppercase border border-blue-400/20">
                        {sheet ? `${activeFileIndex + 1}/${sheet.pages.length}` : '-/-'}
                    </span>
                </div>
                <div className="text-[10px] text-slate-400 font-mono tracking-wider">
                    {numSubPages > 0 ? `PAGE ${subPageIndex + 1} OF ${numSubPages}` : 'SYNCHRONIZING...'}
                </div>
            </div>
        </div>

        <div className="flex items-center gap-2">
            {queue && queue.length > 1 && (
                <button onClick={() => setShowPlaylist(!showPlaylist)} className={`p-2.5 rounded-full transition-all ${showPlaylist ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                    <List size={20} />
                </button>
            )}
            <button onClick={() => setIsDrawingMode(!isDrawingMode)} className={`p-2.5 rounded-full transition-all ${isDrawingMode ? 'bg-blue-600 text-white scale-110 shadow-blue-500/40' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                <PenTool size={20} />
            </button>
        </div>
      </div>

      {/* Setlist Drawer */}
      {showPlaylist && queue && (
          <div className="absolute top-20 right-4 z-[100] w-72 max-h-[70vh] bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 fade-in duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Queue</h3>
                  <button onClick={() => setShowPlaylist(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2">
                  {queue.map((item, idx) => (
                      <button 
                        key={item.id + idx} 
                        onClick={() => { onJumpTo?.(idx); setShowPlaylist(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                          {idx === currentQueueIndex && <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />}
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Main Content Area */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {loading && (
            <div className="absolute z-50 inset-0 flex items-center justify-center pointer-events-none">
                 <Loader2 className="animate-spin text-blue-500" size={48} />
            </div>
        )}

        <div ref={containerRef} className="relative w-full h-full flex items-center justify-center touch-none">
            <canvas 
                ref={pdfCanvasRef} 
                className="shadow-2xl pointer-events-none transition-opacity duration-200"
                style={{ 
                    maxWidth: '100%', 
                    maxHeight: '100%', 
                    display: fileType === 'application/pdf' ? 'block' : 'none',
                    opacity: loading ? 0 : 1
                }}
            />

            {fileType === 'image' && sheet?.pages[activeFileIndex] && (
                <img 
                    src={URL.createObjectURL(sheet.pages[activeFileIndex].blob)} 
                    className="max-w-full max-h-full object-contain pointer-events-none" 
                    alt="Page" 
                    onLoad={() => setLoading(false)}
                />
            )}

            {!loading && (
                <svg 
                    className="absolute inset-0 w-full h-full pointer-events-none z-10" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {allStrokes.filter(isStrokeOnCurrentPage).map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                </svg>
            )}
        </div>

        {/* Navigation Touch Zones */}
        {!isDrawingMode && !showPlaylist && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center pl-4" onClick={handlePagePrev}>
                <ChevronLeft className="text-white/0 group-active:text-white/40" size={48} />
            </div>
            <div className="absolute inset-y-0 right-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-end pr-4" onClick={handlePageNext}>
                <ChevronRight className="text-white/0 group-active:text-white/40" size={48} />
            </div>
          </>
        )}
      </div>

      {/* Floating Info Badge */}
      {!isDrawingMode && !loading && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-2xl">
              FILE {activeFileIndex + 1} • PAGE {subPageIndex + 1}
          </div>
      )}

      {/* Pen Tools */}
      {isDrawingMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-4 p-2 bg-slate-900/90 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl z-50 animate-in slide-in-from-bottom-4 duration-300">
               <button onClick={() => setTool('pen')} className={`p-3 rounded-xl transition-all ${tool === 'pen' ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' : 'text-slate-400 hover:text-slate-200'}`}><PenTool size={20}/></button>
               <button onClick={() => setTool('eraser')} className={`p-3 rounded-xl transition-all ${tool === 'eraser' ? 'bg-red-600 text-white shadow-lg shadow-red-500/30' : 'text-slate-400 hover:text-slate-200'}`}><Eraser size={20}/></button>
               <div className="w-px h-8 bg-white/10 mx-1" />
               <button onClick={() => setIsDrawingMode(false)} className="p-3 text-slate-400 hover:text-white font-bold px-4 tracking-tight uppercase text-xs">Done</button>
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

interface ViewerProps {
  sheetId: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  title: string;
  queue?: { id: string; name: string }[];
  currentQueueIndex?: number;
  onJumpTo?: (index: number) => void;
  initialDirection?: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({ 
    sheetId, onClose, onNext, onPrev, hasNext, hasPrev, title,
    queue, currentQueueIndex, onJumpTo,
    initialDirection = 'forward'
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [fileType, setFileType] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [workerReady, setWorkerReady] = useState(false);
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [tool, setTool] = useState<'pen' | 'eraser'>('pen');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [showPlaylist, setShowPlaylist] = useState(false);

  // Synchronization and Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());

  // This ref tracks the most recent navigation intent to prevent race conditions
  const currentRequestRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number | 'last' }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? 'last' : 0
  });

  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    setWorkerReady(true);
  }, []);

  // 1. CLEAR STATE IMMEDIATELY ON SHEET CHANGE
  // This prevents the "Page 1 of Previous Song" flash
  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    // Setting subPageIndex to a special value while "snapping" logic is pending
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0); 
    pdfDocCache.current.clear();

    // Wipe current canvas immediately
    const mainCanvas = pdfCanvasRef.current;
    if (mainCanvas) {
      const ctx = mainCanvas.getContext('2d');
      ctx?.clearRect(0, 0, mainCanvas.width, mainCanvas.height);
    }

    currentRequestRef.current = {
      sheetId,
      fileIndex: 0, // temporary, will be updated in load effect
      pageIndex: initialDirection === 'backward' ? 'last' : 0
    };
  }, [sheetId, initialDirection]);

  // 2. LOAD SHEET DATA
  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentRequestRef.current.sheetId) return;

        if (loaded) {
          const startFileIdx = initialDirection === 'backward' ? loaded.pages.length - 1 : 0;

          setSheet(loaded);
          setActiveFileIndex(startFileIdx);
          currentRequestRef.current.fileIndex = startFileIdx;

          const stored = await storage.getAnnotation(sheetId);
          if (active) setAllStrokes(stored ? stored.strokes : []);
        } else {
          setLoading(false);
        }
      } catch (err) {
        console.error("Storage error", err);
        setLoading(false);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  // 3. PDF DOCUMENT FETCHER
  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({
            data: new Uint8Array(arrayBuffer),
            cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
            cMapPacked: true,
        }).promise;
        pdfDocCache.current.set(fileIdx, doc);
        return doc;
    } catch (e) {
        return null;
    }
  }, [sheet]);

  // 4. METADATA AND SNAP LOGIC
  // This effect handles resolving "last page" and prefetching
  useEffect(() => {
    if (!sheet || !workerReady) return;

    const current = sheet.pages[activeFileIndex];
    if (current?.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentRequestRef.current.sheetId) return;

            const total = doc.numPages;
            setNumSubPages(total);
            setFileType('application/pdf');

            // Determine if we need to snap to the end (subPageIndex is -1 or request is 'last')
            if (currentRequestRef.current.pageIndex === 'last' || subPageIndex === -1) {
              const targetPage = total - 1;
              setSubPageIndex(targetPage);
              currentRequestRef.current.pageIndex = targetPage;
            }
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setSubPageIndex(0);
        currentRequestRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, sheetId, activeFileIndex, workerReady, getPdfDoc, subPageIndex]);

  // 5. RENDERER
  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number, isHighPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;
    if (canvasCache.current.has(key) || renderTasks.current.has(key)) {
        if (isHighPriority && canvasCache.current.has(key)) setLoading(false);
        return;
    }

    try {
        const doc = await getPdfDoc(fIdx);
        if (!doc || sheetId !== currentRequestRef.current.sheetId) return;
        if (pIdx < 0 || pIdx >= doc.numPages) return;

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const { clientWidth, clientHeight } = container;
        const viewport = page.getViewport({ 
            scale: Math.min(clientWidth / page.getViewport({ scale: 1 }).width, clientHeight / page.getViewport({ scale: 1 }).height) * 2.0 
        });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d', { alpha: false })!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        // Final guard: ensure we are still on the same song/page before updating UI
        if (sheetId === currentRequestRef.current.sheetId) {
            canvasCache.current.set(key, offscreenCanvas);
            renderTasks.current.delete(key);

            if (isHighPriority && fIdx === activeFileIndex && pIdx === subPageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d', { alpha: false })?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isHighPriority) setLoading(false);
    }
  }, [sheetId, activeFileIndex, subPageIndex, getPdfDoc]);

  // 6. DRAWING TRIGGER
  const drawCurrentPage = useCallback(() => {
    // Safety: don't attempt to draw if we are in the middle of a "snap-to-end" calculation
    if (subPageIndex === -1) return;

    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
        mainCanvas.getContext('2d', { alpha: false })?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        renderPageToCache(activeFileIndex, subPageIndex, true);
    }
  }, [sheetId, activeFileIndex, subPageIndex, renderPageToCache]);

  useLayoutEffect(() => {
    if (sheet && workerReady && numSubPages > 0 && subPageIndex !== -1) {
        drawCurrentPage();
    }
  }, [sheet, workerReady, drawCurrentPage, numSubPages, subPageIndex]);

  // 7. PREFETCHING
  useEffect(() => {
    if (!sheet || numSubPages <= 0 || subPageIndex === -1) return;

    // Forward prefetch
    if (subPageIndex < numSubPages - 1) renderPageToCache(activeFileIndex, subPageIndex + 1);
    else if (activeFileIndex < sheet.pages.length - 1) renderPageToCache(activeFileIndex + 1, 0);

    // Backward prefetch
    if (subPageIndex > 0) renderPageToCache(activeFileIndex, subPageIndex - 1);
  }, [sheet, activeFileIndex, subPageIndex, numSubPages, renderPageToCache]);

  const handlePageNext = () => {
    if (subPageIndex < numSubPages - 1) {
        const next = subPageIndex + 1;
        setSubPageIndex(next);
        currentRequestRef.current.pageIndex = next;
    } else {
        if (sheet && activeFileIndex < sheet.pages.length - 1) {
            const nextFile = activeFileIndex + 1;
            setActiveFileIndex(nextFile);
            setSubPageIndex(0);
            setNumSubPages(0);
            currentRequestRef.current.fileIndex = nextFile;
            currentRequestRef.current.pageIndex = 0;
        } else if (hasNext) {
            onNext();
        }
    }
  };

  const handlePagePrev = () => {
    if (subPageIndex > 0) {
        const prev = subPageIndex - 1;
        setSubPageIndex(prev);
        currentRequestRef.current.pageIndex = prev;
    } else {
        if (activeFileIndex > 0) {
            const prevFile = activeFileIndex - 1;
            setActiveFileIndex(prevFile);
            setNumSubPages(0);
            setSubPageIndex(-1); // Triggers snap to last in metadata effect
            currentRequestRef.current.fileIndex = prevFile;
            currentRequestRef.current.pageIndex = 'last';
        } else if (hasPrev) {
            onPrev();
        }
    }
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden select-none">
      {/* Top HUD */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/95 to-transparent transition-opacity duration-200 ${isDrawingMode || showPlaylist ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
