        const doc = await pdfjs.getDocument({
            data: new Uint8Array(arrayBuffer),
            cMapUrl: 'https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/cmaps/',
            cMapPacked: true,
        }).promise;

        // Final guard before caching
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  // 4. METADATA & BOUNDARY RESOLUTION
  useEffect(() => {
    if (!sheet || !workerReady) return;

    const currentFile = activeFileIndex;
    const target = sheet.pages[currentFile];
    if (!target) return;

    if (target.fileType === 'application/pdf') {
        getPdfDoc(currentFile).then(doc => {
            // CRITICAL GUARD: Ensure we haven't moved to another piece or file while PDF was loading
            if (!doc || sheetId !== currentViewRef.current.sheetId || currentFile !== currentViewRef.current.fileIndex) return;

            const total = doc.numPages;
            setNumSubPages(total);
            setFileType('application/pdf');

            // Handle "Last Page" snapping (used when navigating backward into a piece)
            if (subPageIndex === -1) {
              const lastIdx = total - 1;
              currentViewRef.current.pageIndex = lastIdx;
              setSubPageIndex(lastIdx);
            }
        });
    } else {
        setFileType('image');
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, sheetId, activeFileIndex, workerReady, getPdfDoc, subPageIndex]);

  // 5. ASYNC RENDERER
  const renderPageToCache = useCallback(async (fIdx: number, pIdx: number, isHighPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;
    if (canvasCache.current.has(key)) {
        if (isHighPriority) setLoading(false);
        return;
    }

    try {
        const doc = await getPdfDoc(fIdx);
        if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) {
            if (isHighPriority) setLoading(false);
            return;
        }

        if (pIdx < 0 || pIdx >= doc.numPages) {
            if (isHighPriority) setLoading(false);
            return;
        }

        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const { clientWidth, clientHeight } = container;
        const viewport = page.getViewport({ 
            scale: Math.min(clientWidth / page.getViewport({ scale: 1 }).width, clientHeight / page.getViewport({ scale: 1 }).height) * 2.0 
        });

        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d', { alpha: false })!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        // Final guard: Ensure we are still looking at exactly this file and page
        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            renderTasks.current.delete(key);

            if (isHighPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d', { alpha: false })?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isHighPriority) setLoading(false);
    }
  }, [sheetId, activeFileIndex, subPageIndex, getPdfDoc]);

  // 6. VIEWPORT UPDATER
  const drawCurrentPage = useCallback(() => {
    // Wait for snapping logic to finish if subPageIndex is -1
    if (subPageIndex === -1) return;

    const key = `${sheetId}-${activeFileIndex}-${subPageIndex}`;
    const cachedCanvas = canvasCache.current.get(key);
    const mainCanvas = pdfCanvasRef.current;

    if (cachedCanvas && mainCanvas) {
        mainCanvas.width = cachedCanvas.width;
        mainCanvas.height = cachedCanvas.height;
        setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
        mainCanvas.getContext('2d', { alpha: false })?.drawImage(cachedCanvas, 0, 0);
        setLoading(false);
    } else {
        renderPageToCache(activeFileIndex, subPageIndex, true);
    }
  }, [sheetId, activeFileIndex, subPageIndex, renderPageToCache]);

  useLayoutEffect(() => {
    if (sheet && workerReady && numSubPages > 0 && subPageIndex !== -1) {
        drawCurrentPage();
    }
  }, [sheet, workerReady, drawCurrentPage, numSubPages, subPageIndex]);

  // 7. PREFETCHING
  useEffect(() => {
    if (!sheet || numSubPages <= 0 || subPageIndex === -1) return;

    // Prefetch next and previous
    if (subPageIndex < numSubPages - 1) renderPageToCache(activeFileIndex, subPageIndex + 1);
    else if (activeFileIndex < sheet.pages.length - 1) renderPageToCache(activeFileIndex + 1, 0);

    if (subPageIndex > 0) renderPageToCache(activeFileIndex, subPageIndex - 1);
  }, [sheet, activeFileIndex, subPageIndex, numSubPages, renderPageToCache]);

  const handlePageNext = () => {
    if (subPageIndex < numSubPages - 1) {
        const next = subPageIndex + 1;
        currentViewRef.current.pageIndex = next;
        setSubPageIndex(next);
    } else {
        if (sheet && activeFileIndex < sheet.pages.length - 1) {
            const nextFile = activeFileIndex + 1;
            currentViewRef.current.fileIndex = nextFile;
            currentViewRef.current.pageIndex = 0;
            setActiveFileIndex(nextFile);
            setSubPageIndex(0);
            setNumSubPages(0);
        } else if (hasNext) {
            onNext();
        }
    }
  };

  const handlePagePrev = () => {
    if (subPageIndex > 0) {
        const prev = subPageIndex - 1;
        currentViewRef.current.pageIndex = prev;
        setSubPageIndex(prev);
    } else {
        if (activeFileIndex > 0) {
            const prevFile = activeFileIndex - 1;
            currentViewRef.current.fileIndex = prevFile;
            currentViewRef.current.pageIndex = -1; // Snap to last
            setActiveFileIndex(prevFile);
            setNumSubPages(0);
            setSubPageIndex(-1);
        } else if (hasPrev) {
            onPrev();
        }
    }
  };

  const isStrokeOnCurrentPage = (stroke: Stroke) => {
    let sFile = stroke.fileIndex ?? 0;
    return sFile === activeFileIndex && stroke.pageIndex === subPageIndex;
  };

  const getSvgPath = (points: Point[]) => points.length === 0 ? '' : points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col h-screen w-screen overflow-hidden select-none">
      {/* Top HUD */}
      <div className={`absolute top-0 left-0 right-0 z-30 flex justify-between items-center p-4 bg-gradient-to-b from-black/95 to-transparent transition-opacity duration-200 ${isDrawingMode || showPlaylist ? 'opacity-100' : 'opacity-0 hover:opacity-100'}`}>
        <div className="flex items-center gap-4">
            <button onClick={onClose} className="p-2.5 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur text-white shadow-xl"><X size={20} /></button>
            <div className="flex flex-col">
                <div className="flex items-center gap-2">
                    <h2 className="text-white font-bold tracking-tight truncate max-w-[150px] sm:max-w-xs">{title}</h2>
                    <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded uppercase border border-blue-400/20">
                        {sheet ? `${activeFileIndex + 1}/${sheet.pages.length}` : '-/-'}
                    </span>
                </div>
                <div className="text-[10px] text-slate-400 font-mono tracking-wider">
                    {(numSubPages > 0 && subPageIndex !== -1) ? `PAGE ${subPageIndex + 1} OF ${numSubPages}` : 'SYNCHRONIZING...'}
                </div>
            </div>
        </div>

        <div className="flex items-center gap-2">
            {queue && queue.length > 1 && (
                <button onClick={() => setShowPlaylist(!showPlaylist)} className={`p-2.5 rounded-full transition-all ${showPlaylist ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                    <List size={20} />
                </button>
            )}
            <button onClick={() => setIsDrawingMode(!isDrawingMode)} className={`p-2.5 rounded-full transition-all ${isDrawingMode ? 'bg-blue-600 text-white scale-110 shadow-blue-500/40' : 'bg-slate-800 text-slate-400 shadow-xl'}`}>
                <PenTool size={20} />
            </button>
        </div>
      </div>

      {/* Setlist Drawer */}
      {showPlaylist && queue && (
          <div className="absolute top-20 right-4 z-[100] w-72 max-h-[70vh] bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 fade-in duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Queue</h3>
                  <button onClick={() => setShowPlaylist(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2">
                  {queue.map((item, idx) => (
                      <button 
                        key={item.id + idx} 
                        onClick={() => { onJumpTo?.(idx); setShowPlaylist(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                          {idx === currentQueueIndex && <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />}
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Content Area */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {(loading || subPageIndex === -1) && (
            <div className="absolute z-50 inset-0 flex items-center justify-center pointer-events-none bg-zinc-950">
                 <Loader2 className="animate-spin text-blue-500" size={48} />
            </div>
        )}

        <div ref={containerRef} className="relative w-full h-full flex items-center justify-center touch-none">
            <canvas 
                ref={pdfCanvasRef} 
                className="shadow-2xl pointer-events-none transition-opacity duration-200"
                style={{ 
                    maxWidth: '100%', 
                    maxHeight: '100%', 
                    display: fileType === 'application/pdf' ? 'block' : 'none',
                    opacity: (loading || subPageIndex === -1) ? 0 : 1
                }}
            />

            {fileType === 'image' && sheet?.pages[activeFileIndex] && (
                <img 
                    src={URL.createObjectURL(sheet.pages[activeFileIndex].blob)} 
                    className="max-w-full max-h-full object-contain pointer-events-none" 
                    alt="Page" 
                    onLoad={() => setLoading(false)}
                />
            )}

            {!loading && subPageIndex !== -1 && (
                <svg 
                    className="absolute inset-0 w-full h-full pointer-events-none z-10" 
                    viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                    preserveAspectRatio="none"
                >
                    {allStrokes.filter(isStrokeOnCurrentPage).map((stroke, i) => (
                        <path 
                            key={i}
                            d={getSvgPath(stroke.points)}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))}
                </svg>
            )}
        </div>

        {/* Navigation Touch Zones */}
        {!isDrawingMode && !showPlaylist && (
          <>
            <div className="absolute inset-y-0 left-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center pl-4" onClick={handlePagePrev}>
                <ChevronLeft className="text-white/0 group-active:text-white/40" size={48} />
            </div>
            <div className="absolute inset-y-0 right-0 w-[20%] z-20 cursor-pointer active:bg-white/5 transition-colors group flex items-center justify-end pr-4" onClick={handlePageNext}>
                <ChevronRight className="text-white/0 group-active:text-white/40" size={48} />
            </div>
          </>
        )}
      </div>

      {/* Info Badge */}
      {!isDrawingMode && !loading && subPageIndex !== -1 && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-2xl">
              FILE {activeFileIndex + 1} • PAGE {subPageIndex + 1}
          </div>
      )}

      {/* Tools */}
      {isDrawingMode && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-4 p-2 bg-slate-900/90 backdrop-blur-xl rounded-2xl border border-white/10 shadow-2xl z-50 animate-in slide-in-from-bottom-4 duration-300">
               <button onClick={() => setTool('pen')} className={`p-3 rounded-xl transition-all ${tool === 'pen' ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' : 'text-slate-400 hover:text-slate-200'}`}><PenTool size={20}/></button>
               <button onClick={() => setTool('eraser')} className={`p-3 rounded-xl transition-all ${tool === 'eraser' ? 'bg-red-600 text-white shadow-lg shadow-red-500/30' : 'text-slate-400 hover:text-slate-200'}`}><Eraser size={20}/></button>
               <div className="w-px h-8 bg-white/10 mx-1" />
               <button onClick={() => setIsDrawingMode(false)} className="p-3 text-slate-400 hover:text-white font-bold px-4 tracking-tight uppercase text-xs">Done</button>
          </div>
      )}
    </div>
  );
};

export default Viewer;

import { DB_NAME, DB_VERSION, STORES, INITIAL_TAGS } from '../constants';
import { Sheet, Setlist, AnnotationLayer, SheetPage, TagDef } from '../types';

class StorageService {
  private db: IDBDatabase | null = null;

  async init(): Promise<void> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onerror = () => reject(request.error);
      request.onsuccess = async () => {
        this.db = request.result;
        await this.checkAndSeed();
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;

        if (!db.objectStoreNames.contains(STORES.SHEETS)) {
          db.createObjectStore(STORES.SHEETS, { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains(STORES.SETLISTS)) {
          db.createObjectStore(STORES.SETLISTS, { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains(STORES.ANNOTATIONS)) {
          db.createObjectStore(STORES.ANNOTATIONS, { keyPath: 'sheetId' });
        }
        if (!db.objectStoreNames.contains(STORES.TAGS)) {
          const tagStore = db.createObjectStore(STORES.TAGS, { keyPath: 'label' });
          INITIAL_TAGS.forEach(tag => tagStore.add(tag));
        }
      };
    });
  }

  private async checkAndSeed(): Promise<void> {
    const sheets = await this.getAllSheets();
    if (sheets.length === 0) {
      console.log("Seeding demo data...");
      await this.seedDemoData();
    }
  }

  private async seedDemoData(): Promise<void> {
    // Generate a dummy transparent 1x1 PNG blob to act as sheet music
    const dummyPngBase64 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8/5+hHgAHggJ/PchI7wAAAABJRU5ErkJggg==';
    const byteCharacters = atob(dummyPngBase64);
    const byteNumbers = new Array(byteCharacters.length);
    for (let i = 0; i < byteCharacters.length; i++) {
      byteNumbers[i] = byteCharacters.charCodeAt(i);
    }
    const byteArray = new Uint8Array(byteNumbers);
    const dummyBlob = new Blob([byteArray], { type: 'image/png' });

    const demoSheets: Sheet[] = [
      {
        id: 'demo-1',
        name: 'Piano Sonata No. 14',
        tags: ['Classical', 'Favorites'],
        dateAdded: Date.now() - 3000,
        pages: [{ blob: dummyBlob, fileType: 'image/png' }, { blob: dummyBlob, fileType: 'image/png' }]
      },
      {
        id: 'demo-2',
        name: 'Autumn Leaves - Lead Sheet',
        tags: ['Jazz'],
        dateAdded: Date.now() - 2000,
        pages: [{ blob: dummyBlob, fileType: 'image/png' }]
      },
      {
        id: 'demo-3',
        name: 'The Entertainer',
        tags: ['Pop', 'Jazz'],
        dateAdded: Date.now() - 1000,
        pages: [{ blob: dummyBlob, fileType: 'image/png' }]
      }
    ];

    const demoSetlist: Setlist = {
      id: 'demo-setlist-1',
      name: 'Demo Notes',
      sheetIds: ['demo-1', 'demo-2', 'demo-3'],
      dateCreated: Date.now()
    };

    for (const sheet of demoSheets) {
      await this.addSheet(sheet);
    }
    await this.saveSetlist(demoSetlist);
  }

  private async transaction<T>(storeName: string, mode: IDBTransactionMode, callback: (store: IDBObjectStore) => IDBRequest | void): Promise<T> {
    if (!this.db) await this.init();
    return new Promise((resolve, reject) => {
      const tx = this.db!.transaction(storeName, mode);
      const store = tx.objectStore(storeName);
      let request: IDBRequest | void;

      try {
        request = callback(store);
      } catch (e) {
        reject(e);
        return;
      }

      tx.oncomplete = () => resolve(request ? request.result : undefined);
      tx.onerror = () => reject(tx.error);
    });
  }

  // --- Sheets ---

  async addSheet(sheet: Sheet): Promise<void> {
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.put(sheet));
  }

  async updateSheetMetadata(sheet: Sheet): Promise<void> {
    const existing = await this.transaction<Sheet>(STORES.SHEETS, 'readonly', (store) => store.get(sheet.id));
    if (!existing) throw new Error('Sheet not found');

    const record: Sheet = { 
      ...existing, 
      name: sheet.name, 
      tags: sheet.tags,
      tagIcons: sheet.tagIcons
    };
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.put(record));
  }

  async getAllSheets(): Promise<Sheet[]> {
    return this.transaction(STORES.SHEETS, 'readonly', (store) => store.getAll());
  }

  async getSheet(id: string): Promise<Sheet | undefined> {
    return this.transaction<Sheet>(STORES.SHEETS, 'readonly', (store) => store.get(id));
  }

  async deleteSheet(id: string): Promise<void> {
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.delete(id));
    await this.deleteAnnotation(id);
    const setlists = await this.getAllSetlists();
    for (const list of setlists) {
        if (list.sheetIds.includes(id)) {
            list.sheetIds = list.sheetIds.filter(sheetId => sheetId !== id);
            await this.saveSetlist(list);
        }
    }
  }

  // --- Setlists ---

  async saveSetlist(setlist: Setlist): Promise<void> {
    await this.transaction(STORES.SETLISTS, 'readwrite', (store) => store.put(setlist));
  }

  async getAllSetlists(): Promise<Setlist[]> {
    return this.transaction(STORES.SETLISTS, 'readonly', (store) => store.getAll());
  }

  async deleteSetlist(id: string): Promise<void> {
    await this.transaction(STORES.SETLISTS, 'readwrite', (store) => store.delete(id));
  }

  // --- Annotations ---

  async saveAnnotation(sheetId: string, strokes: any[]): Promise<void> {
    await this.transaction(STORES.ANNOTATIONS, 'readwrite', (store) => store.put({ sheetId, strokes }));
  }

  async getAnnotation(sheetId: string): Promise<AnnotationLayer | undefined> {
    return this.transaction(STORES.ANNOTATIONS, 'readonly', (store) => store.get(sheetId));
  }

  async deleteAnnotation(sheetId: string): Promise<void> {
    await this.transaction(STORES.ANNOTATIONS, 'readwrite', (store) => store.delete(sheetId));
  }

  // --- Tags ---

  async getAllTags(): Promise<TagDef[]> {
    return this.transaction(STORES.TAGS, 'readonly', (store) => store.getAll());
  }

  async saveTag(tag: TagDef): Promise<void> {
    await this.transaction(STORES.TAGS, 'readwrite', (store) => store.put(tag));
  }

  async deleteTag(label: string): Promise<void> {
    await this.transaction(STORES.TAGS, 'readwrite', (store) => store.delete(label));
  }
}

export const storage = new StorageService();

import { DB_NAME, DB_VERSION, STORES, INITIAL_TAGS } from '../constants';
import { Sheet, Setlist, AnnotationLayer, SheetPage, TagDef } from '../types';

class StorageService {
  private db: IDBDatabase | null = null;

  async init(): Promise<void> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onerror = () => reject(request.error);
      request.onsuccess = async () => {
        this.db = request.result;
        await this.checkAndSeed();
        resolve();
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;

        if (!db.objectStoreNames.contains(STORES.SHEETS)) {
          db.createObjectStore(STORES.SHEETS, { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains(STORES.SETLISTS)) {
          db.createObjectStore(STORES.SETLISTS, { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains(STORES.ANNOTATIONS)) {
          db.createObjectStore(STORES.ANNOTATIONS, { keyPath: 'sheetId' });
        }
        if (!db.objectStoreNames.contains(STORES.TAGS)) {
          const tagStore = db.createObjectStore(STORES.TAGS, { keyPath: 'label' });
          INITIAL_TAGS.forEach(tag => tagStore.add(tag));
        }
      };
    });
  }

  private async checkAndSeed(): Promise<void> {
    const sheets = await this.getAllSheets();
    if (sheets.length === 0) {
      console.log("Seeding real demo data from 'demo notes'...");
      await this.seedDemoData();
    }
  }

  private async seedDemoData(): Promise<void> {
    const fetchBlob = async (url: string) => {
      try {
        const res = await fetch(url);
        if (!res.ok) throw new Error(`Failed to fetch ${url}`);
        return await res.blob();
      } catch (e) {
        console.warn(`Could not fetch ${url}, skipping or using fallback.`, e);
        return null;
      }
    };

    // Attempting to fetch the files from the 'demo notes' directory provided by user
    // We try to find the PDF files and the image files in the subfolder.
    const sonataBlob = await fetchBlob('demo notes/Sonata.pdf');
    const autumnBlob = await fetchBlob('demo notes/Autumn.pdf');
    const ent1Blob = await fetchBlob('demo notes/Entertainer/page1.png');
    const ent2Blob = await fetchBlob('demo notes/Entertainer/page2.png');

    const demoSheets: Sheet[] = [];

    if (sonataBlob) {
      demoSheets.push({
        id: 'demo-sonata',
        name: 'Piano Sonata No. 14 (Moonlight)',
        tags: ['Classical', 'Favorites'],
        dateAdded: Date.now() - 3000,
        pages: [{ blob: sonataBlob, fileType: 'application/pdf' }]
      });
    }

    if (autumnBlob) {
      demoSheets.push({
        id: 'demo-autumn',
        name: 'Autumn Leaves',
        tags: ['Jazz'],
        dateAdded: Date.now() - 2000,
        pages: [{ blob: autumnBlob, fileType: 'application/pdf' }]
      });
    }

    if (ent1Blob && ent2Blob) {
      demoSheets.push({
        id: 'demo-entertainer',
        name: 'The Entertainer (Folder Import)',
        tags: ['Jazz', 'Pop'],
        dateAdded: Date.now() - 1000,
        pages: [
          { blob: ent1Blob, fileType: 'image/png' },
          { blob: ent2Blob, fileType: 'image/png' }
        ]
      });
    }

    // Fallback dummy data if files are not found (to ensure library isn't empty on test)
    if (demoSheets.length === 0) {
      const dummyPngBase64 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8/5+hHgAHggJ/PchI7wAAAABJRU5ErkJggg==';
      const byteCharacters = atob(dummyPngBase64);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) {
        byteNumbers[i] = byteCharacters.charCodeAt(i);
      }
      const byteArray = new Uint8Array(byteNumbers);
      const dummyBlob = new Blob([byteArray], { type: 'image/png' });

      demoSheets.push({
        id: 'demo-1',
        name: 'Piano Sonata No. 14 (Fallback)',
        tags: ['Classical', 'Favorites'],
        dateAdded: Date.now() - 3000,
        pages: [{ blob: dummyBlob, fileType: 'image/png' }]
      });
    }

    const demoSetlist: Setlist = {
      id: 'demo-setlist-1',
      name: 'Demo Notes',
      sheetIds: demoSheets.map(s => s.id),
      dateCreated: Date.now()
    };

    for (const sheet of demoSheets) {
      await this.addSheet(sheet);
    }
    await this.saveSetlist(demoSetlist);
  }

  private async transaction<T>(storeName: string, mode: IDBTransactionMode, callback: (store: IDBObjectStore) => IDBRequest | void): Promise<T> {
    if (!this.db) await this.init();
    return new Promise((resolve, reject) => {
      const tx = this.db!.transaction(storeName, mode);
      const store = tx.objectStore(storeName);
      let request: IDBRequest | void;

      try {
        request = callback(store);
      } catch (e) {
        reject(e);
        return;
      }

      tx.oncomplete = () => resolve(request ? request.result : undefined);
      tx.onerror = () => reject(tx.error);
    });
  }

  // --- Sheets ---

  async addSheet(sheet: Sheet): Promise<void> {
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.put(sheet));
  }

  async updateSheetMetadata(sheet: Sheet): Promise<void> {
    const existing = await this.transaction<Sheet>(STORES.SHEETS, 'readonly', (store) => store.get(sheet.id));
    if (!existing) throw new Error('Sheet not found');

    const record: Sheet = { 
      ...existing, 
      name: sheet.name, 
      tags: sheet.tags,
      tagIcons: sheet.tagIcons
    };
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.put(record));
  }

  async getAllSheets(): Promise<Sheet[]> {
    return this.transaction(STORES.SHEETS, 'readonly', (store) => store.getAll());
  }

  async getSheet(id: string): Promise<Sheet | undefined> {
    return this.transaction<Sheet>(STORES.SHEETS, 'readonly', (store) => store.get(id));
  }

  async deleteSheet(id: string): Promise<void> {
    await this.transaction(STORES.SHEETS, 'readwrite', (store) => store.delete(id));
    await this.deleteAnnotation(id);
    const setlists = await this.getAllSetlists();
    for (const list of setlists) {
        if (list.sheetIds.includes(id)) {
            list.sheetIds = list.sheetIds.filter(sheetId => sheetId !== id);
            await this.saveSetlist(list);
        }
    }
  }

  // --- Setlists ---

  async saveSetlist(setlist: Setlist): Promise<void> {
    await this.transaction(STORES.SETLISTS, 'readwrite', (store) => store.put(setlist));
  }

  async getAllSetlists(): Promise<Setlist[]> {
    return this.transaction(STORES.SETLISTS, 'readonly', (store) => store.getAll());
  }

  async deleteSetlist(id: string): Promise<void> {
    await this.transaction(STORES.SETLISTS, 'readwrite', (store) => store.delete(id));
  }

  // --- Annotations ---

  async saveAnnotation(sheetId: string, strokes: any[]): Promise<void> {
    await this.transaction(STORES.ANNOTATIONS, 'readwrite', (store) => store.put({ sheetId, strokes }));
  }

  async getAnnotation(sheetId: string): Promise<AnnotationLayer | undefined> {
    return this.transaction(STORES.ANNOTATIONS, 'readonly', (store) => store.get(sheetId));
  }

  async deleteAnnotation(sheetId: string): Promise<void> {
    await this.transaction(STORES.ANNOTATIONS, 'readwrite', (store) => store.delete(sheetId));
  }

  // --- Tags ---

  async getAllTags(): Promise<TagDef[]> {
    return this.transaction(STORES.TAGS, 'readonly', (store) => store.getAll());
  }

  async saveTag(tag: TagDef): Promise<void> {
    await this.transaction(STORES.TAGS, 'readwrite', (store) => store.put(tag));
  }

  async deleteTag(label: string): Promise<void> {
    await this.transaction(STORES.TAGS, 'readwrite', (store) => store.delete(label));
  }
}

export const storage = new StorageService();

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';

// Use PDF.js from the ESM provider as configured in service worker
import * as pdfjs from 'pdfjs-dist';

// Set worker source to a matching version
pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [loading, setLoading] = useState(true);
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<'pen' | 'eraser'>('pen');
  const [currentColor, setCurrentColor] = useState(COLORS[0]);
  const [currentWidth, setCurrentWidth] = useState(3);
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);

  // Pagination within the sheet
  const [currentPageIndex, setCurrentPageIndex] = useState(0); 
  const [pdfPageNumber, setPdfPageNumber] = useState(1);
  const [numPdfPages, setNumPdfPages] = useState(1);

  const [strokes, setStrokes] = useState<Stroke[]>([]);
  const [isDrawing, setIsDrawing] = useState(false);
  const currentStrokeRef = useRef<Point[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfDocRef = useRef<pdfjs.PDFDocumentProxy | null>(null);

  // Reset and Load sheet data whenever sheetId changes
  useEffect(() => {
    const loadSheet = async () => {
      setLoading(true);
      const data = await storage.getSheet(sheetId);
      if (data) {
        setSheet(data);
        const annotation = await storage.getAnnotation(sheetId);
        setStrokes(annotation?.strokes || []);

        if (initialDirection === 'forward') {
          setCurrentPageIndex(0);
          setPdfPageNumber(1);
        } else {
          setCurrentPageIndex(data.pages.length - 1);
          // pdfPageNumber will be set once the PDF loads in the next effect
        }
      }
      setLoading(false);
    };
    loadSheet();
  }, [sheetId, initialDirection]);

  // Load PDF content for the current page if it's a PDF file
  useEffect(() => {
    if (!sheet) return;
    const currentPage = sheet.pages[currentPageIndex];
    if (currentPage?.fileType === 'application/pdf') {
      const loadPdf = async () => {
        try {
          const arrayBuffer = await currentPage.blob.arrayBuffer();
          const loadingTask = pdfjs.getDocument({ data: arrayBuffer });
          const pdf = await loadingTask.promise;
          pdfDocRef.current = pdf;
          setNumPdfPages(pdf.numPages);

          if (initialDirection === 'backward' && currentPageIndex === sheet.pages.length - 1) {
            setPdfPageNumber(pdf.numPages);
          } else {
            setPdfPageNumber(1);
          }
        } catch (err) {
          console.error("PDF loading error:", err);
        }
      };
      loadPdf();
    } else {
      pdfDocRef.current = null;
      setNumPdfPages(1);
      setPdfPageNumber(1);
    }
  }, [sheet, currentPageIndex, initialDirection]);

  // Handle keyboard navigation (Bluetooth page turners)
  const handleNavigateNext = useCallback(() => {
    if (!sheet) return;
    if (pdfDocRef.current && pdfPageNumber < numPdfPages) {
      setPdfPageNumber(prev => prev + 1);
      return;
    }
    if (currentPageIndex < sheet.pages.length - 1) {
      setCurrentPageIndex(prev => prev + 1);
      setPdfPageNumber(1);
      return;
    }
    if (hasNext) onNext();
  }, [sheet, pdfPageNumber, numPdfPages, currentPageIndex, hasNext, onNext]);

  const handleNavigatePrev = useCallback(() => {
    if (!sheet) return;
    if (pdfDocRef.current && pdfPageNumber > 1) {
      setPdfPageNumber(prev => prev - 1);
      return;
    }
    if (currentPageIndex > 0) {
      setCurrentPageIndex(prev => prev - 1);
      return;
    }
    if (hasPrev) onPrev();
  }, [sheet, pdfPageNumber, currentPageIndex, hasPrev, onPrev]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) {
        handleNavigateNext();
      } else if (PAGE_TURN_KEYS.PREV.includes(e.key)) {
        handleNavigatePrev();
      } else if (e.key === 'Escape') {
        if (isAnnotating) setIsAnnotating(false);
        else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNavigateNext, handleNavigatePrev, isAnnotating, onClose]);

  // Render the current page and annotations to the canvas
  useLayoutEffect(() => {
    let isMounted = true;
    const render = async () => {
      if (!sheet || !containerRef.current || !canvasRef.current || !isMounted) return;

      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      const currentPage = sheet.pages[currentPageIndex];
      const width = containerRef.current.clientWidth;
      const height = containerRef.current.clientHeight;

      canvasRef.current.width = width;
      canvasRef.current.height = height;
      ctx.clearRect(0, 0, width, height);

      if (currentPage.fileType === 'application/pdf' && pdfDocRef.current) {
        try {
          const page = await pdfDocRef.current.getPage(pdfPageNumber);
          const viewport = page.getViewport({ scale: 1 });
          const scale = Math.min(width / viewport.width, height / viewport.height);
          const scaledViewport = page.getViewport({ scale });

          const offsetX = (width - scaledViewport.width) / 2;
          const offsetY = (height - scaledViewport.height) / 2;

          await page.render({
            canvasContext: ctx,
            viewport: scaledViewport,
            transform: [1, 0, 0, 1, offsetX, offsetY]
          }).promise;
        } catch (err) {
          console.error("PDF render error:", err);
        }
      } else {
        const img = new Image();
        const url = URL.createObjectURL(currentPage.blob);
        img.src = url;
        await new Promise(r => img.onload = r);

        if (!isMounted) return;
        const scale = Math.min(width / img.width, height / img.height);
        const dw = img.width * scale;
        const dh = img.height * scale;
        const dx = (width - dw) / 2;
        const dy = (height - dh) / 2;
        ctx.drawImage(img, dx, dy, dw, dh);
        URL.revokeObjectURL(url);
      }

      // Draw annotations on top
      const filtered = strokes.filter(s => s.fileIndex === currentPageIndex && s.pageIndex === (pdfPageNumber - 1));
      filtered.forEach(stroke => {
        if (stroke.points.length < 2) return;
        ctx.beginPath();
        ctx.strokeStyle = stroke.color;
        ctx.lineWidth = stroke.width;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.moveTo(stroke.points[0].x * width, stroke.points[0].y * height);
        for (let i = 1; i < stroke.points.length; i++) {
          ctx.lineTo(stroke.points[i].x * width, stroke.points[i].y * height);
        }
        ctx.stroke();
      });
    };
    render();
    return () => { isMounted = false; };
  }, [sheet, currentPageIndex, pdfPageNumber, strokes]);

  const startDrawing = (e: React.PointerEvent) => {
    if (!isAnnotating || !canvasRef.current) return;
    setIsDrawing(true);
    const rect = canvasRef.current.getBoundingClientRect();
    currentStrokeRef.current = [{ 
      x: (e.clientX - rect.left) / rect.width, 
      y: (e.clientY - rect.top) / rect.height 
    }];
  };

  const draw = (e: React.PointerEvent) => {
    if (!isDrawing || !isAnnotating || !canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const p = { 
      x: (e.clientX - rect.left) / rect.width, 
      y: (e.clientY - rect.top) / rect.height 
    };
    currentStrokeRef.current.push(p);

    const ctx = canvasRef.current.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.strokeStyle = currentTool === 'eraser' ? '#0f172a' : currentColor;
      ctx.lineWidth = currentWidth;
      ctx.lineCap = 'round';
      const p1 = currentStrokeRef.current[currentStrokeRef.current.length - 2];
      ctx.moveTo(p1.x * rect.width, p1.y * rect.height);
      ctx.lineTo(p.x * rect.width, p.y * rect.height);
      ctx.stroke();
    }
  };

  const endDrawing = async () => {
    if (!isDrawing) return;
    setIsDrawing(false);

    if (currentTool === 'eraser') {
      const newStrokes = strokes.filter(s => {
        if (s.fileIndex !== currentPageIndex || s.pageIndex !== (pdfPageNumber - 1)) return true;
        return !s.points.some(p => currentStrokeRef.current.some(cp => Math.hypot(p.x - cp.x, p.y - cp.y) < 0.02));
      });
      setStrokes(newStrokes);
      await storage.saveAnnotation(sheetId, newStrokes);
    } else {
      const newStrokes = [...strokes, {
        points: currentStrokeRef.current,
        color: currentColor,
        width: currentWidth,
        pageIndex: pdfPageNumber - 1,
        fileIndex: currentPageIndex
      }];
      setStrokes(newStrokes);
      await storage.saveAnnotation(sheetId, newStrokes);
    }
  };

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating) return;
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handleNavigatePrev();
    else if (x > 0.8) handleNavigateNext();
    else setShowControls(!showControls);
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none">
      {showControls && (
        <div className="absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-colors"><X size={24} /></button>
             <div className="text-white">
                <h2 className="font-bold text-lg truncate max-w-[200px] md:max-w-md">{title}</h2>
                <p className="text-xs text-slate-400">
                    {sheet ? `File ${currentPageIndex + 1}/${sheet.pages.length}` : ''}
                    {pdfDocRef.current ? ` • Page ${pdfPageNumber}/${numPdfPages}` : ''}
                </p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             <div className="hidden md:flex items-center bg-black/40 backdrop-blur-md rounded-full p-1 border border-white/10 mr-2">
                 {COLORS.map(color => (
                    <button 
                        key={color} 
                        onClick={() => { setCurrentColor(color); setCurrentTool('pen'); setIsAnnotating(true); }}
                        className={`w-7 h-7 rounded-full border-2 transition-all ${currentColor === color && currentTool === 'pen' ? 'border-white scale-110 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}`}
                        style={{ backgroundColor: color }}
                    />
                 ))}
             </div>
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating) setCurrentTool('pen'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'pen' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white hover:bg-white/20'}`}><PenTool size={22} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white hover:bg-white/20'}`}><Eraser size={22} /></button>
             <div className="relative">
                <button onClick={() => setShowQueue(!showQueue)} className="p-3 bg-white/10 text-white rounded-full hover:bg-white/20 backdrop-blur-md"><List size={22} /></button>
                {showQueue && (
                    <div className="absolute top-full right-0 mt-2 w-64 bg-slate-900 border border-slate-800 rounded-xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-top-2">
                        <div className="p-3 border-b border-slate-800 text-[10px] font-black text-slate-500 uppercase tracking-widest bg-slate-950">Setlist Queue</div>
                        <div className="max-h-64 overflow-y-auto no-scrollbar">
                            {queue.map((item, idx) => (
                                <button key={item.id} onClick={() => { onJumpTo(idx); setShowQueue(false); }} className={`w-full text-left p-4 text-sm hover:bg-slate-800 transition-colors ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 font-bold border-l-4 border-blue-500' : 'text-slate-300'}`}>{idx + 1}. {item.name}</button>
                            ))}
                        </div>
                    </div>
                )}
             </div>
          </div>
        </div>
      )}
      <div ref={containerRef} className="flex-1 relative flex items-center justify-center bg-slate-950" onClick={handleContainerClick}>
        {loading ? (
            <div className="flex flex-col items-center gap-4">
                <Loader2 className="animate-spin text-blue-500" size={48} />
                <p className="text-slate-400 font-medium animate-pulse">Loading piece...</p>
            </div>
        ) : (
            <canvas ref={canvasRef} onPointerDown={startDrawing} onPointerMove={draw} onPointerUp={endDrawing} onPointerLeave={endDrawing} className={`max-w-full max-h-full object-contain ${isAnnotating ? 'touch-none cursor-crosshair' : 'cursor-pointer shadow-2xl'}`} />
        )}
      </div>
      {showControls && (
        <div className="absolute bottom-10 left-0 right-0 px-8 flex justify-between pointer-events-none">
            <button onClick={(e) => { e.stopPropagation(); handleNavigatePrev(); }} className={`p-4 rounded-full bg-black/60 text-white backdrop-blur-md pointer-events-auto transition-all active:scale-90 ${!hasPrev && currentPageIndex === 0 && pdfPageNumber === 1 ? 'opacity-20' : 'hover:bg-blue-600 hover:shadow-xl'}`}><ChevronLeft size={32} /></button>
            <button onClick={(e) => { e.stopPropagation(); handleNavigateNext(); }} className={`p-4 rounded-full bg-black/60 text-white backdrop-blur-md pointer-events-auto transition-all active:scale-90 ${!hasNext && sheet && currentPageIndex === sheet.pages.length - 1 && pdfPageNumber === numPdfPages ? 'opacity-20' : 'hover:bg-blue-600 hover:shadow-xl'}`}><ChevronRight size={32} /></button>
        </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<'pen' | 'eraser'>('pen');
  const [currentColor, setCurrentColor] = useState(COLORS[0]);
  const [currentWidth, setCurrentWidth] = useState(3);
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // This ref is the source of truth for the current expected view state.
  // Any async task finishing MUST check against this to avoid leaking state from previous pieces.
  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // 1. ATOMIC STATE RESET
  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    // Clear rendering caches
    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    // Physically wipe the canvas to prevent ghosting
    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  // 2. DATA LOADING
  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? loaded.pages.length - 1 : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection]);

  // 3. PDF CACHING & RENDERING
  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;
    if (canvasCache.current.has(key)) {
        if (isPriority) setLoading(false);
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  // 4. VIEWPORT LOGIC
  useEffect(() => {
    if (!sheet) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  const handleNextPage = () => {
    if (subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1); // Signal snap to last page
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating) return;
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <div className="flex items-center gap-2 text-[10px] text-slate-400 font-black uppercase tracking-widest">
                    <span>FILE {activeFileIndex + 1}/{sheet?.pages.length || 1}</span>
                    <span>•</span>
                    <span>PAGE {subPageIndex + 1}/{numSubPages || '?'}</span>
                </div>
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating) setCurrentTool('pen'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'pen' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={() => setShowQueue(!showQueue)} className="p-3 bg-white/10 text-white rounded-full"><List size={20} /></button>
        </div>
      </div>

      {/* Main Viewport */}
      <div ref={containerRef} className="flex-1 relative flex items-center justify-center bg-zinc-950" onClick={handleContainerClick}>
        {(loading || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className="max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300"
            style={{ opacity: loading || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet?.pages[activeFileIndex]?.fileType !== 'application/pdf' && (
            <img 
                src={URL.createObjectURL(sheet!.pages[activeFileIndex].blob)} 
                className="max-w-full max-h-full object-contain"
                alt="Sheet Page"
            />
        )}

        {/* Annotations Overlay */}
        {!loading && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => (
                        <path 
                            key={i}
                            d={stroke.points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))
                }
            </svg>
        )}
      </div>

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

