                        min="1" 
                        max={numSubPages}
                        value={jumpInputValue}
                        onChange={e => setJumpInputValue(e.target.value)}
                        placeholder="1-99"
                        className="flex-1 bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white font-bold text-xl outline-none focus:ring-2 focus:ring-blue-500"
                      />
                      <button type="submit" className="p-3 bg-blue-600 text-white rounded-xl hover:bg-blue-500 shadow-lg shadow-blue-900/20"><ArrowRight size={24}/></button>
                  </form>
                  <p className="mt-4 text-xs text-slate-500 font-medium">Enter a page between 1 and {numSubPages}</p>
