};

export default App;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<'pen' | 'eraser'>('pen');
  const [currentColor, setCurrentColor] = useState(COLORS[0]);
  const [currentWidth, setCurrentWidth] = useState(3);
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [isJumpingPage, setIsJumpingPage] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    // Check if cached
    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  const handleNextPage = () => {
    if (subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= numSubPages) {
        setSubPageIndex(val - 1);
        currentViewRef.current.pageIndex = val - 1;
        setIsJumpingPage(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (isJumpingPage) {
        jumpInputRef.current?.focus();
    }
  }, [isJumpingPage]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || isJumpingPage) return;
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={() => !loading && setIsJumpingPage(true)}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing piece...</span>
                    ) : (
                        <>
                            <span>FILE {activeFileIndex + 1}/{sheet?.pages?.length || 1}</span>
                            <span>•</span>
                            <span className="bg-white/5 px-1.5 py-0.5 rounded flex items-center gap-1">
                                PAGE {Math.max(0, subPageIndex) + 1}/{numSubPages || '?'} <ChevronDown size={10}/>
                            </span>
                        </>
                    )}
                </button>
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating) setCurrentTool('pen'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'pen' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={() => setShowQueue(!showQueue)} className="p-3 bg-white/10 text-white rounded-full"><List size={20} /></button>
        </div>
      </div>

      {/* Jump Page UI */}
      {isJumpingPage && (
          <div className="absolute inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm" onClick={() => setIsJumpingPage(false)}>
              <div className="bg-slate-900 border border-slate-700 p-8 rounded-3xl shadow-2xl w-full max-w-xs animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
                  <div className="flex items-center gap-3 mb-6">
                      <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white"><Hash size={20}/></div>
                      <h3 className="font-bold text-white">Jump to Page</h3>
                  </div>
                  <form onSubmit={handleJumpPage} className="flex gap-2">
                      <input 
                        ref={jumpInputRef}
                        type="number" 
                        min="1" 
                        max={numSubPages}
                        value={jumpInputValue}
                        onChange={e => setJumpInputValue(e.target.value)}
                        placeholder="1-99"
                        className="flex-1 bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white font-bold text-xl outline-none focus:ring-2 focus:ring-blue-500"
                      />
                      <button type="submit" className="p-3 bg-blue-600 text-white rounded-xl hover:bg-blue-500 shadow-lg shadow-blue-900/20"><ArrowRight size={24}/></button>
                  </form>
                  <p className="mt-4 text-xs text-slate-500 font-medium">Enter a page between 1 and {numSubPages}</p>
              </div>
          </div>
      )}

      {/* Main Viewport */}
      <div ref={containerRef} className="flex-1 relative flex items-center justify-center bg-zinc-950" onClick={handleContainerClick}>
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 ${isPdf ? 'block' : 'hidden'}`}
            style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet && currentFile && !isPdf && (
            <img 
                src={URL.createObjectURL(currentFile.blob)} 
                className="max-w-full max-h-full object-contain"
                alt="Sheet Page"
                onLoad={(e) => {
                    const img = e.target as HTMLImageElement;
                    setDimensions({ width: img.naturalWidth, height: img.naturalHeight });
                }}
            />
        )}

        {/* Annotations Overlay */}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => (
                        <path 
                            key={i}
                            d={stroke.points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))
                }
            </svg>
        )}
      </div>

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<'pen' | 'eraser'>('pen');
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  // If it's a PDF, "total pages" is the internal PDF page count.
  // If it's a folder of images, "total pages" is the number of files in the sheet.
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue) {
        setShowJumpDropdown(false);
        setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>

                {/* Jump Dropdown Menu */}
                {showJumpDropdown && (
                    <div 
                        className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="flex items-center gap-2 mb-3 text-slate-400">
                            <BookOpen size={14} />
                            <span className="text-[10px] font-black uppercase tracking-widest">Go to page</span>
                        </div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input 
                                ref={jumpInputRef}
                                type="number"
                                min="1"
                                max={totalDisplayPages}
                                value={jumpInputValue}
                                onChange={e => setJumpInputValue(e.target.value)}
                                placeholder={`1-${totalDisplayPages}`}
                                className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500"
                            />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors">
                                <ArrowRight size={20} />
                            </button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating) setCurrentTool('pen'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'pen' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      {/* Main Viewport */}
      <div ref={containerRef} className="flex-1 relative flex items-center justify-center bg-zinc-950" onClick={handleContainerClick}>
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 ${isPdf ? 'block' : 'hidden'}`}
            style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet && currentFile && !isPdf && (
            <img 
                src={URL.createObjectURL(currentFile.blob)} 
                className="max-w-full max-h-full object-contain shadow-2xl"
                alt="Sheet Page"
                onLoad={(e) => {
                    const img = e.target as HTMLImageElement;
                    setDimensions({ width: img.naturalWidth, height: img.naturalHeight });
                }}
            />
        )}

        {/* Annotations Overlay */}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => (
                        <path 
                            key={i}
                            d={stroke.points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))
                }
            </svg>
        )}
      </div>

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, ListMusic, Trash2, Play, X, Check, Pencil, GripVertical, Search, Import, AlertTriangle } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // DRAG STATE
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [hoverIndex, setHoverIndex] = useState<number | null>(null);
  const [dragOffset, setDragOffset] = useState(0);
  const startPointerY = useRef(0);
  const itemHeights = useRef<number[]>([]);
  const containerRect = useRef<DOMRect | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });
  const importInputRef = useRef<HTMLInputElement>(null);
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;
    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;
    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };
    await storage.saveSetlist(setlist);
    setIsEditing(false);
    onRefresh();
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // --- REORDERING LOGIC ---

  const handlePointerDown = (e: React.PointerEvent, index: number) => {
    const target = e.currentTarget as HTMLElement;
    target.setPointerCapture(e.pointerId);

    if (containerRef.current) {
        containerRect.current = containerRef.current.getBoundingClientRect();
        const children = Array.from(containerRef.current.children);
        itemHeights.current = children.map(child => child.getBoundingClientRect().height + 8); 
    }

    startPointerY.current = e.clientY;
    setDraggedIndex(index);
    setHoverIndex(index);
    setDragOffset(0);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (draggedIndex === null || !containerRect.current) return;

    const currentY = e.clientY;
    const deltaY = currentY - startPointerY.current;
    setDragOffset(deltaY);

    const relativeY = currentY - containerRect.current.top + (containerRef.current?.scrollTop || 0);

    let currentTotalHeight = 0;
    let newHoverIndex = 0;

    for (let i = 0; i < itemHeights.current.length; i++) {
        const h = itemHeights.current[i];
        if (relativeY > currentTotalHeight + h / 2) {
            newHoverIndex = i;
        }
        currentTotalHeight += h;
    }

    const clampedIndex = Math.max(0, Math.min(newHoverIndex, selectedSheetIds.length - 1));
    if (clampedIndex !== hoverIndex) {
        setHoverIndex(clampedIndex);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (draggedIndex !== null && hoverIndex !== null && draggedIndex !== hoverIndex) {
        const newIds = [...selectedSheetIds];
        const [removed] = newIds.splice(draggedIndex, 1);
        newIds.splice(hoverIndex, 0, removed);
        setSelectedSheetIds(newIds);
    }

    const target = e.currentTarget as HTMLElement;
    if (target.hasPointerCapture(e.pointerId)) {
        target.releasePointerCapture(e.pointerId);
    }
    setDraggedIndex(null);
    setHoverIndex(null);
    setDragOffset(0);
  };

  const getItemStyle = (index: number) => {
    if (draggedIndex === null || hoverIndex === null) return {};

    if (index === draggedIndex) {
        return {
            transform: `translateY(${dragOffset}px) scale(1.03)`,
            zIndex: 50,
            boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.8)',
            borderColor: '#3b82f6', 
            backgroundColor: '#1e293b', 
            transition: 'none',
        };
    }

    let shift = 0;
    const height = itemHeights.current[draggedIndex] || 64;

    if (draggedIndex < hoverIndex) {
        if (index > draggedIndex && index <= hoverIndex) shift = -height;
    } else if (draggedIndex > hoverIndex) {
        if (index < draggedIndex && index >= hoverIndex) shift = height;
    }

    return {
        transform: `translateY(${shift}px)`,
        transition: 'transform 0.25s cubic-bezier(0.2, 0, 0, 1)',
    };
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.sheets.length > 0) {
            for (const sheet of result.sheets) {
                await storage.addSheet(sheet);
            }
            const sortedIds = [...result.sheets]
                .sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true }))
                .map(s => s.id);

            const newSetlist: Setlist = {
                id: crypto.randomUUID(),
                name: result.setlistName || "Imported Setlist",
                sheetIds: sortedIds,
                dateCreated: Date.now()
            };

            await storage.saveSetlist(newSetlist);
            onRefresh();
        } else if (result.error) {
            alert(result.error);
        }
    }
    if (e.target) e.target.value = '';
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => s.name.toLowerCase().includes(q) || (s.tags && s.tags.some(t => t.toLowerCase().includes(q))));
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white tracking-tight">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={() => setIsEditing(false)} className="px-4 py-2 text-slate-400 hover:text-white transition-colors font-medium">Cancel</button>
             <button onClick={handleSave} disabled={!newSetName || selectedSheetIds.length === 0} className="flex items-center gap-2 bg-green-600 text-white px-5 py-2.5 rounded-xl hover:bg-green-500 disabled:opacity-50 transition-all shadow-lg shadow-green-900/20 active:scale-95">
                <Check size={18} /> <span className="font-bold">Save Setlist</span>
             </button>
           </div>
        </div>

        <div className="relative mb-6">
            <input 
                type="text" 
                placeholder="Ex: Tonight's Performance, Jazz Set, etc." 
                className="w-full bg-slate-800 border-2 border-slate-700 rounded-xl p-4 text-xl text-white focus:border-blue-500 outline-none transition-colors" 
                value={newSetName} 
                onChange={e => setNewSetName(e.target.value)} 
            />
        </div>

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/40 rounded-2xl p-4 border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Add Library Pieces</h3>
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                    <input type="text" placeholder="Search library..." className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-sm text-slate-200 outline-none focus:ring-1 focus:ring-blue-500" value={librarySearch} onChange={(e) => setLibrarySearch(e.target.value)} />
                </div>
                <div className="overflow-y-auto space-y-2 flex-1 no-scrollbar">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <button 
                                key={sheet.id} 
                                onClick={() => !isSelected && toggleSelection(sheet.id)} 
                                className={`w-full flex items-center p-3 rounded-xl border-2 transition-all text-left ${isSelected ? 'opacity-40 border-slate-700 bg-transparent grayscale' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700 hover:border-blue-500/30'}`}
                            >
                                <div className={`w-7 h-7 rounded-lg flex items-center justify-center mr-3 shrink-0 transition-colors ${isSelected ? 'bg-slate-700' : 'bg-blue-600'}`}>
                                    {isSelected ? <Check size={14}/> : <Plus size={14} />}
                                </div>
                                <span className="text-slate-200 text-sm font-medium truncate">{sheet.name}</span>
                            </button>
                        );
                    })}
                </div>
            </div>

            <div className="flex-[1.5] overflow-y-auto min-h-0 bg-slate-800/40 rounded-2xl p-4 no-scrollbar border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Performance Order</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-48 text-slate-500 italic text-sm">
                        <ListMusic size={32} className="mb-2 opacity-20" />
                        Select pieces from the library to build your set
                    </div>
                ) : (
                    <div ref={containerRef} className="space-y-2 select-none relative pb-10">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isBeingDragged = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    style={getItemStyle(index)}
                                    className="flex items-center bg-slate-800 p-2 rounded-xl border border-slate-700 relative group"
                                >
                                    <div 
                                        className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none transition-colors hover:text-white"
                                        onPointerDown={(e) => handlePointerDown(e, index)}
                                        onPointerMove={handlePointerMove}
                                        onPointerUp={handlePointerUp}
                                    >
                                        <GripVertical size={20} />
                                    </div>
                                    <div className={`flex items-center flex-1 min-w-0 ${isBeingDragged ? 'pointer-events-none' : ''}`}>
                                        <div className="w-6 h-6 flex items-center justify-center text-[10px] font-black text-slate-600 bg-slate-900 rounded-md shrink-0">
                                            {index + 1}
                                        </div>
                                        <span className="flex-1 truncate mx-3 text-sm font-semibold text-white">{sheet.name}</span>
                                    </div>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); toggleSelection(id); }} 
                                        className={`p-3 text-slate-500 hover:text-red-500 transition-all ${isBeingDragged ? 'pointer-events-none opacity-0' : 'opacity-0 group-hover:opacity-100'}`}
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-6">
        <div>
            <h1 className="text-4xl font-black text-white mb-2">Setlists</h1>
            <p className="text-slate-400 text-sm">Performance ready repertoire lists</p>
        </div>
        <div className="flex gap-3 items-center flex-wrap">
            <div className="relative group">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-500 transition-colors" />
                <input type="text" placeholder="Search sets..." className="bg-slate-800 border border-slate-700 rounded-xl pl-10 pr-4 py-2.5 text-white focus:border-blue-500 outline-none transition-all w-full md:w-48 lg:w-64" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
            </div>

            <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 px-5 py-2.5 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-lg active:scale-95">
                <Import size={18} />
                <span className="font-bold text-sm">Import Set</span>
            </button>

            <button onClick={startCreate} className="flex items-center gap-2 bg-blue-600 text-white px-6 py-2.5 rounded-xl hover:bg-blue-500 transition-all shadow-xl shadow-blue-900/20 active:scale-95">
                <Plus size={20} />
                <span className="font-bold text-sm">Create New</span>
            </button>

            <input type="file" ref={importInputRef} className="hidden" 
                // @ts-ignore
                webkitdirectory="" directory="" multiple onChange={handleImportSetlist} 
            />
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
          {filteredSetlists.map(list => (
            <div key={list.id} className="bg-slate-800/80 rounded-2xl p-4 sm:p-5 flex items-center justify-between hover:bg-slate-800 hover:shadow-2xl transition-all border border-slate-700/50 group">
               <div className="flex items-center gap-4 sm:gap-5 cursor-pointer flex-1 min-w-0" onClick={() => onPlay(list)}>
                  <div className="p-3 sm:p-4 bg-slate-900 rounded-2xl text-slate-500 group-hover:text-blue-400 transition-colors shrink-0"><ListMusic size={28} /></div>
                  <div className="min-w-0">
                      <h3 className="text-lg sm:text-xl font-bold text-white group-hover:text-blue-400 transition-colors truncate">{list.name}</h3>
                      <div className="flex items-center flex-wrap gap-x-2 gap-y-1 mt-1">
                          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest whitespace-nowrap">{list.sheetIds.length} pieces</span>
                          <span className="w-1 h-1 rounded-full bg-slate-700 hidden xs:block" />
                          <span className="text-[10px] text-slate-500 whitespace-nowrap">{new Date(list.dateCreated).toLocaleDateString()}</span>
                      </div>
                  </div>
               </div>
               <div className="flex items-center gap-2 sm:gap-3 ml-4 shrink-0">
                   <button onClick={() => onPlay(list)} className="p-2.5 sm:p-3 bg-green-600 text-white rounded-xl sm:rounded-2xl hover:bg-green-500 transition-all shadow-lg shadow-green-900/20 active:scale-90 flex items-center gap-2 sm:px-4 group/play">
                       <Play size={20} fill="currentColor" />
                       <span className="font-black text-[10px] uppercase tracking-widest hidden sm:block">Start Gig</span>
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-1 hidden md:block" />
                   <button onClick={() => startEdit(list)} className="p-2.5 text-slate-500 hover:text-blue-400 hover:bg-blue-400/10 rounded-xl transition-all"><Pencil size={18} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-2.5 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"><Trash2 size={18} /></button>
               </div>
            </div>
          ))}

          {filteredSetlists.length === 0 && (
              <div className="py-24 text-center">
                  <p className="text-slate-500 font-medium">No setlists found matching "{listSearch}"</p>
              </div>
          )}
      </div>

      {deleteModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 w-full max-w-md shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle size={32} className="text-red-500" />
            </div>
            <h2 className="text-2xl font-bold text-white text-center mb-2">Delete Setlist?</h2>
            <p className="text-slate-400 text-center text-sm mb-8 px-4 leading-relaxed">This will remove the "{deleteModal.setlist?.name}" playlist. Your library files and annotations are safe.</p>
            <div className="flex gap-3">
                <button onClick={() => setDeleteModal({ isOpen: false, setlist: null })} className="flex-1 py-3.5 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 py-3.5 bg-red-600 text-white rounded-2xl hover:bg-red-500 transition-all font-bold shadow-lg shadow-red-900/20">Delete List</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useRef, useState, useMemo, useEffect, useCallback } from 'react';
import { Upload, FileText, Trash2, Plus, Music, Search, Tag, X, PenLine, Save, FolderUp, Layers, ChevronDown, Check, Library as LibraryIcon, AlertTriangle, Copy, FileWarning, RefreshCw } from 'lucide-react';
import { Sheet, SheetPage, TagDef, Setlist } from '../types';
import { storage } from '../services/storage';
import { ICON_MAP } from '../constants';
import { processBatchImport } from '../utils/fileProcessor';

interface LibraryProps {
  sheets: Sheet[];
  setlists: Setlist[];
  onImport: () => void;
  onRefresh: () => void;
  onSelect: (id: string) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    sheet: Sheet | null;
    affectedSetlists: string[];
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    successMessage?: string;
}

interface ErrorModalState {
    isOpen: boolean;
    message: string;
}

const Library: React.FC<LibraryProps> = ({ sheets, setlists, onRefresh, onSelect }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const batchInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const [allTags, setAllTags] = useState<TagDef[]>([]);
  const [editingSheet, setEditingSheet] = useState<Sheet | null>(null);
  const [editName, setEditName] = useState('');
  const [editTags, setEditTags] = useState<string[]>([]);
  const [editTagIcons, setEditTagIcons] = useState<Record<string, string>>({});
  const [tagInput, setTagInput] = useState('');

  const [selectedIconName, setSelectedIconName] = useState<string>('Tag');
  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, sheet: null, affectedSetlists: [] });
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);
  const [errorModal, setErrorModal] = useState<ErrorModalState>({ isOpen: false, message: '' });

  const loadTags = useCallback(async () => {
    try {
        const tags = await storage.getAllTags();
        setAllTags(tags);
    } catch (e) {
        console.error("Failed to load tags", e);
    }
  }, []);

  useEffect(() => {
    loadTags();
  }, [loadTags]);

  const initiateImport = async (newSheets: Sheet[], successMessage?: string) => {
    if (newSheets.length === 0) return;
    const currentSheets = await storage.getAllSheets();
    const duplicates = newSheets.filter(newSheet => 
        currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
    );
    if (duplicates.length > 0) {
        setConflictData({ newSheets, duplicates, successMessage });
    } else {
        await finalizeImport(newSheets, false, successMessage);
    }
  };

  const finalizeImport = async (newSheets: Sheet[], overwrite: boolean, successMessage?: string) => {
      const currentSheets = await storage.getAllSheets();
      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
          let sheetToSave = sheet;

          if (existing && overwrite) {
              sheetToSave = {
                  ...sheet,
                  id: existing.id, // Preserve ID to keep tags/annotations
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }
          await storage.addSheet(sheetToSave);
      }
      setConflictData(null);
      if (successMessage) setTimeout(() => alert(successMessage), 100);
      onRefresh();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newSheets: Sheet[] = [];
      for (let i = 0; i < e.target.files.length; i++) {
        const file = e.target.files[i];
        const page: SheetPage = { blob: file, fileType: file.type as any };
        newSheets.push({
          id: crypto.randomUUID(),
          name: file.name.replace(/\.[^/.]+$/, ""),
          tags: [],
          dateAdded: Date.now(),
          pages: [page]
        });
      }
      await initiateImport(newSheets);
    }
    if (e.target) e.target.value = '';
  };

  const handleFolderChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = (Array.from(e.target.files) as File[]).filter(f => !f.name.startsWith('.'));
      if (files.length === 0) return;
      files.sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));
      const pathParts = files[0].webkitRelativePath.split('/');
      const sheetName = pathParts.length > 1 ? pathParts[pathParts.length - 2] : "Imported Folder";
      const pages: SheetPage[] = files.map(f => ({ blob: f, fileType: f.type as any }));
      const newSheet: Sheet = {
          id: crypto.randomUUID(),
          name: sheetName,
          tags: [],
          dateAdded: Date.now(),
          pages: pages
      };
      await initiateImport([newSheet]);
    }
    if (e.target) e.target.value = '';
  };

  const handleBatchImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.error) {
            setErrorModal({ isOpen: true, message: result.error });
            if (e.target) e.target.value = '';
            return;
        }
        if (result.sheets.length > 0) {
            await initiateImport(result.sheets, `Successfully imported ${result.sheets.length} entries.`);
        } else {
            alert("No valid files found in selection.");
        }
    }
    if (e.target) e.target.value = '';
  };

  const handleDeleteClick = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    e.preventDefault();
    const affected = setlists
        .filter(list => list.sheetIds.includes(sheet.id))
        .map(list => list.name);
    setDeleteModal({ isOpen: true, sheet, affectedSetlists: affected });
  };

  const confirmDelete = async () => {
      if (deleteModal.sheet) {
          await storage.deleteSheet(deleteModal.sheet.id);
          setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] });
          onRefresh();
      }
  };

  const openEditModal = (e: React.MouseEvent, sheet: Sheet) => {
    e.stopPropagation();
    e.preventDefault();
    setEditingSheet(sheet);
    setEditName(sheet.name);
    setEditTags(sheet.tags || []);
    setEditTagIcons(sheet.tagIcons || {});
    setTagInput('');
    setSelectedIconName('Tag');
  };

  const closeEditModal = () => {
    setEditingSheet(null);
  };

  const handleAddTag = async () => {
    if (tagInput.trim()) {
      const tagName = tagInput.trim();
      if (!editTags.includes(tagName)) setEditTags([...editTags, tagName]);
      const iconName = selectedIconName || 'Tag';
      const newTagDef = { label: tagName, iconName };
      if (!allTags.some(t => t.label === tagName)) {
          setAllTags(prev => [...prev, newTagDef]);
          try {
            await storage.saveTag(newTagDef);
            await loadTags();
          } catch (err) {
            console.error("Failed to save tag", err);
            await loadTags();
          }
      }
      setTagInput('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setEditTags(editTags.filter(t => t !== tagToRemove));
  };

  const saveEdits = async () => {
    if (editingSheet && editName.trim()) {
      const updatedSheet: Sheet = {
        ...editingSheet,
        name: editName.trim(),
        tags: editTags,
        tagIcons: editTagIcons
      };
      await storage.updateSheetMetadata(updatedSheet);
      closeEditModal();
      onRefresh();
    }
  };

  const filteredSheets = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return sheets.filter(s => 
      s.name.toLowerCase().includes(q) || 
      (s.tags && s.tags.some(t => t.toLowerCase().includes(q)))
    );
  }, [sheets, searchQuery]);

  const getTagIcon = (tag: string, sheet?: Sheet) => {
    if (sheet?.tagIcons?.[tag]) return ICON_MAP[sheet.tagIcons[tag]] || Tag;
    if (editTagIcons[tag]) return ICON_MAP[editTagIcons[tag]] || Tag;
    const def = allTags.find(t => t.label === tag);
    return def ? ICON_MAP[def.iconName] || Tag : Tag;
  };

  return (
    <div className="p-6 pb-24 relative">
      <div className="flex flex-col xl:flex-row xl:items-start justify-between mb-8 gap-4">
        <div className="mt-1">
           <h1 className="text-3xl font-bold text-white mb-1">Library</h1>
           <p className="text-slate-400 text-sm">All your imported sheet music</p>
        </div>

        <div className="flex flex-col md:flex-row gap-3 items-start w-full xl:w-auto">
            <div className="relative flex-1 w-full md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Search by name or tags..." 
                    className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>

            <div className="flex flex-col gap-2 w-full md:w-auto">
                <button onClick={() => batchInputRef.current?.click()} className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap">
                    <LibraryIcon size={20} /> <span className="hidden sm:inline">Batch Import</span>
                </button>
                <div className="flex gap-2 w-full">
                    <button onClick={() => fileInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 whitespace-nowrap">
                        <Upload size={20} /> <span className="hidden sm:inline">File</span>
                    </button>
                    <button onClick={() => folderInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2.5 rounded-lg shadow-lg transition-all active:scale-95 border border-slate-600 whitespace-nowrap">
                        <FolderUp size={20} /> <span className="hidden sm:inline">Folder (Images)</span>
                    </button>
                </div>
            </div>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept="image/png, image/jpeg, application/pdf" multiple onChange={handleFileChange} />
        <input type="file" ref={folderInputRef} className="hidden" 
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleFolderChange} 
        />
        <input type="file" ref={batchInputRef} className="hidden"
            // @ts-ignore
            webkitdirectory="" directory="" multiple onChange={handleBatchImport} 
        />
      </div>

      {sheets.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-800/30">
          <Upload size={32} className="text-slate-400 mb-4" />
          <p className="text-lg text-slate-300 font-medium">No sheets yet</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {filteredSheets.map((sheet) => {
             const fileCount = sheet.pages.length;
             const isPdf = sheet.pages?.[0]?.fileType === 'application/pdf';
             return (
                <div key={sheet.id} onClick={() => onSelect(sheet.id)} className="group relative bg-slate-800 rounded-xl overflow-hidden hover:ring-2 hover:ring-blue-500 transition-all cursor-pointer aspect-[3/4] flex flex-col">
                    <div className="flex-1 bg-slate-900 flex items-center justify-center relative overflow-hidden">
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-transparent to-transparent z-10" />
                        <div className="flex flex-col items-center gap-2">
                            {isPdf ? <FileText size={48} className="text-slate-600" /> : <Music size={48} className="text-slate-600" />}
                            <span className="text-xs text-slate-500 uppercase font-bold tracking-wider">
                                {fileCount > 1 ? `${fileCount} ${isPdf ? 'Files' : 'Pages'}` : (isPdf ? 'PDF' : 'Image')}
                            </span>
                        </div>
                        <div className="absolute bottom-2 left-2 z-20 flex flex-wrap gap-1 max-w-[90%]">
                            {(sheet.tags || []).slice(0, 4).map(tag => {
                                const Icon = getTagIcon(tag, sheet);
                                return <span key={tag} className="text-[10px] bg-blue-500/20 text-blue-300 p-1 rounded-full border border-blue-500/30"><Icon size={12} /></span>;
                            })}
                        </div>
                    </div>
                    <div className="bg-slate-800 p-3 z-20 border-t border-slate-700/50">
                        <h3 className="text-white font-medium text-sm truncate">{sheet.name}</h3>
                        <p className="text-xs text-slate-400 mt-0.5">{new Date(sheet.dateAdded).toLocaleDateString()}</p>
                    </div>
                    <div className="absolute top-2 right-2 flex flex-col gap-2 z-30">
                        <button 
                            onClick={(e) => openEditModal(e, sheet)} 
                            className="p-3 bg-black/80 text-white rounded-full hover:bg-blue-600 active:scale-90 transition-all shadow-xl"
                        >
                            <PenLine size={16} />
                        </button>
                        <button 
                            onClick={(e) => handleDeleteClick(e, sheet)}
                            className="p-3 bg-black/80 text-white rounded-full hover:bg-red-500 active:scale-90 transition-all shadow-xl"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </div>
             );
          })}
        </div>
      )}

      {/* Duplicate Conflict Resolution Modal */}
      {conflictData && (
          <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
              <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 w-full max-w-lg shadow-2xl animate-in zoom-in-95 duration-200">
                  <div className="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                      <FileWarning size={32} className="text-amber-500" />
                  </div>
                  <h2 className="text-2xl font-bold text-white text-center mb-2">Duplicate Sheets Found</h2>
                  <p className="text-slate-400 text-center text-sm mb-6 leading-relaxed">
                      The following entries already exist in your library. How would you like to proceed?
                  </p>

                  <div className="max-h-48 overflow-y-auto mb-8 pr-2 space-y-2 no-scrollbar">
                      {conflictData.duplicates.map(d => (
                          <div key={d.id} className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-xl border border-slate-700/50">
                              <FileText size={16} className="text-slate-500" />
                              <span className="text-sm font-medium text-white truncate flex-1">{d.name}</span>
                              <span className="text-[10px] font-black uppercase tracking-tighter text-amber-500 bg-amber-500/10 px-2 py-0.5 rounded">Conflict</span>
                          </div>
                      ))}
                  </div>

                  <div className="flex flex-col gap-3">
                      <button 
                        onClick={() => finalizeImport(conflictData.newSheets, true, conflictData.successMessage)} 
                        className="w-full flex items-center justify-center gap-2 py-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-500 transition-all font-bold shadow-lg shadow-blue-900/20"
                      >
                          <RefreshCw size={20} /> Overwrite Existing
                      </button>
                      <button 
                        onClick={() => finalizeImport(conflictData.newSheets, false, conflictData.successMessage)} 
                        className="w-full flex items-center justify-center gap-2 py-4 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold"
                      >
                          <Copy size={20} /> Keep Both (Create Duplicates)
                      </button>
                      <button 
                        onClick={() => setConflictData(null)} 
                        className="w-full py-3 text-slate-500 hover:text-white transition-colors text-sm font-medium"
                      >
                          Cancel Import
                      </button>
                  </div>
              </div>
          </div>
      )}

      {deleteModal.isOpen && deleteModal.sheet && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-md shadow-2xl" onClick={e => e.stopPropagation()}>
            <div className="p-8 text-center">
                <AlertTriangle size={48} className="text-red-500 mx-auto mb-4" />
                <h2 className="text-xl font-bold text-white mb-2">Delete "{deleteModal.sheet.name}"?</h2>
                <p className="text-slate-400 text-sm">This will permanently remove the sheet and its annotations from your device.</p>
            </div>
            <div className="p-4 bg-slate-950 border-t border-slate-800 flex gap-3 rounded-b-2xl">
                <button onClick={() => setDeleteModal({ isOpen: false, sheet: null, affectedSetlists: [] })} className="flex-1 px-4 py-3 bg-slate-800 text-white rounded-lg font-medium">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 px-4 py-3 bg-red-600 text-white rounded-lg font-medium hover:bg-red-500">Delete Forever</button>
            </div>
          </div>
        </div>
      )}

      {editingSheet && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm" onClick={closeEditModal}>
          <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-lg shadow-2xl flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
                <h2 className="text-xl font-bold text-white">Edit Sheet Details</h2>
                <button onClick={closeEditModal} className="text-slate-400 hover:text-white"><X /></button>
            </div>
            <div className="p-6 space-y-6 overflow-y-auto no-scrollbar">
                <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Sheet Name</label>
                    <input type="text" className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none" value={editName} onChange={e => setEditName(e.target.value)} />
                </div>
                <div className="space-y-3">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Tags & Icons</label>
                    <div className="flex flex-wrap gap-2 mb-4">
                        {editTags.map(tag => (
                            <span key={tag} className="inline-flex items-center gap-2 px-3 py-1.5 bg-blue-600/20 text-blue-300 border border-blue-500/30 rounded-full text-sm">
                                {React.createElement(getTagIcon(tag), { size: 14 })}
                                {tag} <button onClick={() => handleRemoveTag(tag)} className="hover:text-red-400 transition-colors p-0.5"><X size={14}/></button>
                            </span>
                        ))}
                    </div>
                    <div className="flex gap-2">
                        <input type="text" className="flex-1 bg-slate-800 border border-slate-700 rounded-lg px-4 text-white" placeholder="Type new tag..." value={tagInput} onChange={e => setTagInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAddTag()} />
                        <button onClick={handleAddTag} className="p-3 bg-blue-600 text-white rounded-lg hover:bg-blue-500"><Plus size={20} /></button>
                    </div>
                </div>
            </div>
            <div className="p-4 bg-slate-950 border-t border-slate-800 flex gap-3 rounded-b-2xl">
                <button onClick={closeEditModal} className="flex-1 px-4 py-3 bg-slate-800 text-white rounded-lg font-medium">Cancel</button>
                <button onClick={saveEdits} className="flex-1 px-4 py-3 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-500">Save Changes</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Library;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, ListMusic, Trash2, Play, X, Check, Pencil, GripVertical, Search, Import, AlertTriangle, FileWarning, RefreshCw, Copy, FileText } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    setlistName?: string;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // DRAG STATE
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [hoverIndex, setHoverIndex] = useState<number | null>(null);
  const [dragOffset, setDragOffset] = useState(0);
  const startPointerY = useRef(0);
  const itemHeights = useRef<number[]>([]);
  const containerRect = useRef<DOMRect | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;
    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;
    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };
    await storage.saveSetlist(setlist);
    setIsEditing(false);
    onRefresh();
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // --- REORDERING LOGIC ---

  const handlePointerDown = (e: React.PointerEvent, index: number) => {
    const target = e.currentTarget as HTMLElement;
    target.setPointerCapture(e.pointerId);

    if (containerRef.current) {
        containerRect.current = containerRef.current.getBoundingClientRect();
        const children = Array.from(containerRef.current.children);
        itemHeights.current = children.map(child => child.getBoundingClientRect().height + 8); 
    }

    startPointerY.current = e.clientY;
    setDraggedIndex(index);
    setHoverIndex(index);
    setDragOffset(0);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (draggedIndex === null || !containerRect.current) return;

    const currentY = e.clientY;
    const deltaY = currentY - startPointerY.current;
    setDragOffset(deltaY);

    const relativeY = currentY - containerRect.current.top + (containerRef.current?.scrollTop || 0);

    let currentTotalHeight = 0;
    let newHoverIndex = 0;

    for (let i = 0; i < itemHeights.current.length; i++) {
        const h = itemHeights.current[i];
        if (relativeY > currentTotalHeight + h / 2) {
            newHoverIndex = i;
        }
        currentTotalHeight += h;
    }

    const clampedIndex = Math.max(0, Math.min(newHoverIndex, selectedSheetIds.length - 1));
    if (clampedIndex !== hoverIndex) {
        setHoverIndex(clampedIndex);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (draggedIndex !== null && hoverIndex !== null && draggedIndex !== hoverIndex) {
        const newIds = [...selectedSheetIds];
        const [removed] = newIds.splice(draggedIndex, 1);
        newIds.splice(hoverIndex, 0, removed);
        setSelectedSheetIds(newIds);
    }

    const target = e.currentTarget as HTMLElement;
    if (target.hasPointerCapture(e.pointerId)) {
        target.releasePointerCapture(e.pointerId);
    }
    setDraggedIndex(null);
    setHoverIndex(null);
    setDragOffset(0);
  };

  const getItemStyle = (index: number) => {
    if (draggedIndex === null || hoverIndex === null) return {};

    if (index === draggedIndex) {
        return {
            transform: `translateY(${dragOffset}px) scale(1.03)`,
            zIndex: 50,
            boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.8)',
            borderColor: '#3b82f6', 
            backgroundColor: '#1e293b', 
            transition: 'none',
        };
    }

    let shift = 0;
    const height = itemHeights.current[draggedIndex] || 64;

    if (draggedIndex < hoverIndex) {
        if (index > draggedIndex && index <= hoverIndex) shift = -height;
    } else if (draggedIndex > hoverIndex) {
        if (index < draggedIndex && index >= hoverIndex) shift = height;
    }

    return {
        transform: `translateY(${shift}px)`,
        transition: 'transform 0.25s cubic-bezier(0.2, 0, 0, 1)',
    };
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.sheets.length > 0) {
            const currentSheets = await storage.getAllSheets();
            const duplicates = result.sheets.filter(newSheet => 
                currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
            );

            if (duplicates.length > 0) {
                setConflictData({ 
                    newSheets: result.sheets, 
                    duplicates, 
                    setlistName: result.setlistName 
                });
            } else {
                await finalizeSetlistImport(result.sheets, false, result.setlistName);
            }
        } else if (result.error) {
            alert(result.error);
        }
    }
    if (e.target) e.target.value = '';
  };

  const finalizeSetlistImport = async (newSheets: Sheet[], overwrite: boolean, setlistName?: string) => {
      const currentSheets = await storage.getAllSheets();
      const finalSheetIds: string[] = [];

      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
          let sheetToSave = sheet;

          if (existing && overwrite) {
              sheetToSave = {
                  ...sheet,
                  id: existing.id, // Overwrite underlying data but keep metadata
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }
          await storage.addSheet(sheetToSave);
          finalSheetIds.push(sheetToSave.id);
      }

      // Preserve alphabetical order within the imported setlist
      finalSheetIds.sort((a, b) => {
          const sA = newSheets.find(s => s.id === a || (overwrite && s.name === currentSheets.find(ex => ex.id === a)?.name));
          const sB = newSheets.find(s => s.id === b || (overwrite && s.name === currentSheets.find(ex => ex.id === b)?.name));
          return (sA?.name || '').localeCompare(sB?.name || '', undefined, { numeric: true });
      });

      const newSetlist: Setlist = {
          id: crypto.randomUUID(),
          name: setlistName || "Imported Setlist",
          sheetIds: finalSheetIds,
          dateCreated: Date.now()
      };

      await storage.saveSetlist(newSetlist);
      setConflictData(null);
      onRefresh();
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => s.name.toLowerCase().includes(q) || (s.tags && s.tags.some(t => t.toLowerCase().includes(q))));
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white tracking-tight">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={() => setIsEditing(false)} className="px-4 py-2 text-slate-400 hover:text-white transition-colors font-medium">Cancel</button>
             <button onClick={handleSave} disabled={!newSetName || selectedSheetIds.length === 0} className="flex items-center gap-2 bg-green-600 text-white px-5 py-2.5 rounded-xl hover:bg-green-500 disabled:opacity-50 transition-all shadow-lg shadow-green-900/20 active:scale-95">
                <Check size={18} /> <span className="font-bold">Save Setlist</span>
             </button>
           </div>
        </div>

        <div className="relative mb-6">
            <input 
                type="text" 
                placeholder="Ex: Tonight's Performance, Jazz Set, etc." 
                className="w-full bg-slate-800 border-2 border-slate-700 rounded-xl p-4 text-xl text-white focus:border-blue-500 outline-none transition-colors" 
                value={newSetName} 
                onChange={e => setNewSetName(e.target.value)} 
            />
        </div>

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/40 rounded-2xl p-4 border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Add Library Pieces</h3>
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                    <input type="text" placeholder="Search library..." className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-sm text-slate-200 outline-none focus:ring-1 focus:ring-blue-500" value={librarySearch} onChange={(e) => setLibrarySearch(e.target.value)} />
                </div>
                <div className="overflow-y-auto space-y-2 flex-1 no-scrollbar">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <button 
                                key={sheet.id} 
                                onClick={() => !isSelected && toggleSelection(sheet.id)} 
                                className={`w-full flex items-center p-3 rounded-xl border-2 transition-all text-left ${isSelected ? 'opacity-40 border-slate-700 bg-transparent grayscale' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700 hover:border-blue-500/30'}`}
                            >
                                <div className={`w-7 h-7 rounded-lg flex items-center justify-center mr-3 shrink-0 transition-colors ${isSelected ? 'bg-slate-700' : 'bg-blue-600'}`}>
                                    {isSelected ? <Check size={14}/> : <Plus size={14} />}
                                </div>
                                <span className="text-slate-200 text-sm font-medium truncate">{sheet.name}</span>
                            </button>
                        );
                    })}
                </div>
            </div>

            <div className="flex-[1.5] overflow-y-auto min-h-0 bg-slate-800/40 rounded-2xl p-4 no-scrollbar border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Performance Order</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-48 text-slate-500 italic text-sm">
                        <ListMusic size={32} className="mb-2 opacity-20" />
                        Select pieces from the library to build your set
                    </div>
                ) : (
                    <div ref={containerRef} className="space-y-2 select-none relative pb-10">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isBeingDragged = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    style={getItemStyle(index)}
                                    className="flex items-center bg-slate-800 p-2 rounded-xl border border-slate-700 relative group"
                                >
                                    <div 
                                        className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none transition-colors hover:text-white"
                                        onPointerDown={(e) => handlePointerDown(e, index)}
                                        onPointerMove={handlePointerMove}
                                        onPointerUp={handlePointerUp}
                                    >
                                        <GripVertical size={20} />
                                    </div>
                                    <div className={`flex items-center flex-1 min-w-0 ${isBeingDragged ? 'pointer-events-none' : ''}`}>
                                        <div className="w-6 h-6 flex items-center justify-center text-[10px] font-black text-slate-600 bg-slate-900 rounded-md shrink-0">
                                            {index + 1}
                                        </div>
                                        <span className="flex-1 truncate mx-3 text-sm font-semibold text-white">{sheet.name}</span>
                                    </div>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); toggleSelection(id); }} 
                                        className={`p-3 text-slate-500 hover:text-red-500 transition-all ${isBeingDragged ? 'pointer-events-none opacity-0' : 'opacity-0 group-hover:opacity-100'}`}
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-6">
        <div>
            <h1 className="text-4xl font-black text-white mb-2">Setlists</h1>
            <p className="text-slate-400 text-sm">Performance ready repertoire lists</p>
        </div>
        <div className="flex gap-3 items-center flex-wrap">
            <div className="relative group">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-500 transition-colors" />
                <input type="text" placeholder="Search sets..." className="bg-slate-800 border border-slate-700 rounded-xl pl-10 pr-4 py-2.5 text-white focus:border-blue-500 outline-none transition-all w-full md:w-48 lg:w-64" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
            </div>

            <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 px-5 py-2.5 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-lg active:scale-95">
                <Import size={18} />
                <span className="font-bold text-sm">Import Set</span>
            </button>

            <button onClick={startCreate} className="flex items-center gap-2 bg-blue-600 text-white px-6 py-2.5 rounded-xl hover:bg-blue-500 transition-all shadow-xl shadow-blue-900/20 active:scale-95">
                <Plus size={20} />
                <span className="font-bold text-sm">Create New</span>
            </button>

            <input type="file" ref={importInputRef} className="hidden" 
                // @ts-ignore
                webkitdirectory="" directory="" multiple onChange={handleImportSetlist} 
            />
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
          {filteredSetlists.map(list => (
            <div key={list.id} className="bg-slate-800/80 rounded-2xl p-4 sm:p-5 flex items-center justify-between hover:bg-slate-800 hover:shadow-2xl transition-all border border-slate-700/50 group">
               <div className="flex items-center gap-4 sm:gap-5 cursor-pointer flex-1 min-w-0" onClick={() => onPlay(list)}>
                  <div className="p-3 sm:p-4 bg-slate-900 rounded-2xl text-slate-500 group-hover:text-blue-400 transition-colors shrink-0"><ListMusic size={28} /></div>
                  <div className="min-w-0">
                      <h3 className="text-lg sm:text-xl font-bold text-white group-hover:text-blue-400 transition-colors truncate">{list.name}</h3>
                      <div className="flex items-center flex-wrap gap-x-2 gap-y-1 mt-1">
                          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest whitespace-nowrap">{list.sheetIds.length} pieces</span>
                          <span className="w-1 h-1 rounded-full bg-slate-700 hidden xs:block" />
                          <span className="text-[10px] text-slate-500 whitespace-nowrap">{new Date(list.dateCreated).toLocaleDateString()}</span>
                      </div>
                  </div>
               </div>
               <div className="flex items-center gap-2 sm:gap-3 ml-4 shrink-0">
                   <button onClick={() => onPlay(list)} className="p-2.5 sm:p-3 bg-green-600 text-white rounded-xl sm:rounded-2xl hover:bg-green-500 transition-all shadow-lg shadow-green-900/20 active:scale-90 flex items-center gap-2 sm:px-4 group/play">
                       <Play size={20} fill="currentColor" />
                       <span className="font-black text-[10px] uppercase tracking-widest hidden sm:block">Start Gig</span>
                   </button>
                   <div className="w-px h-8 bg-slate-700 mx-1 hidden md:block" />
                   <button onClick={() => startEdit(list)} className="p-2.5 text-slate-500 hover:text-blue-400 hover:bg-blue-400/10 rounded-xl transition-all"><Pencil size={18} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-2.5 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"><Trash2 size={18} /></button>
               </div>
            </div>
          ))}

          {filteredSetlists.length === 0 && (
              <div className="py-24 text-center">
                  <p className="text-slate-500 font-medium">No setlists found matching "{listSearch}"</p>
              </div>
          )}
      </div>

      {/* Duplicate Conflict Resolution Modal */}
      {conflictData && (
          <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
              <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 w-full max-w-lg shadow-2xl animate-in zoom-in-95 duration-200">
                  <div className="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                      <FileWarning size={32} className="text-amber-500" />
                  </div>
                  <h2 className="text-2xl font-bold text-white text-center mb-2">Duplicate Sheets in Setlist</h2>
                  <p className="text-slate-400 text-center text-sm mb-6 leading-relaxed">
                      The following sheets in your imported setlist already exist in your library.
                  </p>

                  <div className="max-h-48 overflow-y-auto mb-8 pr-2 space-y-2 no-scrollbar">
                      {conflictData.duplicates.map(d => (
                          <div key={d.id} className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-xl border border-slate-700/50">
                              <FileText size={16} className="text-slate-500" />
                              <span className="text-sm font-medium text-white truncate flex-1">{d.name}</span>
                              <span className="text-[10px] font-black uppercase tracking-tighter text-amber-500 bg-amber-500/10 px-2 py-0.5 rounded">Conflict</span>
                          </div>
                      ))}
                  </div>

                  <div className="flex flex-col gap-3">
                      <button 
                        onClick={() => finalizeSetlistImport(conflictData.newSheets, true, conflictData.setlistName)} 
                        className="w-full flex items-center justify-center gap-2 py-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-500 transition-all font-bold shadow-lg shadow-blue-900/20"
                      >
                          <RefreshCw size={20} /> Overwrite Library Content
                      </button>
                      <button 
                        onClick={() => finalizeSetlistImport(conflictData.newSheets, false, conflictData.setlistName)} 
                        className="w-full flex items-center justify-center gap-2 py-4 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold"
                      >
                          <Copy size={20} /> Keep Both (New Copies)
                      </button>
                      <button 
                        onClick={() => setConflictData(null)} 
                        className="w-full py-3 text-slate-500 hover:text-white transition-colors text-sm font-medium"
                      >
                          Cancel Import
                      </button>
                  </div>
              </div>
          </div>
      )}

      {deleteModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 w-full max-w-md shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle size={32} className="text-red-500" />
            </div>
            <h2 className="text-2xl font-bold text-white text-center mb-2">Delete Setlist?</h2>
            <p className="text-slate-400 text-center text-sm mb-8 px-4 leading-relaxed">This will remove the "{deleteModal.setlist?.name}" playlist. Your library files and annotations are safe.</p>
            <div className="flex gap-3">
                <button onClick={() => setDeleteModal({ isOpen: false, setlist: null })} className="flex-1 py-3.5 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 py-3.5 bg-red-600 text-white rounded-2xl hover:bg-red-500 transition-all font-bold shadow-lg shadow-red-900/20">Delete List</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Setlists;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type } from 'lucide-react';
import { Stroke, Point, Sheet } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<'pen' | 'eraser'>('pen');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(3);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    const newStroke: Stroke = {
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
  };

  const handlePointerUp = () => {
    if (activeStroke) {
      const updated = [...allStrokes, activeStroke];
      setAllStrokes(updated);
      storage.saveAnnotation(sheetId, updated);
      setActiveStroke(null);
    }
  };

  const clearPageAnnotations = () => {
    const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex);
    setAllStrokes(updated);
    storage.saveAnnotation(sheetId, updated);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue) {
        setShowJumpDropdown(false);
        setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>

                {/* Jump Dropdown Menu */}
                {showJumpDropdown && (
                    <div 
                        className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="flex items-center gap-2 mb-3 text-slate-400">
                            <BookOpen size={14} />
                            <span className="text-[10px] font-black uppercase tracking-widest">Go to page</span>
                        </div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input 
                                ref={jumpInputRef}
                                type="number"
                                min="1"
                                max={totalDisplayPages}
                                value={jumpInputValue}
                                onChange={e => setJumpInputValue(e.target.value)}
                                placeholder={`1-${totalDisplayPages}`}
                                className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500"
                            />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors">
                                <ArrowRight size={20} />
                            </button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating) setCurrentTool('pen'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'pen' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      {/* Main Viewport */}
      <div 
        ref={containerRef} 
        className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} 
        onClick={handleContainerClick}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`}
            style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet && currentFile && !isPdf && (
            <img 
                src={URL.createObjectURL(currentFile.blob)} 
                className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none"
                alt="Sheet Page"
                onLoad={(e) => {
                    const img = e.target as HTMLImageElement;
                    setDimensions({ width: img.naturalWidth, height: img.naturalHeight });
                }}
            />
        )}

        {/* Annotations Overlay */}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => (
                        <path 
                            key={i}
                            d={stroke.points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                            stroke={stroke.color}
                            strokeWidth={stroke.width}
                            fill="none"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        />
                    ))
                }
                {activeStroke && (
                    <path 
                        d={activeStroke.points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                        stroke={activeStroke.color}
                        strokeWidth={activeStroke.width}
                        fill="none"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        className="opacity-60"
                    />
                )}
            </svg>
        )}
      </div>

      {/* Drawing Toolbar (Bottom) */}
      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2.5 px-4 rounded-3xl shadow-2xl flex items-center gap-6 z-50 animate-in slide-in-from-bottom-4 duration-300">
              <div className="flex items-center gap-2">
                  {COLORS.map(c => (
                      <button 
                        key={c} 
                        onClick={() => { setSelectedColor(c); setCurrentTool('pen'); }}
                        className={`w-7 h-7 rounded-full border-2 transition-all ${selectedColor === c && currentTool === 'pen' ? 'scale-125 border-white shadow-lg' : 'border-transparent scale-100'}`}
                        style={{ backgroundColor: c }}
                      />
                  ))}
              </div>
              <div className="w-px h-6 bg-white/10" />
              <div className="flex items-center gap-4">
                  {[2, 4, 8].map(w => (
                      <button 
                        key={w} 
                        onClick={() => { setSelectedWidth(w); setCurrentTool('pen'); }}
                        className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool === 'pen' ? 'text-blue-400 scale-110' : 'text-slate-500'}`}
                      >
                          <div className="rounded-full bg-current" style={{ width: w + 4, height: w + 4 }} />
                      </button>
                  ))}
              </div>
              <div className="w-px h-6 bg-white/10" />
              <button onClick={clearPageAnnotations} className="p-2 text-slate-500 hover:text-red-400 transition-colors" title="Clear Page">
                  <RotateCcw size={18} />
              </button>
              <button onClick={() => setIsAnnotating(false)} className="bg-white/5 hover:bg-white/10 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-colors">
                  Done
              </button>
          </div>
      )}

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, ListMusic, Trash2, Play, X, Check, Pencil, GripVertical, Search, Import, AlertTriangle, FileWarning, RefreshCw, Copy, FileText } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    setlistName?: string;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // DRAG STATE
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [hoverIndex, setHoverIndex] = useState<number | null>(null);
  const [dragOffset, setDragOffset] = useState(0);
  const startPointerY = useRef(0);
  const itemHeights = useRef<number[]>([]);
  const containerRect = useRef<DOMRect | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;
    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;
    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };
    await storage.saveSetlist(setlist);
    setIsEditing(false);
    onRefresh();
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // --- REORDERING LOGIC ---

  const handlePointerDown = (e: React.PointerEvent, index: number) => {
    const target = e.currentTarget as HTMLElement;
    target.setPointerCapture(e.pointerId);

    if (containerRef.current) {
        containerRect.current = containerRef.current.getBoundingClientRect();
        const children = Array.from(containerRef.current.children);
        itemHeights.current = children.map(child => child.getBoundingClientRect().height + 8); 
    }

    startPointerY.current = e.clientY;
    setDraggedIndex(index);
    setHoverIndex(index);
    setDragOffset(0);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (draggedIndex === null || !containerRect.current) return;

    const currentY = e.clientY;
    const deltaY = currentY - startPointerY.current;
    setDragOffset(deltaY);

    const relativeY = currentY - containerRect.current.top + (containerRef.current?.scrollTop || 0);

    let currentTotalHeight = 0;
    let newHoverIndex = 0;

    for (let i = 0; i < itemHeights.current.length; i++) {
        const h = itemHeights.current[i];
        if (relativeY > currentTotalHeight + h / 2) {
            newHoverIndex = i;
        }
        currentTotalHeight += h;
    }

    const clampedIndex = Math.max(0, Math.min(newHoverIndex, selectedSheetIds.length - 1));
    if (clampedIndex !== hoverIndex) {
        setHoverIndex(clampedIndex);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (draggedIndex !== null && hoverIndex !== null && draggedIndex !== hoverIndex) {
        const newIds = [...selectedSheetIds];
        const [removed] = newIds.splice(draggedIndex, 1);
        newIds.splice(hoverIndex, 0, removed);
        setSelectedSheetIds(newIds);
    }

    const target = e.currentTarget as HTMLElement;
    if (target.hasPointerCapture(e.pointerId)) {
        target.releasePointerCapture(e.pointerId);
    }
    setDraggedIndex(null);
    setHoverIndex(null);
    setDragOffset(0);
  };

  const getItemStyle = (index: number) => {
    if (draggedIndex === null || hoverIndex === null) return {};

    if (index === draggedIndex) {
        return {
            transform: `translateY(${dragOffset}px) scale(1.03)`,
            zIndex: 50,
            boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.8)',
            borderColor: '#3b82f6', 
            backgroundColor: '#1e293b', 
            transition: 'none',
        };
    }

    let shift = 0;
    const height = itemHeights.current[draggedIndex] || 64;

    if (draggedIndex < hoverIndex) {
        if (index > draggedIndex && index <= hoverIndex) shift = -height;
    } else if (draggedIndex > hoverIndex) {
        if (index < draggedIndex && index >= hoverIndex) shift = height;
    }

    return {
        transform: `translateY(${shift}px)`,
        transition: 'transform 0.25s cubic-bezier(0.2, 0, 0, 1)',
    };
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.sheets.length > 0) {
            const currentSheets = await storage.getAllSheets();
            const duplicates = result.sheets.filter(newSheet => 
                currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
            );

            if (duplicates.length > 0) {
                setConflictData({ 
                    newSheets: result.sheets, 
                    duplicates, 
                    setlistName: result.setlistName 
                });
            } else {
                await finalizeSetlistImport(result.sheets, false, result.setlistName);
            }
        } else if (result.error) {
            alert(result.error);
        }
    }
    if (e.target) e.target.value = '';
  };

  const finalizeSetlistImport = async (newSheets: Sheet[], overwrite: boolean, setlistName?: string) => {
      const currentSheets = await storage.getAllSheets();
      const finalSheetIds: string[] = [];

      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
          let sheetToSave = sheet;

          if (existing && overwrite) {
              sheetToSave = {
                  ...sheet,
                  id: existing.id, 
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }
          await storage.addSheet(sheetToSave);
          finalSheetIds.push(sheetToSave.id);
      }

      finalSheetIds.sort((a, b) => {
          const sA = newSheets.find(s => s.id === a || (overwrite && s.name === currentSheets.find(ex => ex.id === a)?.name));
          const sB = newSheets.find(s => s.id === b || (overwrite && s.name === currentSheets.find(ex => ex.id === b)?.name));
          return (sA?.name || '').localeCompare(sB?.name || '', undefined, { numeric: true });
      });

      const newSetlist: Setlist = {
          id: crypto.randomUUID(),
          name: setlistName || "Imported Setlist",
          sheetIds: finalSheetIds,
          dateCreated: Date.now()
      };

      await storage.saveSetlist(newSetlist);
      setConflictData(null);
      onRefresh();
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => s.name.toLowerCase().includes(q) || (s.tags && s.tags.some(t => t.toLowerCase().includes(q))));
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white tracking-tight">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={() => setIsEditing(false)} className="px-4 py-2 text-slate-400 hover:text-white transition-colors font-medium">Cancel</button>
             <button onClick={handleSave} disabled={!newSetName || selectedSheetIds.length === 0} className="flex items-center gap-2 bg-green-600 text-white px-5 py-2.5 rounded-xl hover:bg-green-500 disabled:opacity-50 transition-all shadow-lg shadow-green-900/20 active:scale-95">
                <Check size={18} /> <span className="font-bold">Save Setlist</span>
             </button>
           </div>
        </div>

        <div className="relative mb-6">
            <input 
                type="text" 
                placeholder="Ex: Tonight's Performance, Jazz Set, etc." 
                className="w-full bg-slate-800 border-2 border-slate-700 rounded-xl p-4 text-xl text-white focus:border-blue-500 outline-none transition-colors" 
                value={newSetName} 
                onChange={e => setNewSetName(e.target.value)} 
            />
        </div>

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/40 rounded-2xl p-4 border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Add Library Pieces</h3>
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                    <input type="text" placeholder="Search library..." className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-sm text-slate-200 outline-none focus:ring-1 focus:ring-blue-500" value={librarySearch} onChange={(e) => setLibrarySearch(e.target.value)} />
                </div>
                <div className="overflow-y-auto space-y-2 flex-1 no-scrollbar">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <button 
                                key={sheet.id} 
                                onClick={() => !isSelected && toggleSelection(sheet.id)} 
                                className={`w-full flex items-center p-3 rounded-xl border-2 transition-all text-left ${isSelected ? 'opacity-40 border-slate-700 bg-transparent grayscale' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700 hover:border-blue-500/30'}`}
                            >
                                <div className={`w-7 h-7 rounded-lg flex items-center justify-center mr-3 shrink-0 transition-colors ${isSelected ? 'bg-slate-700' : 'bg-blue-600'}`}>
                                    {isSelected ? <Check size={14}/> : <Plus size={14} />}
                                </div>
                                <span className="text-slate-200 text-sm font-medium truncate">{sheet.name}</span>
                            </button>
                        );
                    })}
                </div>
            </div>

            <div className="flex-[1.5] overflow-y-auto min-h-0 bg-slate-800/40 rounded-2xl p-4 no-scrollbar border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Performance Order</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-48 text-slate-500 italic text-sm">
                        <ListMusic size={32} className="mb-2 opacity-20" />
                        Select pieces from the library to build your set
                    </div>
                ) : (
                    <div ref={containerRef} className="space-y-2 select-none relative pb-10">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isBeingDragged = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    style={getItemStyle(index)}
                                    className="flex items-center bg-slate-800 p-2 rounded-xl border border-slate-700 relative group"
                                >
                                    <div 
                                        className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none transition-colors hover:text-white"
                                        onPointerDown={(e) => handlePointerDown(e, index)}
                                        onPointerMove={handlePointerMove}
                                        onPointerUp={handlePointerUp}
                                    >
                                        <GripVertical size={20} />
                                    </div>
                                    <div className={`flex items-center flex-1 min-w-0 ${isBeingDragged ? 'pointer-events-none' : ''}`}>
                                        <div className="w-6 h-6 flex items-center justify-center text-[10px] font-black text-slate-600 bg-slate-900 rounded-md shrink-0">
                                            {index + 1}
                                        </div>
                                        <span className="flex-1 truncate mx-3 text-sm font-semibold text-white">{sheet.name}</span>
                                    </div>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); toggleSelection(id); }} 
                                        className={`p-3 text-slate-500 hover:text-red-500 transition-all ${isBeingDragged ? 'pointer-events-none opacity-0' : 'opacity-0 group-hover:opacity-100'}`}
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-6">
        <div>
            <h1 className="text-4xl font-black text-white mb-2">Setlists</h1>
            <p className="text-slate-400 text-sm">Performance ready repertoire lists</p>
        </div>
        <div className="flex gap-3 items-center flex-wrap">
            <div className="relative group">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-500 transition-colors" />
                <input type="text" placeholder="Search sets..." className="bg-slate-800 border border-slate-700 rounded-xl pl-10 pr-4 py-2.5 text-white focus:border-blue-500 outline-none transition-all w-full md:w-48 lg:w-64" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
            </div>

            <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 px-4 py-2 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-lg active:scale-95">
                <Import size={16} />
                <span className="font-bold text-xs">Import Set</span>
            </button>

            <button onClick={startCreate} className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2 rounded-xl hover:bg-blue-500 transition-all shadow-xl shadow-blue-900/20 active:scale-95">
                <Plus size={18} />
                <span className="font-bold text-xs">Create New</span>
            </button>

            <input type="file" ref={importInputRef} className="hidden" 
                // @ts-ignore
                webkitdirectory="" directory="" multiple onChange={handleImportSetlist} 
            />
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
          {filteredSetlists.map(list => (
            <div key={list.id} className="bg-slate-800/80 rounded-2xl p-4 sm:p-5 flex items-center justify-between hover:bg-slate-800 hover:shadow-2xl transition-all border border-slate-700/50 group">
               <div className="flex items-center gap-4 sm:gap-5 cursor-pointer flex-1 min-w-0" onClick={() => onPlay(list)}>
                  <div className="p-3 bg-slate-900 rounded-2xl text-slate-500 group-hover:text-blue-400 transition-colors shrink-0"><ListMusic size={24} /></div>
                  <div className="min-w-0">
                      <h3 className="text-lg font-bold text-white group-hover:text-blue-400 transition-colors truncate">{list.name}</h3>
                      <div className="flex items-center flex-wrap gap-x-2 gap-y-1 mt-1">
                          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest whitespace-nowrap">{list.sheetIds.length} pieces</span>
                          <span className="w-1 h-1 rounded-full bg-slate-700 hidden xs:block" />
                          <span className="text-[10px] text-slate-500 whitespace-nowrap">{new Date(list.dateCreated).toLocaleDateString()}</span>
                      </div>
                  </div>
               </div>
               <div className="flex items-center gap-2 ml-4 shrink-0">
                   <button onClick={() => onPlay(list)} className="p-2 px-3 bg-green-600 text-white rounded-xl hover:bg-green-500 transition-all shadow-lg shadow-green-900/20 active:scale-90 flex items-center gap-1.5 group/play">
                       <Play size={16} fill="currentColor" />
                       <span className="font-black text-[9px] uppercase tracking-widest hidden sm:block">Start Gig</span>
                   </button>
                   <div className="w-px h-6 bg-slate-700 mx-1 hidden md:block" />
                   <button onClick={() => startEdit(list)} className="p-2 text-slate-500 hover:text-blue-400 hover:bg-blue-400/10 rounded-xl transition-all"><Pencil size={16} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"><Trash2 size={16} /></button>
               </div>
            </div>
          ))}

          {filteredSetlists.length === 0 && (
              <div className="py-24 text-center">
                  <p className="text-slate-500 font-medium">No setlists found matching "{listSearch}"</p>
              </div>
          )}
      </div>

      {/* Duplicate Conflict Resolution Modal */}
      {conflictData && (
          <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
              <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 w-full max-w-lg shadow-2xl animate-in zoom-in-95 duration-200">
                  <div className="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                      <FileWarning size={32} className="text-amber-500" />
                  </div>
                  <h2 className="text-2xl font-bold text-white text-center mb-2">Duplicate Sheets in Setlist</h2>
                  <p className="text-slate-400 text-center text-sm mb-6 leading-relaxed">
                      The following sheets in your imported setlist already exist in your library.
                  </p>

                  <div className="max-h-48 overflow-y-auto mb-8 pr-2 space-y-2 no-scrollbar">
                      {conflictData.duplicates.map(d => (
                          <div key={d.id} className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-xl border border-slate-700/50">
                              <FileText size={16} className="text-slate-500" />
                              <span className="text-sm font-medium text-white truncate flex-1">{d.name}</span>
                              <span className="text-[10px] font-black uppercase tracking-tighter text-amber-500 bg-amber-500/10 px-2 py-0.5 rounded">Conflict</span>
                          </div>
                      ))}
                  </div>

                  <div className="flex flex-col gap-3">
                      <button 
                        onClick={() => finalizeSetlistImport(conflictData.newSheets, true, conflictData.setlistName)} 
                        className="w-full flex items-center justify-center gap-2 py-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-500 transition-all font-bold shadow-lg shadow-blue-900/20"
                      >
                          <RefreshCw size={20} /> Overwrite Library Content
                      </button>
                      <button 
                        onClick={() => finalizeSetlistImport(conflictData.newSheets, false, conflictData.setlistName)} 
                        className="w-full flex items-center justify-center gap-2 py-4 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold"
                      >
                          <Copy size={20} /> Keep Both (New Copies)
                      </button>
                      <button 
                        onClick={() => setConflictData(null)} 
                        className="w-full py-3 text-slate-500 hover:text-white transition-colors text-sm font-medium"
                      >
                          Cancel Import
                      </button>
                  </div>
              </div>
          </div>
      )}

      {deleteModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 w-full max-w-md shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle size={32} className="text-red-500" />
            </div>
            <h2 className="text-2xl font-bold text-white text-center mb-2">Delete Setlist?</h2>
            <p className="text-slate-400 text-center text-sm mb-8 px-4 leading-relaxed">This will remove the "{deleteModal.setlist?.name}" playlist. Your library files and annotations are safe.</p>
            <div className="flex gap-3">
                <button onClick={() => setDeleteModal({ isOpen: false, setlist: null })} className="flex-1 py-3.5 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 py-3.5 bg-red-600 text-white rounded-2xl hover:bg-red-500 transition-all font-bold shadow-lg shadow-red-900/20">Delete List</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Setlists;

export interface Point {
  x: number;
  y: number;
}

export type AnnotationType = 'path' | 'text' | 'rect' | 'circle';

export interface Stroke {
  id?: string;
  type?: AnnotationType;
  points: Point[];
  color: string;
  width: number;
  text?: string;
  pageIndex: number; // For PDF: page number (0-based). For Images: 0.
  fileIndex?: number; // Index of the file in sheet.pages. Defaults to 0 if undefined.
}

export interface SheetPage {
  blob: Blob;
  fileType: 'image/png' | 'image/jpeg' | 'application/pdf';
}

export interface TagDef {
  label: string;
  iconName: string;
}

export interface Sheet {
  id: string;
  name: string;
  tags: string[]; 
  tagIcons?: Record<string, string>; // Map tag label to icon name (e.g. 'MyTag': 'Guitar')
  dateAdded: number;
  pages: SheetPage[]; // Replaced single blob with array of pages
  previewUrl?: string; // For images
}

export interface AnnotationLayer {
  sheetId: string;
  strokes: Stroke[];
}

export interface Setlist {
  id: string;
  name: string;
  sheetIds: string[]; // Ordered list of sheet IDs
  dateCreated: number;
}

export enum AppView {
  LIBRARY = 'LIBRARY',
  SETLISTS = 'SETLISTS',
  VIEWER = 'VIEWER',
}

export interface ViewerState {
  activeSetlistId: string | null; // null if viewing single file from library
  queue: string[]; // Sheet IDs in order
  currentIndex: number;
}

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(3);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);
  const [textInput, setTextInput] = useState<{ x: number, y: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const textInputRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;

    // Stop event propagation to prevent triggering page turns or HUD toggles
    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        // Basic proximity check for erasing
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    if (currentTool === 'text') {
        setTextInput({ x, y, value: '' });
        return;
    }

    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      type: currentTool === 'eraser' ? 'path' : currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        // Shapes like rect or circle only need two points: start and end
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (activeStroke) {
      const updated = [...allStrokes, activeStroke];
      setAllStrokes(updated);
      storage.saveAnnotation(sheetId, updated);
      setActiveStroke(null);
    }
  };

  const handleTextSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            points: [{ x: textInput.x, y: textInput.y }],
            color: selectedColor,
            width: selectedWidth,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const clearPageAnnotations = () => {
    const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex);
    setAllStrokes(updated);
    storage.saveAnnotation(sheetId, updated);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput) {
        setTimeout(() => textInputRef.current?.focus(), 50);
    }
  }, [textInput]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) return; // Don't turn page if typing
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (textInput) setTextInput(null);
          else if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-50' : ''
      };

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              return (
                  <text 
                    key={key}
                    x={x0}
                    y={y0}
                    fill={color}
                    fontSize={width * 5 + 12}
                    fontFamily="sans-serif"
                    fontWeight="bold"
                    className={isGhost ? 'opacity-50' : ''}
                  >
                      {text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>

                {/* Jump Dropdown Menu */}
                {showJumpDropdown && (
                    <div 
                        className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="flex items-center gap-2 mb-3 text-slate-400">
                            <BookOpen size={14} />
                            <span className="text-[10px] font-black uppercase tracking-widest">Go to page</span>
                        </div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input 
                                ref={jumpInputRef}
                                type="number"
                                min="1"
                                max={totalDisplayPages}
                                value={jumpInputValue}
                                onChange={e => setJumpInputValue(e.target.value)}
                                placeholder={`1-${totalDisplayPages}`}
                                className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500"
                            />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors">
                                <ArrowRight size={20} />
                            </button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      {/* Main Viewport */}
      <div 
        ref={containerRef} 
        className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} 
        onClick={handleContainerClick}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`}
            style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet && currentFile && !isPdf && (
            <img 
                src={URL.createObjectURL(currentFile.blob)} 
                className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none"
                alt="Sheet Page"
                onLoad={(e) => {
                    const img = e.target as HTMLImageElement;
                    setDimensions({ width: img.naturalWidth, height: img.naturalHeight });
                }}
            />
        )}

        {/* Annotations Overlay */}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => renderAnnotation(stroke, i))
                }
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}

        {/* Text Input Overlay */}
        {textInput && (
            <div className="absolute inset-0 z-[60] bg-black/20 flex items-center justify-center">
                <form 
                    onSubmit={handleTextSubmit} 
                    className="bg-slate-900 border border-white/20 p-4 rounded-2xl shadow-2xl w-full max-w-xs animate-in zoom-in-95 duration-200"
                    onClick={e => e.stopPropagation()}
                >
                    <div className="flex items-center gap-2 mb-3 text-slate-400">
                        <Type size={14} />
                        <span className="text-[10px] font-black uppercase tracking-widest">Add Note</span>
                    </div>
                    <input 
                        ref={textInputRef}
                        type="text"
                        placeholder="Type something..."
                        className="w-full bg-slate-800 border border-white/5 rounded-xl px-4 py-3 text-white font-medium outline-none focus:ring-2 focus:ring-blue-500 mb-4"
                        value={textInput.value}
                        onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                        onKeyDown={e => e.key === 'Escape' && setTextInput(null)}
                    />
                    <div className="flex gap-2">
                        <button type="button" onClick={() => setTextInput(null)} className="flex-1 py-2 text-slate-400 hover:text-white transition-colors text-xs font-bold uppercase tracking-widest">Cancel</button>
                        <button type="submit" className="flex-1 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold uppercase tracking-widest transition-all">Add</button>
                    </div>
                </form>
            </div>
        )}
      </div>

      {/* Drawing Toolbar (Bottom) */}
      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2 rounded-[2rem] shadow-2xl flex items-center gap-4 z-50 animate-in slide-in-from-bottom-4 duration-300 max-w-[95vw] overflow-x-auto no-scrollbar">

              {/* Tool Selector */}
              <div className="flex items-center bg-black/20 rounded-full p-1 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-2 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <PenTool size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('text')} className={`p-2 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Type size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-2 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Square size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-2 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Circle size={18} />
                  </button>
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Color Selector */}
              <div className="flex items-center gap-2 shrink-0">
                  {COLORS.map(c => (
                      <button 
                        key={c} 
                        onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`w-6 h-6 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-lg' : 'border-transparent scale-100 opacity-60'}`}
                        style={{ backgroundColor: c }}
                      />
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Stroke Width */}
              <div className="flex items-center gap-3 shrink-0">
                  {[2, 4, 8].map(w => (
                      <button 
                        key={w} 
                        onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}
                      >
                          <div className="rounded-full bg-current" style={{ width: w + 2, height: w + 2 }} />
                      </button>
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              <button onClick={clearPageAnnotations} className="p-2 text-slate-500 hover:text-red-400 transition-colors shrink-0" title="Clear Page">
                  <RotateCcw size={18} />
              </button>

              <button onClick={() => setIsAnnotating(false)} className="bg-white/10 hover:bg-white/20 text-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.15em] transition-all shrink-0 active:scale-95">
                  Done
              </button>
          </div>
      )}

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(3);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);
  const [textInput, setTextInput] = useState<{ x: number, y: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const textInputRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;

    // Stop event propagation to prevent triggering page turns or HUD toggles
    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        // Basic proximity check for erasing
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    if (currentTool === 'text') {
        setTextInput({ x, y, value: '' });
        return;
    }

    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      // Fix: Removed redundant type check for 'eraser' as the narrowed type here excludes it.
      type: currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        // Shapes like rect or circle only need two points: start and end
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (activeStroke) {
      const updated = [...allStrokes, activeStroke];
      setAllStrokes(updated);
      storage.saveAnnotation(sheetId, updated);
      setActiveStroke(null);
    }
  };

  const handleTextSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            points: [{ x: textInput.x, y: textInput.y }],
            color: selectedColor,
            width: selectedWidth,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const clearPageAnnotations = () => {
    const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex);
    setAllStrokes(updated);
    storage.saveAnnotation(sheetId, updated);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput) {
        setTimeout(() => textInputRef.current?.focus(), 50);
    }
  }, [textInput]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) return; // Don't turn page if typing
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (textInput) setTextInput(null);
          else if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-50' : ''
      };

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              return (
                  <text 
                    key={key}
                    x={x0}
                    y={y0}
                    fill={color}
                    fontSize={width * 5 + 12}
                    fontFamily="sans-serif"
                    fontWeight="bold"
                    className={isGhost ? 'opacity-50' : ''}
                  >
                      {text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>

                {/* Jump Dropdown Menu */}
                {showJumpDropdown && (
                    <div 
                        className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="flex items-center gap-2 mb-3 text-slate-400">
                            <BookOpen size={14} />
                            <span className="text-[10px] font-black uppercase tracking-widest">Go to page</span>
                        </div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input 
                                ref={jumpInputRef}
                                type="number"
                                min="1"
                                max={totalDisplayPages}
                                value={jumpInputValue}
                                onChange={e => setJumpInputValue(e.target.value)}
                                placeholder={`1-${totalDisplayPages}`}
                                className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500"
                            />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors">
                                <ArrowRight size={20} />
                            </button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      {/* Main Viewport */}
      <div 
        ref={containerRef} 
        className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} 
        onClick={handleContainerClick}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`}
            style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet && currentFile && !isPdf && (
            <img 
                src={URL.createObjectURL(currentFile.blob)} 
                className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none"
                alt="Sheet Page"
                onLoad={(e) => {
                    const img = e.target as HTMLImageElement;
                    setDimensions({ width: img.naturalWidth, height: img.naturalHeight });
                }}
            />
        )}

        {/* Annotations Overlay */}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => renderAnnotation(stroke, i))
                }
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}

        {/* Text Input Overlay */}
        {textInput && (
            <div className="absolute inset-0 z-[60] bg-black/20 flex items-center justify-center">
                <form 
                    onSubmit={handleTextSubmit} 
                    className="bg-slate-900 border border-white/20 p-4 rounded-2xl shadow-2xl w-full max-w-xs animate-in zoom-in-95 duration-200"
                    onClick={e => e.stopPropagation()}
                >
                    <div className="flex items-center gap-2 mb-3 text-slate-400">
                        <Type size={14} />
                        <span className="text-[10px] font-black uppercase tracking-widest">Add Note</span>
                    </div>
                    <input 
                        ref={textInputRef}
                        type="text"
                        placeholder="Type something..."
                        className="w-full bg-slate-800 border border-white/5 rounded-xl px-4 py-3 text-white font-medium outline-none focus:ring-2 focus:ring-blue-500 mb-4"
                        value={textInput.value}
                        onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                        onKeyDown={e => e.key === 'Escape' && setTextInput(null)}
                    />
                    <div className="flex gap-2">
                        <button type="button" onClick={() => setTextInput(null)} className="flex-1 py-2 text-slate-400 hover:text-white transition-colors text-xs font-bold uppercase tracking-widest">Cancel</button>
                        <button type="submit" className="flex-1 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold uppercase tracking-widest transition-all">Add</button>
                    </div>
                </form>
            </div>
        )}
      </div>

      {/* Drawing Toolbar (Bottom) */}
      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2 rounded-[2rem] shadow-2xl flex items-center gap-4 z-50 animate-in slide-in-from-bottom-4 duration-300 max-w-[95vw] overflow-x-auto no-scrollbar">

              {/* Tool Selector */}
              <div className="flex items-center bg-black/20 rounded-full p-1 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-2 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <PenTool size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('text')} className={`p-2 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Type size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-2 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Square size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-2 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Circle size={18} />
                  </button>
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Color Selector */}
              <div className="flex items-center gap-2 shrink-0">
                  {COLORS.map(c => (
                      <button 
                        key={c} 
                        onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`w-6 h-6 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-lg' : 'border-transparent scale-100 opacity-60'}`}
                        style={{ backgroundColor: c }}
                      />
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Stroke Width */}
              <div className="flex items-center gap-3 shrink-0">
                  {[2, 4, 8].map(w => (
                      <button 
                        key={w} 
                        onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}
                      >
                          <div className="rounded-full bg-current" style={{ width: w + 2, height: w + 2 }} />
                      </button>
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              <button onClick={clearPageAnnotations} className="p-2 text-slate-500 hover:text-red-400 transition-colors shrink-0" title="Clear Page">
                  <RotateCcw size={18} />
              </button>

              <button onClick={() => setIsAnnotating(false)} className="bg-white/10 hover:bg-white/20 text-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.15em] transition-all shrink-0 active:scale-95">
                  Done
              </button>
          </div>
      )}

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(3);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);

  // Inline Text Input State
  const [textInput, setTextInput] = useState<{ x: number, y: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const inlineTextRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;

    // If we're already typing somewhere else, finish that first
    if (textInput) {
        handleFinishText();
        return;
    }

    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    if (currentTool === 'text') {
        setTextInput({ x, y, value: '' });
        return;
    }

    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      type: currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (activeStroke) {
      const updated = [...allStrokes, activeStroke];
      setAllStrokes(updated);
      storage.saveAnnotation(sheetId, updated);
      setActiveStroke(null);
    }
  };

  const handleFinishText = () => {
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            points: [{ x: textInput.x, y: textInput.y }],
            color: selectedColor,
            width: selectedWidth,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const clearPageAnnotations = () => {
    const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex);
    setAllStrokes(updated);
    storage.saveAnnotation(sheetId, updated);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput && inlineTextRef.current) {
        inlineTextRef.current.focus();
    }
  }, [textInput]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) {
          if (e.key === 'Enter') handleFinishText();
          if (e.key === 'Escape') setTextInput(null);
          return;
      }
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-50' : ''
      };

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              return (
                  <text 
                    key={key}
                    x={x0}
                    y={y0}
                    fill={color}
                    fontSize={width * 5 + 12}
                    fontFamily="sans-serif"
                    fontWeight="bold"
                    className={isGhost ? 'opacity-50' : ''}
                  >
                      {text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>

                {/* Jump Dropdown Menu */}
                {showJumpDropdown && (
                    <div 
                        className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="flex items-center gap-2 mb-3 text-slate-400">
                            <BookOpen size={14} />
                            <span className="text-[10px] font-black uppercase tracking-widest">Go to page</span>
                        </div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input 
                                ref={jumpInputRef}
                                type="number"
                                min="1"
                                max={totalDisplayPages}
                                value={jumpInputValue}
                                onChange={e => setJumpInputValue(e.target.value)}
                                placeholder={`1-${totalDisplayPages}`}
                                className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500"
                            />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors">
                                <ArrowRight size={20} />
                            </button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      {/* Main Viewport */}
      <div 
        ref={containerRef} 
        className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} 
        onClick={handleContainerClick}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`}
            style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet && currentFile && !isPdf && (
            <img 
                src={URL.createObjectURL(currentFile.blob)} 
                className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none"
                alt="Sheet Page"
                onLoad={(e) => {
                    const img = e.target as HTMLImageElement;
                    setDimensions({ width: img.naturalWidth, height: img.naturalHeight });
                }}
            />
        )}

        {/* Annotations Overlay */}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => renderAnnotation(stroke, i))
                }
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}

        {/* Inline Text Input Overlay */}
        {textInput && (
            <div 
                className="absolute pointer-events-auto z-50 flex items-center"
                style={{ 
                    left: `${textInput.x * 100}%`, 
                    top: `${textInput.y * 100}%`,
                    transform: 'translateY(-50%)' 
                }}
                onClick={e => e.stopPropagation()}
            >
                <input 
                    ref={inlineTextRef}
                    type="text"
                    value={textInput.value}
                    onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                    onBlur={handleFinishText}
                    className="bg-slate-900/40 border-b-2 border-white/20 px-1 py-0.5 text-white font-bold outline-none shadow-xl focus:border-blue-500"
                    style={{ 
                        color: selectedColor,
                        fontSize: `${selectedWidth * 5 + 12}px`,
                        fontFamily: 'sans-serif'
                    }}
                />
            </div>
        )}
      </div>

      {/* Drawing Toolbar (Bottom) */}
      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2 rounded-[2rem] shadow-2xl flex items-center gap-4 z-50 animate-in slide-in-from-bottom-4 duration-300 max-w-[95vw] overflow-x-auto no-scrollbar">

              {/* Tool Selector */}
              <div className="flex items-center bg-black/20 rounded-full p-1 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-2 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <PenTool size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('text')} className={`p-2 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Type size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-2 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Square size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-2 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Circle size={18} />
                  </button>
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Color Selector */}
              <div className="flex items-center gap-2 shrink-0">
                  {COLORS.map(c => (
                      <button 
                        key={c} 
                        onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`w-6 h-6 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-lg' : 'border-transparent scale-100 opacity-60'}`}
                        style={{ backgroundColor: c }}
                      />
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Stroke Width */}
              <div className="flex items-center gap-3 shrink-0">
                  {[2, 4, 8].map(w => (
                      <button 
                        key={w} 
                        onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}
                      >
                          <div className="rounded-full bg-current" style={{ width: w + 2, height: w + 2 }} />
                      </button>
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              <button onClick={clearPageAnnotations} className="p-2 text-slate-500 hover:text-red-400 transition-colors shrink-0" title="Clear Page">
                  <RotateCcw size={18} />
              </button>

              <button onClick={() => setIsAnnotating(false)} className="bg-white/10 hover:bg-white/20 text-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.15em] transition-all shrink-0 active:scale-95">
                  Done
              </button>
          </div>
      )}

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(3);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);

  // Inline Text Input State
  const [textInput, setTextInput] = useState<{ x: number, y: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const inlineTextRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;

    // If we're already typing, tapping anywhere else will finish the current text
    if (textInput) {
        handleFinishText();
        return;
    }

    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    if (currentTool === 'text') {
        // Toggle input at location
        setTextInput({ x, y, value: '' });
        return;
    }

    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      type: currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (activeStroke) {
      const updated = [...allStrokes, activeStroke];
      setAllStrokes(updated);
      storage.saveAnnotation(sheetId, updated);
      setActiveStroke(null);
    }
  };

  const handleFinishText = () => {
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            points: [{ x: textInput.x, y: textInput.y }],
            color: selectedColor,
            width: selectedWidth,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const clearPageAnnotations = () => {
    const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex);
    setAllStrokes(updated);
    storage.saveAnnotation(sheetId, updated);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput && inlineTextRef.current) {
        // Ensure the input gets focused immediately when state changes
        inlineTextRef.current.focus();
    }
  }, [textInput]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) {
          if (e.key === 'Enter') {
              e.preventDefault();
              handleFinishText();
          }
          if (e.key === 'Escape') {
              setTextInput(null);
          }
          return;
      }
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-50' : ''
      };

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              return (
                  <text 
                    key={key}
                    x={x0}
                    y={y0}
                    fill={color}
                    fontSize={width * 5 + 12}
                    fontFamily="sans-serif"
                    fontWeight="bold"
                    dominantBaseline="middle"
                    className={isGhost ? 'opacity-50' : ''}
                  >
                      {text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>

                {/* Jump Dropdown Menu */}
                {showJumpDropdown && (
                    <div 
                        className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="flex items-center gap-2 mb-3 text-slate-400">
                            <BookOpen size={14} />
                            <span className="text-[10px] font-black uppercase tracking-widest">Go to page</span>
                        </div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input 
                                ref={jumpInputRef}
                                type="number"
                                min="1"
                                max={totalDisplayPages}
                                value={jumpInputValue}
                                onChange={e => setJumpInputValue(e.target.value)}
                                placeholder={`1-${totalDisplayPages}`}
                                className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500"
                            />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors">
                                <ArrowRight size={20} />
                            </button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      {/* Main Viewport */}
      <div 
        ref={containerRef} 
        className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} 
        onClick={handleContainerClick}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`}
            style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet && currentFile && !isPdf && (
            <img 
                src={URL.createObjectURL(currentFile.blob)} 
                className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none"
                alt="Sheet Page"
                onLoad={(e) => {
                    const img = e.target as HTMLImageElement;
                    setDimensions({ width: img.naturalWidth, height: img.naturalHeight });
                }}
            />
        )}

        {/* Annotations Overlay */}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => renderAnnotation(stroke, i))
                }
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}

        {/* Inline Text Input Overlay */}
        {textInput && (
            <div 
                className="absolute z-50 flex items-center pointer-events-auto"
                style={{ 
                    left: `${textInput.x * 100}%`, 
                    top: `${textInput.y * 100}%`,
                    transform: 'translateY(-50%)' 
                }}
                onPointerDown={e => e.stopPropagation()} // CRITICAL: Stop propagation to prevent handlePointerDown from firing
            >
                <input 
                    ref={inlineTextRef}
                    type="text"
                    value={textInput.value}
                    placeholder="Note..."
                    onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                    onBlur={handleFinishText}
                    className="bg-slate-900/60 border-2 border-blue-500/50 rounded px-2 py-1 text-white font-bold outline-none shadow-[0_0_15px_rgba(59,130,246,0.3)] min-w-[60px]"
                    style={{ 
                        color: selectedColor,
                        fontSize: `${selectedWidth * 5 + 14}px`,
                        fontFamily: 'sans-serif'
                    }}
                />
            </div>
        )}
      </div>

      {/* Drawing Toolbar (Bottom) */}
      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2 rounded-[2rem] shadow-2xl flex items-center gap-4 z-50 animate-in slide-in-from-bottom-4 duration-300 max-w-[95vw] overflow-x-auto no-scrollbar">

              {/* Tool Selector */}
              <div className="flex items-center bg-black/20 rounded-full p-1 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-2 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <PenTool size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('text')} className={`p-2 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Type size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-2 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Square size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-2 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Circle size={18} />
                  </button>
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Color Selector */}
              <div className="flex items-center gap-2 shrink-0">
                  {COLORS.map(c => (
                      <button 
                        key={c} 
                        onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`w-6 h-6 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-lg' : 'border-transparent scale-100 opacity-60'}`}
                        style={{ backgroundColor: c }}
                      />
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Stroke Width */}
              <div className="flex items-center gap-3 shrink-0">
                  {[2, 4, 8].map(w => (
                      <button 
                        key={w} 
                        onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}
                      >
                          <div className="rounded-full bg-current" style={{ width: w + 2, height: w + 2 }} />
                      </button>
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              <button onClick={clearPageAnnotations} className="p-2 text-slate-500 hover:text-red-400 transition-colors shrink-0" title="Clear Page">
                  <RotateCcw size={18} />
              </button>

              <button onClick={() => setIsAnnotating(false)} className="bg-white/10 hover:bg-white/20 text-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.15em] transition-all shrink-0 active:scale-95">
                  Done
              </button>
          </div>
      )}

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(3);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);

  // Inline Text Input State (x, y, w, h are normalized 0-1)
  const [textInput, setTextInput] = useState<{ x: number, y: number, w: number, h: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const inlineTextRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;

    // If typing, tap finishes previous note
    if (textInput) {
        handleFinishText();
        return;
    }

    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    // Both text and shapes start with a drag rectangle
    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      type: currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        // Shapes and text-selection-box use two points
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (!activeStroke) return;

    if (activeStroke.type === 'text') {
        // Special case for text: Trigger input instead of saving stroke immediately
        const p0 = activeStroke.points[0];
        const p1 = activeStroke.points[activeStroke.points.length - 1];

        const x = Math.min(p0.x, p1.x);
        const y = Math.min(p0.y, p1.y);
        const w = Math.max(0.05, Math.abs(p1.x - p0.x)); // Minimum width for visibility
        const h = Math.max(0.02, Math.abs(p1.y - p0.y)); // Minimum height for visibility

        setTextInput({ x, y, w, h, value: '' });
        setActiveStroke(null);
    } else {
        const updated = [...allStrokes, activeStroke];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
        setActiveStroke(null);
    }
  };

  const handleFinishText = () => {
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            // For text, we'll store start and end points to define the box
            points: [
                { x: textInput.x, y: textInput.y },
                { x: textInput.x + textInput.w, y: textInput.y + textInput.h }
            ],
            color: selectedColor,
            width: selectedWidth,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const clearPageAnnotations = () => {
    const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex);
    setAllStrokes(updated);
    storage.saveAnnotation(sheetId, updated);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput && inlineTextRef.current) {
        inlineTextRef.current.focus();
    }
  }, [textInput]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) {
          if (e.key === 'Enter') {
              e.preventDefault();
              handleFinishText();
          }
          if (e.key === 'Escape') {
              setTextInput(null);
          }
          return;
      }
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-40 stroke-dash-array' : ''
      };

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              // For text annotations, p0 is top-left, p1 is used for orientation/box if needed
              // But standard SVG text just needs the start point. 
              // We use dominantBaseline to ensure middle alignment if a box was drawn
              const boxHeight = Math.abs(y1 - y0);
              return (
                  <text 
                    key={key}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1) + (boxHeight / 2)}
                    fill={color}
                    fontSize={width * 5 + 14}
                    fontFamily="sans-serif"
                    fontWeight="bold"
                    dominantBaseline="middle"
                    className={isGhost ? 'opacity-30' : ''}
                  >
                      {isGhost ? 'TEXT BOX...' : text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>

                {/* Jump Dropdown Menu */}
                {showJumpDropdown && (
                    <div 
                        className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="flex items-center gap-2 mb-3 text-slate-400">
                            <BookOpen size={14} />
                            <span className="text-[10px] font-black uppercase tracking-widest">Go to page</span>
                        </div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input 
                                ref={jumpInputRef}
                                type="number"
                                min="1"
                                max={totalDisplayPages}
                                value={jumpInputValue}
                                onChange={e => setJumpInputValue(e.target.value)}
                                placeholder={`1-${totalDisplayPages}`}
                                className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500"
                            />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors">
                                <ArrowRight size={20} />
                            </button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      {/* Main Viewport */}
      <div 
        ref={containerRef} 
        className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} 
        onClick={handleContainerClick}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
      >
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}

        <canvas 
            ref={pdfCanvasRef} 
            className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`}
            style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }}
        />

        {!loading && sheet && currentFile && !isPdf && (
            <img 
                src={URL.createObjectURL(currentFile.blob)} 
                className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none"
                alt="Sheet Page"
                onLoad={(e) => {
                    const img = e.target as HTMLImageElement;
                    setDimensions({ width: img.naturalWidth, height: img.naturalHeight });
                }}
            />
        )}

        {/* Annotations Overlay */}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg 
                className="absolute inset-0 w-full h-full pointer-events-none z-10"
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                preserveAspectRatio="none"
            >
                {allStrokes
                    .filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex)
                    .map((stroke, i) => renderAnnotation(stroke, i))
                }
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}

        {/* Inline Text Input Overlay */}
        {textInput && (
            <div 
                className="absolute z-50 flex items-center pointer-events-auto"
                style={{ 
                    left: `${textInput.x * 100}%`, 
                    top: `${textInput.y * 100}%`,
                    width: `${textInput.w * 100}%`,
                    height: `${textInput.h * 100}%`,
                }}
                onPointerDown={e => e.stopPropagation()} 
            >
                <input 
                    ref={inlineTextRef}
                    type="text"
                    value={textInput.value}
                    placeholder="Type note..."
                    onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                    onBlur={handleFinishText}
                    className="w-full h-full bg-slate-900/80 border-2 border-blue-500/80 rounded px-2 text-white font-bold outline-none shadow-[0_0_20px_rgba(59,130,246,0.5)]"
                    style={{ 
                        color: selectedColor,
                        fontSize: `${selectedWidth * 5 + 14}px`,
                        fontFamily: 'sans-serif'
                    }}
                />
            </div>
        )}
      </div>

      {/* Drawing Toolbar (Bottom) */}
      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur-xl border border-white/10 p-2 rounded-[2rem] shadow-2xl flex items-center gap-4 z-50 animate-in slide-in-from-bottom-4 duration-300 max-w-[95vw] overflow-x-auto no-scrollbar">

              {/* Tool Selector */}
              <div className="flex items-center bg-black/20 rounded-full p-1 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-2 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <PenTool size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('text')} className={`p-2 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Type size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-2 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Square size={18} />
                  </button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-2 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}>
                      <Circle size={18} />
                  </button>
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Color Selector */}
              <div className="flex items-center gap-2 shrink-0">
                  {COLORS.map(c => (
                      <button 
                        key={c} 
                        onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`w-6 h-6 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-lg' : 'border-transparent scale-100 opacity-60'}`}
                        style={{ backgroundColor: c }}
                      />
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              {/* Stroke Width */}
              <div className="flex items-center gap-3 shrink-0">
                  {[2, 4, 8].map(w => (
                      <button 
                        key={w} 
                        onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }}
                        className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}
                      >
                          <div className="rounded-full bg-current" style={{ width: w + 2, height: w + 2 }} />
                      </button>
                  ))}
              </div>

              <div className="w-px h-6 bg-white/10 shrink-0" />

              <button onClick={clearPageAnnotations} className="p-2 text-slate-500 hover:text-red-400 transition-colors shrink-0" title="Clear Page">
                  <RotateCcw size={18} />
              </button>

              <button onClick={() => setIsAnnotating(false)} className="bg-white/10 hover:bg-white/20 text-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.15em] transition-all shrink-0 active:scale-95">
                  Done
              </button>
          </div>
      )}

      {/* Queue Sidebar */}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between">
                  <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3>
                  <button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button>
              </div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => { onJumpTo(idx); setShowQueue(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}
                      >
                          <span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span>
                          <span className="text-sm font-medium truncate flex-1">{item.name}</span>
                      </button>
                  ))}
              </div>
          </div>
      )}

      {/* Navigation Indicators */}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/40 backdrop-blur-md rounded-full text-[10px] font-black tracking-widest text-slate-400 border border-white/5 pointer-events-none z-30 uppercase shadow-xl">
               Piece {currentQueueIndex + 1} of {queue.length}
          </div>
      )}
    </div>
  );
};

export default Viewer;

export interface Point {
  x: number;
  y: number;
}

export type AnnotationType = 'path' | 'text' | 'rect' | 'circle';

export interface Stroke {
  id?: string;
  type?: AnnotationType;
  points: Point[];
  color: string;
  width: number;
  text?: string;
  fontFamily?: string;
  pageIndex: number; // For PDF: page number (0-based). For Images: 0.
  fileIndex?: number; // Index of the file in sheet.pages. Defaults to 0 if undefined.
}

export interface SheetPage {
  blob: Blob;
  fileType: 'image/png' | 'image/jpeg' | 'application/pdf';
}

export interface TagDef {
  label: string;
  iconName: string;
}

export interface Sheet {
  id: string;
  name: string;
  tags: string[]; 
  tagIcons?: Record<string, string>; // Map tag label to icon name (e.g. 'MyTag': 'Guitar')
  dateAdded: number;
  pages: SheetPage[]; // Replaced single blob with array of pages
  previewUrl?: string; // For images
}

export interface AnnotationLayer {
  sheetId: string;
  strokes: Stroke[];
}

export interface Setlist {
  id: string;
  name: string;
  sheetIds: string[]; // Ordered list of sheet IDs
  dateCreated: number;
}

export enum AppView {
  LIBRARY = 'LIBRARY',
  SETLISTS = 'SETLISTS',
  VIEWER = 'VIEWER',
}

export interface ViewerState {
  activeSetlistId: string | null; // null if viewing single file from library
  queue: string[]; // Sheet IDs in order
  currentIndex: number;
}

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle, Italic, Type as TypeIcon } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const FONTS = [
    { label: 'Sans', value: 'sans-serif' },
    { label: 'Serif', value: 'serif' },
    { label: 'Mono', value: 'monospace' }
];

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(4);
  const [selectedFont, setSelectedFont] = useState(FONTS[0].value);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);

  // Inline Text Input State (x, y, w, h are normalized 0-1)
  const [textInput, setTextInput] = useState<{ x: number, y: number, w: number, h: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const inlineTextRef = useRef<HTMLTextAreaElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;

    // If typing, tap finishes previous note
    if (textInput) {
        handleFinishText();
        return;
    }

    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      type: currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fontFamily: selectedFont,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (!activeStroke) return;

    if (activeStroke.type === 'text') {
        const p0 = activeStroke.points[0];
        const p1 = activeStroke.points[activeStroke.points.length - 1];

        const x = Math.min(p0.x, p1.x);
        const y = Math.min(p0.y, p1.y);
        const w = Math.max(0.02, Math.abs(p1.x - p0.x));
        const h = Math.max(0.015, Math.abs(p1.y - p0.y));

        setTextInput({ x, y, w, h, value: '' });
        setActiveStroke(null);
    } else {
        const updated = [...allStrokes, activeStroke];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
        setActiveStroke(null);
    }
  };

  const handleFinishText = () => {
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            points: [
                { x: textInput.x, y: textInput.y },
                { x: textInput.x + textInput.w, y: textInput.y + textInput.h }
            ],
            color: selectedColor,
            width: selectedWidth,
            fontFamily: selectedFont,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput && inlineTextRef.current) {
        inlineTextRef.current.focus();
    }
  }, [textInput]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) {
          if (e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              handleFinishText();
          }
          if (e.key === 'Escape') {
              setTextInput(null);
          }
          return;
      }
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text, fontFamily } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-50' : ''
      };

      if (isGhost && type === 'text') {
        // User requested a rectangle ghost instead of text preview during dragging
        return (
            <rect 
                key={key}
                x={Math.min(x0, x1)}
                y={Math.min(y0, y1)}
                width={Math.max(2, Math.abs(x1 - x0))}
                height={Math.max(2, Math.abs(y1 - y0))}
                stroke={color}
                strokeWidth={2}
                fill={`${color}22`}
                strokeDasharray="5,5"
                className="opacity-60"
            />
        );
      }

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              const actualFontSize = width * 5 + 14;
              return (
                  <text 
                    key={key}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1) + (actualFontSize * 0.8)}
                    fill={color}
                    fontSize={actualFontSize}
                    fontFamily={fontFamily || 'sans-serif'}
                    fontWeight="bold"
                    className={isGhost ? 'opacity-30' : ''}
                  >
                      {text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>
                {showJumpDropdown && (
                    <div className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center gap-2 mb-3 text-slate-400"><BookOpen size={14} /><span className="text-[10px] font-black uppercase tracking-widest">Go to page</span></div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input ref={jumpInputRef} type="number" min="1" max={totalDisplayPages} value={jumpInputValue} onChange={e => setJumpInputValue(e.target.value)} placeholder={`1-${totalDisplayPages}`} className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500" />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors"><ArrowRight size={20} /></button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      <div ref={containerRef} className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} onClick={handleContainerClick} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}>
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}
        <canvas ref={pdfCanvasRef} className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`} style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }} />
        {!loading && sheet && currentFile && !isPdf && (
            <img src={URL.createObjectURL(currentFile.blob)} className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none" alt="Sheet Page" onLoad={(e) => { const img = e.target as HTMLImageElement; setDimensions({ width: img.naturalWidth, height: img.naturalHeight }); }} />
        )}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg className="absolute inset-0 w-full h-full pointer-events-none z-10" viewBox={`0 0 ${dimensions.width} ${dimensions.height}`} preserveAspectRatio="none">
                {allStrokes.filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex).map((stroke, i) => renderAnnotation(stroke, i))}
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}
        {textInput && (
            <div className="absolute z-50 flex items-center pointer-events-auto" style={{ left: `${textInput.x * 100}%`, top: `${textInput.y * 100}%`, width: `${textInput.w * 100}%`, height: `${textInput.h * 100}%` }} onPointerDown={e => e.stopPropagation()}>
                <textarea 
                    ref={inlineTextRef}
                    value={textInput.value}
                    placeholder="Note..."
                    onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                    onBlur={handleFinishText}
                    className="w-full h-full bg-slate-900/90 border-2 border-blue-500 rounded px-2 py-1 text-white font-bold outline-none shadow-2xl resize-none overflow-hidden"
                    style={{ 
                        color: selectedColor,
                        fontSize: `${selectedWidth * 5 + 14}px`,
                        fontFamily: selectedFont
                    }}
                />
            </div>
        )}
      </div>

      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/95 backdrop-blur-2xl border border-white/10 p-3 rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] flex items-center gap-4 z-50 animate-in slide-in-from-bottom-6 duration-300 max-w-[98vw] overflow-x-auto no-scrollbar">
              <div className="flex items-center bg-black/40 rounded-full p-1 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-2.5 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><PenTool size={18} /></button>
                  <button onClick={() => setCurrentTool('text')} className={`p-2.5 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Type size={18} /></button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-2.5 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Square size={18} /></button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-2.5 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Circle size={18} /></button>
              </div>
              <div className="w-px h-8 bg-white/10 shrink-0" />
              <div className="flex items-center gap-2 shrink-0">
                  {COLORS.map(c => (
                      <button key={c} onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }} className={`w-7 h-7 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-xl' : 'border-transparent scale-100 opacity-50'}`} style={{ backgroundColor: c }} />
                  ))}
              </div>
              <div className="w-px h-8 bg-white/10 shrink-0" />
              <div className="flex items-center gap-3 shrink-0">
                  {[3, 6, 12].map(w => (
                      <button key={w} onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }} className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}>
                          <div className="rounded-full bg-current" style={{ width: w + 2, height: w + 2 }} />
                      </button>
                  ))}
              </div>
              {currentTool === 'text' && (
                  <>
                    <div className="w-px h-8 bg-white/10 shrink-0" />
                    <div className="flex items-center bg-black/40 rounded-full p-1 shrink-0">
                        {FONTS.map(f => (
                            <button key={f.value} onClick={() => setSelectedFont(f.value)} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase transition-all ${selectedFont === f.value ? 'bg-blue-600 text-white' : 'text-slate-500'}`} style={{ fontFamily: f.value }}>{f.label}</button>
                        ))}
                    </div>
                  </>
              )}
              <div className="w-px h-8 bg-white/10 shrink-0" />
              <button onClick={() => { const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex); setAllStrokes(updated); storage.saveAnnotation(sheetId, updated); }} className="p-2.5 text-slate-500 hover:text-red-400 transition-colors shrink-0"><RotateCcw size={18} /></button>
              <button onClick={() => setIsAnnotating(false)} className="bg-white/10 hover:bg-blue-600 text-white px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] transition-all shrink-0 active:scale-95">Done</button>
          </div>
      )}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between"><h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3><button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button></div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button key={idx} onClick={() => { onJumpTo(idx); setShowQueue(false); }} className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}><span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span><span className="text-sm font-medium truncate flex-1">{item.name}</span></button>
                  ))}
              </div>
          </div>
      )}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur-md rounded-full text-[10px] font-black tracking-[0.2em] text-slate-400 border border-white/10 pointer-events-none z-30 uppercase shadow-2xl">Piece {currentQueueIndex + 1} of {queue.length}</div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle, Italic, Type as TypeIcon } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const FONTS = [
    { label: 'Sans', value: 'sans-serif' },
    { label: 'Serif', value: 'serif' },
    { label: 'Mono', value: 'monospace' }
];

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(6);
  const [selectedFont, setSelectedFont] = useState(FONTS[0].value);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);

  // Inline Text Input State (x, y, w, h are normalized 0-1)
  const [textInput, setTextInput] = useState<{ x: number, y: number, w: number, h: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [displayScale, setDisplayScale] = useState(1);

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const inlineTextRef = useRef<HTMLTextAreaElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  // Unified font size logic
  const getNaturalFontSize = (width: number) => width * 6 + 10;

  // Calculate the scale between screen pixels and natural SVG coordinates
  const updateDisplayScale = useCallback(() => {
    const element = isPdf ? pdfCanvasRef.current : imageRef.current;
    if (element && dimensions.width > 0) {
      const rect = element.getBoundingClientRect();
      setDisplayScale(rect.width / dimensions.width);
    }
  }, [isPdf, dimensions.width]);

  useLayoutEffect(() => {
    window.addEventListener('resize', updateDisplayScale);
    return () => window.removeEventListener('resize', updateDisplayScale);
  }, [updateDisplayScale]);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
                setTimeout(updateDisplayScale, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                    setTimeout(updateDisplayScale, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc, updateDisplayScale]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;
    if (textInput) {
        handleFinishText();
        return;
    }

    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      type: currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fontFamily: selectedFont,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (!activeStroke) return;

    if (activeStroke.type === 'text') {
        const p0 = activeStroke.points[0];
        const p1 = activeStroke.points[activeStroke.points.length - 1];

        const x = Math.min(p0.x, p1.x);
        const y = Math.min(p0.y, p1.y);
        const w = Math.max(0.02, Math.abs(p1.x - p0.x));
        const h = Math.max(0.015, Math.abs(p1.y - p0.y));

        updateDisplayScale();
        setTextInput({ x, y, w, h, value: '' });
        setActiveStroke(null);
    } else {
        const updated = [...allStrokes, activeStroke];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
        setActiveStroke(null);
    }
  };

  const handleFinishText = () => {
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            points: [
                { x: textInput.x, y: textInput.y },
                { x: textInput.x + textInput.w, y: textInput.y + textInput.h }
            ],
            color: selectedColor,
            width: selectedWidth,
            fontFamily: selectedFont,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput && inlineTextRef.current) {
        inlineTextRef.current.focus();
    }
  }, [textInput]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) {
          if (e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              handleFinishText();
          }
          if (e.key === 'Escape') {
              setTextInput(null);
          }
          return;
      }
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text, fontFamily } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-50' : ''
      };

      if (isGhost && type === 'text') {
        return (
            <rect 
                key={key}
                x={Math.min(x0, x1)}
                y={Math.min(y0, y1)}
                width={Math.max(2, Math.abs(x1 - x0))}
                height={Math.max(2, Math.abs(y1 - y0))}
                stroke={color}
                strokeWidth={2}
                fill={`${color}22`}
                strokeDasharray="5,5"
                className="opacity-60"
            />
        );
      }

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              const fs = getNaturalFontSize(width);
              return (
                  <text 
                    key={key}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1) + (fs * 0.8)}
                    fill={color}
                    fontSize={fs}
                    fontFamily={fontFamily || 'sans-serif'}
                    fontWeight="bold"
                    className={isGhost ? 'opacity-30' : ''}
                  >
                      {text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>
                {showJumpDropdown && (
                    <div className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center gap-2 mb-3 text-slate-400"><BookOpen size={14} /><span className="text-[10px] font-black uppercase tracking-widest">Go to page</span></div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input ref={jumpInputRef} type="number" min="1" max={totalDisplayPages} value={jumpInputValue} onChange={e => setJumpInputValue(e.target.value)} placeholder={`1-${totalDisplayPages}`} className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500" />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors"><ArrowRight size={20} /></button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      <div ref={containerRef} className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} onClick={handleContainerClick} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}>
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}
        <canvas ref={pdfCanvasRef} className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`} style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }} />
        {!loading && sheet && currentFile && !isPdf && (
            <img ref={imageRef} src={URL.createObjectURL(currentFile.blob)} className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none" alt="Sheet Page" onLoad={(e) => { const img = e.target as HTMLImageElement; setDimensions({ width: img.naturalWidth, height: img.naturalHeight }); setTimeout(updateDisplayScale, 100); }} />
        )}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg className="absolute inset-0 w-full h-full pointer-events-none z-10" viewBox={`0 0 ${dimensions.width} ${dimensions.height}`} preserveAspectRatio="none">
                {allStrokes.filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex).map((stroke, i) => renderAnnotation(stroke, i))}
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}
        {textInput && (
            <div className="absolute z-50 flex items-center pointer-events-auto" style={{ left: `${textInput.x * 100}%`, top: `${textInput.y * 100}%`, width: `${textInput.w * 100}%`, height: `${textInput.h * 100}%` }} onPointerDown={e => e.stopPropagation()}>
                <textarea 
                    ref={inlineTextRef}
                    value={textInput.value}
                    onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                    onBlur={handleFinishText}
                    className="w-full h-full bg-slate-900/90 border-2 border-blue-500 rounded px-2 py-1 text-white font-bold outline-none shadow-2xl resize-none overflow-hidden"
                    style={{ 
                        color: selectedColor,
                        fontSize: `${getNaturalFontSize(selectedWidth) * displayScale}px`,
                        fontFamily: selectedFont,
                        lineHeight: '1.2'
                    }}
                />
            </div>
        )}
      </div>

      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/95 backdrop-blur-2xl border border-white/10 p-3 rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] flex items-center gap-4 z-50 animate-in slide-in-from-bottom-6 duration-300 max-w-[98vw] overflow-x-auto no-scrollbar">
              <div className="flex items-center bg-black/40 rounded-full p-1 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-2.5 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><PenTool size={18} /></button>
                  <button onClick={() => setCurrentTool('text')} className={`p-2.5 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Type size={18} /></button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-2.5 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Square size={18} /></button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-2.5 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Circle size={18} /></button>
              </div>
              <div className="w-px h-8 bg-white/10 shrink-0" />
              <div className="flex items-center gap-2 shrink-0">
                  {COLORS.map(c => (
                      <button key={c} onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }} className={`w-7 h-7 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-xl' : 'border-transparent scale-100 opacity-50'}`} style={{ backgroundColor: c }} />
                  ))}
              </div>
              <div className="w-px h-8 bg-white/10 shrink-0" />
              <div className="flex items-center gap-3 shrink-0">
                  {[3, 6, 12].map(w => (
                      <button key={w} onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }} className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}>
                          <div className="rounded-full bg-current" style={{ width: w + 2, height: w + 2 }} />
                      </button>
                  ))}
              </div>
              {currentTool === 'text' && (
                  <>
                    <div className="w-px h-8 bg-white/10 shrink-0" />
                    <div className="flex items-center bg-black/40 rounded-full p-1 shrink-0">
                        {FONTS.map(f => (
                            <button key={f.value} onClick={() => setSelectedFont(f.value)} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase transition-all ${selectedFont === f.value ? 'bg-blue-600 text-white' : 'text-slate-500'}`} style={{ fontFamily: f.value }}>{f.label}</button>
                        ))}
                    </div>
                  </>
              )}
              <div className="w-px h-8 bg-white/10 shrink-0" />
              <button onClick={() => { const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex); setAllStrokes(updated); storage.saveAnnotation(sheetId, updated); }} className="p-2.5 text-slate-500 hover:text-red-400 transition-colors shrink-0"><RotateCcw size={18} /></button>
              <button onClick={() => setIsAnnotating(false)} className="bg-white/10 hover:bg-blue-600 text-white px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] transition-all shrink-0 active:scale-95">Done</button>
          </div>
      )}
      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between"><h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3><button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button></div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button key={idx} onClick={() => { onJumpTo(idx); setShowQueue(false); }} className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}><span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span><span className="text-sm font-medium truncate flex-1">{item.name}</span></button>
                  ))}
              </div>
          </div>
      )}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur-md rounded-full text-[10px] font-black tracking-[0.2em] text-slate-400 border border-white/10 pointer-events-none z-30 uppercase shadow-2xl">Piece {currentQueueIndex + 1} of {queue.length}</div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle, Search, Check, ChevronUp } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const FONTS = [
    { label: 'Standard Sans', value: 'sans-serif' },
    { label: 'Classic Serif', value: 'serif' },
    { label: 'Typewriter Mono', value: 'monospace' },
    { label: 'Handwritten', value: 'cursive' },
    { label: 'Decorative', value: 'fantasy' },
    { label: 'System Native', value: 'system-ui' }
];

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(6);
  const [selectedFont, setSelectedFont] = useState(FONTS[0].value);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);

  // Font Search State
  const [showFontPicker, setShowFontPicker] = useState(false);
  const [fontSearchQuery, setFontSearchQuery] = useState('');

  // Inline Text Input State (x, y, w, h are normalized 0-1)
  const [textInput, setTextInput] = useState<{ x: number, y: number, w: number, h: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [displayScale, setDisplayScale] = useState(1);

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const inlineTextRef = useRef<HTMLTextAreaElement>(null);
  const fontSearchInputRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  // Unified font size logic
  const getNaturalFontSize = (width: number) => width * 6 + 10;

  // Calculate the scale between screen pixels and natural SVG coordinates
  const updateDisplayScale = useCallback(() => {
    const element = isPdf ? pdfCanvasRef.current : imageRef.current;
    if (element && dimensions.width > 0) {
      const rect = element.getBoundingClientRect();
      setDisplayScale(rect.width / dimensions.width);
    }
  }, [isPdf, dimensions.width]);

  useLayoutEffect(() => {
    window.addEventListener('resize', updateDisplayScale);
    return () => window.removeEventListener('resize', updateDisplayScale);
  }, [updateDisplayScale]);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
                setTimeout(updateDisplayScale, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                    setTimeout(updateDisplayScale, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc, updateDisplayScale]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;
    if (textInput) {
        handleFinishText();
        return;
    }

    // Close font picker if clicking outside
    if (showFontPicker) {
        setShowFontPicker(false);
        return;
    }

    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      type: currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fontFamily: selectedFont,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (!activeStroke) return;

    if (activeStroke.type === 'text') {
        const p0 = activeStroke.points[0];
        const p1 = activeStroke.points[activeStroke.points.length - 1];

        const x = Math.min(p0.x, p1.x);
        const y = Math.min(p0.y, p1.y);
        const w = Math.max(0.02, Math.abs(p1.x - p0.x));
        const h = Math.max(0.015, Math.abs(p1.y - p0.y));

        updateDisplayScale();
        setTextInput({ x, y, w, h, value: '' });
        setActiveStroke(null);
    } else {
        const updated = [...allStrokes, activeStroke];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
        setActiveStroke(null);
    }
  };

  const handleFinishText = () => {
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            points: [
                { x: textInput.x, y: textInput.y },
                { x: textInput.x + textInput.w, y: textInput.y + textInput.h }
            ],
            color: selectedColor,
            width: selectedWidth,
            fontFamily: selectedFont,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput && inlineTextRef.current) {
        inlineTextRef.current.focus();
    }
  }, [textInput]);

  useEffect(() => {
    if (showFontPicker && fontSearchInputRef.current) {
        fontSearchInputRef.current.focus();
    }
  }, [showFontPicker]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) {
          if (e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              handleFinishText();
          }
          if (e.key === 'Escape') {
              setTextInput(null);
          }
          return;
      }
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else if (showFontPicker) setShowFontPicker(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput, showFontPicker]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput || showFontPicker) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        if (showFontPicker) setShowFontPicker(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const filteredFonts = FONTS.filter(f => 
    f.label.toLowerCase().includes(fontSearchQuery.toLowerCase())
  );

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text, fontFamily } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-50' : ''
      };

      if (isGhost && type === 'text') {
        return (
            <rect 
                key={key}
                x={Math.min(x0, x1)}
                y={Math.min(y0, y1)}
                width={Math.max(2, Math.abs(x1 - x0))}
                height={Math.max(2, Math.abs(y1 - y0))}
                stroke={color}
                strokeWidth={2}
                fill={`${color}22`}
                strokeDasharray="5,5"
                className="opacity-60"
            />
        );
      }

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              const fs = getNaturalFontSize(width);
              return (
                  <text 
                    key={key}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1) + (fs * 0.8)}
                    fill={color}
                    fontSize={fs}
                    fontFamily={fontFamily || 'sans-serif'}
                    fontWeight="bold"
                    className={isGhost ? 'opacity-30' : ''}
                  >
                      {text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>
                {showJumpDropdown && (
                    <div className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center gap-2 mb-3 text-slate-400"><BookOpen size={14} /><span className="text-[10px] font-black uppercase tracking-widest">Go to page</span></div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input ref={jumpInputRef} type="number" min="1" max={totalDisplayPages} value={jumpInputValue} onChange={e => setJumpInputValue(e.target.value)} placeholder={`1-${totalDisplayPages}`} className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500" />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors"><ArrowRight size={20} /></button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      <div ref={containerRef} className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} onClick={handleContainerClick} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}>
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}
        <canvas ref={pdfCanvasRef} className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`} style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }} />
        {!loading && sheet && currentFile && !isPdf && (
            <img ref={imageRef} src={URL.createObjectURL(currentFile.blob)} className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none" alt="Sheet Page" onLoad={(e) => { const img = e.target as HTMLImageElement; setDimensions({ width: img.naturalWidth, height: img.naturalHeight }); setTimeout(updateDisplayScale, 100); }} />
        )}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg className="absolute inset-0 w-full h-full pointer-events-none z-10" viewBox={`0 0 ${dimensions.width} ${dimensions.height}`} preserveAspectRatio="none">
                {allStrokes.filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex).map((stroke, i) => renderAnnotation(stroke, i))}
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}
        {textInput && (
            <div className="absolute z-50 flex items-center pointer-events-auto" style={{ left: `${textInput.x * 100}%`, top: `${textInput.y * 100}%`, width: `${textInput.w * 100}%`, height: `${textInput.h * 100}%` }} onPointerDown={e => e.stopPropagation()}>
                <textarea 
                    ref={inlineTextRef}
                    value={textInput.value}
                    onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                    onBlur={handleFinishText}
                    className="w-full h-full bg-slate-900/90 border-2 border-blue-500 rounded px-2 py-1 text-white font-bold outline-none shadow-2xl resize-none overflow-hidden"
                    style={{ 
                        color: selectedColor,
                        fontSize: `${getNaturalFontSize(selectedWidth) * displayScale}px`,
                        fontFamily: selectedFont,
                        lineHeight: '1.2'
                    }}
                />
            </div>
        )}
      </div>

      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/95 backdrop-blur-2xl border border-white/10 p-3 rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] flex items-center gap-4 z-50 animate-in slide-in-from-bottom-6 duration-300 max-w-[98vw] overflow-x-auto no-scrollbar relative">

              {/* Tool Selection */}
              <div className="flex items-center bg-black/40 rounded-full p-1 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-2.5 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><PenTool size={18} /></button>
                  <button onClick={() => setCurrentTool('text')} className={`p-2.5 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Type size={18} /></button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-2.5 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Square size={18} /></button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-2.5 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Circle size={18} /></button>
              </div>

              <div className="w-px h-8 bg-white/10 shrink-0" />

              {/* Color Selection */}
              <div className="flex items-center gap-2 shrink-0">
                  {COLORS.map(c => (
                      <button key={c} onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }} className={`w-7 h-7 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-xl' : 'border-transparent scale-100 opacity-50'}`} style={{ backgroundColor: c }} />
                  ))}
              </div>

              <div className="w-px h-8 bg-white/10 shrink-0" />

              {/* Stroke Width Selection */}
              <div className="flex items-center gap-3 shrink-0">
                  {[3, 6, 12].map(w => (
                      <button key={w} onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }} className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}>
                          <div className="rounded-full bg-current" style={{ width: w + 2, height: w + 2 }} />
                      </button>
                  ))}
              </div>

              {/* Font Picker Dropdown Trigger */}
              {currentTool === 'text' && (
                  <>
                    <div className="w-px h-8 bg-white/10 shrink-0" />
                    <div className="relative shrink-0">
                        <button 
                            onClick={(e) => { e.stopPropagation(); setShowFontPicker(!showFontPicker); }}
                            className={`flex items-center gap-2 px-4 py-2 rounded-full border transition-all ${showFontPicker ? 'bg-blue-600 text-white border-blue-500' : 'bg-black/40 text-slate-400 border-white/10'}`}
                        >
                            <span className="text-[10px] font-black uppercase truncate max-w-[80px]" style={{ fontFamily: selectedFont }}>
                                {FONTS.find(f => f.value === selectedFont)?.label || 'Font'}
                            </span>
                            {showFontPicker ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                        </button>

                        {/* Searchable Font Picker Dropdown */}
                        {showFontPicker && (
                            <div 
                                className="absolute bottom-full left-0 mb-4 w-64 bg-slate-900/98 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-[0_25px_50px_-12px_rgba(0,0,0,0.8)] overflow-hidden animate-in slide-in-from-bottom-2 duration-200"
                                onClick={e => e.stopPropagation()}
                            >
                                <div className="p-3 border-b border-white/5 relative">
                                    <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-500" size={14} />
                                    <input 
                                        ref={fontSearchInputRef}
                                        type="text" 
                                        placeholder="Search fonts..."
                                        className="w-full bg-black/30 border border-white/10 rounded-xl pl-9 pr-3 py-2 text-xs text-white outline-none focus:ring-1 focus:ring-blue-500"
                                        value={fontSearchQuery}
                                        onChange={e => setFontSearchQuery(e.target.value)}
                                    />
                                </div>
                                <div className="max-h-56 overflow-y-auto py-2 no-scrollbar">
                                    {filteredFonts.length > 0 ? (
                                        filteredFonts.map(f => (
                                            <button 
                                                key={f.value}
                                                onClick={() => { setSelectedFont(f.value); setShowFontPicker(false); setFontSearchQuery(''); }}
                                                className={`w-full flex items-center justify-between px-4 py-3 hover:bg-white/5 transition-colors text-left ${selectedFont === f.value ? 'text-blue-400' : 'text-slate-300'}`}
                                            >
                                                <span className="text-sm font-medium" style={{ fontFamily: f.value }}>{f.label}</span>
                                                {selectedFont === f.value && <Check size={14} />}
                                            </button>
                                        ))
                                    ) : (
                                        <div className="px-4 py-8 text-center text-slate-500 text-xs italic">No fonts found</div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                  </>
              )}

              <div className="w-px h-8 bg-white/10 shrink-0" />

              <button onClick={() => { const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex); setAllStrokes(updated); storage.saveAnnotation(sheetId, updated); }} className="p-2.5 text-slate-500 hover:text-red-400 transition-colors shrink-0" title="Clear Page"><RotateCcw size={18} /></button>

              <button onClick={() => { setIsAnnotating(false); setShowFontPicker(false); }} className="bg-white/10 hover:bg-blue-600 text-white px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] transition-all shrink-0 active:scale-95">Done</button>
          </div>
      )}

      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between"><h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3><button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button></div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button key={idx} onClick={() => { onJumpTo(idx); setShowQueue(false); }} className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}><span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span><span className="text-sm font-medium truncate flex-1">{item.name}</span></button>
                  ))}
              </div>
          </div>
      )}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur-md rounded-full text-[10px] font-black tracking-[0.2em] text-slate-400 border border-white/10 pointer-events-none z-30 uppercase shadow-2xl">Piece {currentQueueIndex + 1} of {queue.length}</div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useEffect, useRef, useCallback, useLayoutEffect } from 'react';
import { PenTool, Eraser, X, Loader2, List, ChevronRight, ChevronLeft, Hash, ArrowRight, ChevronDown, BookOpen, RotateCcw, Type, Square, Circle, Search, Check, ChevronUp } from 'lucide-react';
import { Stroke, Point, Sheet, AnnotationType } from '../types';
import { storage } from '../services/storage';
import { COLORS, PAGE_TURN_KEYS } from '../constants';
import * as pdfjsLib from 'pdfjs-dist';

// Handle ESM default export wrapping from CDNs
const pdfjs: any = (pdfjsLib as any).default || pdfjsLib;

// Configure worker immediately
if (pdfjs && pdfjs.GlobalWorkerOptions) {
    pdfjs.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const FONTS = [
    { label: 'Standard Sans', value: 'sans-serif' },
    { label: 'Classic Serif', value: 'serif' },
    { label: 'Typewriter Mono', value: 'monospace' },
    { label: 'Handwritten', value: 'cursive' },
    { label: 'Decorative', value: 'fantasy' },
    { label: 'System Native', value: 'system-ui' }
];

interface ViewerProps {
  sheetId: string;
  title: string;
  onClose: () => void;
  onNext: () => void;
  onPrev: () => void;
  hasNext: boolean;
  hasPrev: boolean;
  queue: { id: string; name: string }[];
  currentQueueIndex: number;
  onJumpTo: (index: number) => void;
  initialDirection: 'forward' | 'backward';
}

const Viewer: React.FC<ViewerProps> = ({
  sheetId,
  title,
  onClose,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  queue,
  currentQueueIndex,
  onJumpTo,
  initialDirection
}) => {
  const [sheet, setSheet] = useState<Sheet | null>(null);
  const [activeFileIndex, setActiveFileIndex] = useState(0);
  const [subPageIndex, setSubPageIndex] = useState(0);
  const [numSubPages, setNumSubPages] = useState(0);
  const [loading, setLoading] = useState(true);

  // Annotation State
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationType | 'eraser'>('path');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);
  const [selectedWidth, setSelectedWidth] = useState(6);
  const [selectedFont, setSelectedFont] = useState(FONTS[0].value);
  const [allStrokes, setAllStrokes] = useState<Stroke[]>([]);
  const [activeStroke, setActiveStroke] = useState<Stroke | null>(null);

  // Font Search State
  const [showFontPicker, setShowFontPicker] = useState(false);
  const [fontSearchQuery, setFontSearchQuery] = useState('');

  // Inline Text Input State (x, y, w, h are normalized 0-1)
  const [textInput, setTextInput] = useState<{ x: number, y: number, w: number, h: number, value: string } | null>(null);

  // UI State
  const [showControls, setShowControls] = useState(true);
  const [showQueue, setShowQueue] = useState(false);
  const [showJumpDropdown, setShowJumpDropdown] = useState(false);
  const [jumpInputValue, setJumpInputValue] = useState('');
  const [dimensions, setDimensions] = useState({ width: 1000, height: 1400 });
  const [displayScale, setDisplayScale] = useState(1);

  // Stability Refs
  const pdfDocCache = useRef<Map<number, any>>(new Map());
  const canvasCache = useRef<Map<string, HTMLCanvasElement>>(new Map());
  const renderTasks = useRef<Map<string, any>>(new Map());
  const containerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);
  const imageRef = useRef<HTMLImageElement>(null);
  const jumpInputRef = useRef<HTMLInputElement>(null);
  const inlineTextRef = useRef<HTMLTextAreaElement>(null);
  const fontSearchInputRef = useRef<HTMLInputElement>(null);

  const currentViewRef = useRef<{ sheetId: string; fileIndex: number; pageIndex: number }>({
    sheetId,
    fileIndex: 0,
    pageIndex: initialDirection === 'backward' ? -1 : 0
  });

  // Derived Values for UI
  const currentFile = sheet?.pages?.[activeFileIndex];
  const isPdf = currentFile?.fileType === 'application/pdf';
  const totalDisplayPages = isPdf ? numSubPages : (sheet?.pages?.length || 0);
  const currentDisplayPage = isPdf ? (Math.max(0, subPageIndex) + 1) : (activeFileIndex + 1);

  // Unified font size logic
  const getNaturalFontSize = (width: number) => width * 6 + 10;

  // Calculate the scale between screen pixels and natural SVG coordinates
  const updateDisplayScale = useCallback(() => {
    const element = isPdf ? pdfCanvasRef.current : imageRef.current;
    if (element && dimensions.width > 0) {
      const rect = element.getBoundingClientRect();
      setDisplayScale(rect.width / dimensions.width);
    }
  }, [isPdf, dimensions.width]);

  useLayoutEffect(() => {
    window.addEventListener('resize', updateDisplayScale);
    return () => window.removeEventListener('resize', updateDisplayScale);
  }, [updateDisplayScale]);

  useLayoutEffect(() => {
    setLoading(true);
    setSheet(null);
    setNumSubPages(0);
    setActiveFileIndex(0);
    setSubPageIndex(initialDirection === 'backward' ? -1 : 0);

    pdfDocCache.current.clear();
    canvasCache.current.clear();
    renderTasks.current.forEach(task => { try { task.cancel(); } catch(e) {} });
    renderTasks.current.clear();

    const ctx = pdfCanvasRef.current?.getContext('2d');
    if (ctx && pdfCanvasRef.current) {
        ctx.clearRect(0, 0, pdfCanvasRef.current.width, pdfCanvasRef.current.height);
    }

    currentViewRef.current = {
      sheetId,
      fileIndex: 0,
      pageIndex: initialDirection === 'backward' ? -1 : 0
    };
  }, [sheetId, initialDirection]);

  useEffect(() => {
    let active = true;
    const load = async () => {
      try {
        const loaded = await storage.getSheet(sheetId);
        if (!active || sheetId !== currentViewRef.current.sheetId) return;

        if (loaded) {
          const targetFileIdx = initialDirection === 'backward' ? Math.max(0, loaded.pages.length - 1) : 0;
          currentViewRef.current.fileIndex = targetFileIdx;
          setActiveFileIndex(targetFileIdx);
          setSheet(loaded);

          const annotations = await storage.getAnnotation(sheetId);
          if (active && sheetId === currentViewRef.current.sheetId) {
            setAllStrokes(annotations?.strokes || []);
          }
        } else {
           onClose();
        }
      } catch (err) {
        console.error("Load error", err);
      }
    };
    load();
    return () => { active = false; };
  }, [sheetId, initialDirection, onClose]);

  const getPdfDoc = useCallback(async (fileIdx: number) => {
    if (!sheet || !sheet.pages || !sheet.pages[fileIdx]) return null;
    if (pdfDocCache.current.has(fileIdx)) return pdfDocCache.current.get(fileIdx);
    if (sheet.pages[fileIdx].fileType !== 'application/pdf') return null;

    try {
        const arrayBuffer = await sheet.pages[fileIdx].blob.arrayBuffer();
        const doc = await pdfjs.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        if (sheetId === currentViewRef.current.sheetId) {
            pdfDocCache.current.set(fileIdx, doc);
            return doc;
        }
        return null;
    } catch (e) {
        return null;
    }
  }, [sheet, sheetId]);

  const renderPage = useCallback(async (fIdx: number, pIdx: number, isPriority = false) => {
    const key = `${sheetId}-${fIdx}-${pIdx}`;

    if (canvasCache.current.has(key)) {
        if (isPriority) {
            const cachedCanvas = canvasCache.current.get(key);
            const mainCanvas = pdfCanvasRef.current;
            if (mainCanvas && cachedCanvas) {
                mainCanvas.width = cachedCanvas.width;
                mainCanvas.height = cachedCanvas.height;
                setDimensions({ width: cachedCanvas.width, height: cachedCanvas.height });
                mainCanvas.getContext('2d')?.drawImage(cachedCanvas, 0, 0);
                setTimeout(updateDisplayScale, 0);
            }
            setLoading(false);
        }
        return;
    }

    const doc = await getPdfDoc(fIdx);
    if (!doc || sheetId !== currentViewRef.current.sheetId || fIdx !== currentViewRef.current.fileIndex) return;

    try {
        const page = await doc.getPage(pIdx + 1);
        const container = containerRef.current;
        if (!container) return;

        const viewport = page.getViewport({ scale: 2 });
        const offscreenCanvas = document.createElement('canvas');
        offscreenCanvas.width = viewport.width;
        offscreenCanvas.height = viewport.height;

        const task = page.render({
            canvasContext: offscreenCanvas.getContext('2d')!,
            viewport
        });

        renderTasks.current.set(key, task);
        await task.promise;

        if (sheetId === currentViewRef.current.sheetId && fIdx === currentViewRef.current.fileIndex) {
            canvasCache.current.set(key, offscreenCanvas);
            if (isPriority && pIdx === currentViewRef.current.pageIndex) {
                const mainCanvas = pdfCanvasRef.current;
                if (mainCanvas) {
                    mainCanvas.width = offscreenCanvas.width;
                    mainCanvas.height = offscreenCanvas.height;
                    setDimensions({ width: offscreenCanvas.width, height: offscreenCanvas.height });
                    mainCanvas.getContext('2d')?.drawImage(offscreenCanvas, 0, 0);
                    setTimeout(updateDisplayScale, 0);
                }
                setLoading(false);
            }
        }
    } catch (e) {
        if (isPriority) setLoading(false);
    }
  }, [sheetId, getPdfDoc, updateDisplayScale]);

  useEffect(() => {
    if (!sheet || !sheet.pages) return;
    const currentFile = sheet.pages[activeFileIndex];
    if (!currentFile) return;

    if (currentFile.fileType === 'application/pdf') {
        getPdfDoc(activeFileIndex).then(doc => {
            if (!doc || sheetId !== currentViewRef.current.sheetId) return;
            setNumSubPages(doc.numPages);
            if (subPageIndex === -1) {
                const last = doc.numPages - 1;
                currentViewRef.current.pageIndex = last;
                setSubPageIndex(last);
            } else {
                renderPage(activeFileIndex, subPageIndex, true);
            }
        });
    } else {
        setNumSubPages(1);
        setSubPageIndex(0);
        currentViewRef.current.pageIndex = 0;
        setLoading(false);
    }
  }, [sheet, activeFileIndex, subPageIndex, sheetId, getPdfDoc, renderPage]);

  // Drawing Logic
  const handlePointerDown = (e: React.PointerEvent) => {
    if (!isAnnotating) return;
    if (textInput) {
        handleFinishText();
        return;
    }

    // Close font picker if clicking outside
    if (showFontPicker) {
        setShowFontPicker(false);
        return;
    }

    e.stopPropagation();

    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (currentTool === 'eraser') {
      const newStrokes = allStrokes.filter(s => {
        if (s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex) return true;
        return !s.points.some(p => Math.sqrt(Math.pow(p.x - x, 2) + Math.pow(p.y - y, 2)) < 0.02);
      });
      setAllStrokes(newStrokes);
      storage.saveAnnotation(sheetId, newStrokes);
      return;
    }

    const newStroke: Stroke = {
      id: crypto.randomUUID(),
      type: currentTool as AnnotationType,
      points: [{ x, y }],
      color: selectedColor,
      width: selectedWidth,
      fontFamily: selectedFont,
      fileIndex: activeFileIndex,
      pageIndex: subPageIndex
    };
    setActiveStroke(newStroke);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isAnnotating || !activeStroke) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    if (activeStroke.type === 'path') {
        setActiveStroke(prev => prev ? { ...prev, points: [...prev.points, { x, y }] } : null);
    } else {
        setActiveStroke(prev => prev ? { ...prev, points: [prev.points[0], { x, y }] } : null);
    }
  };

  const handlePointerUp = () => {
    if (!activeStroke) return;

    if (activeStroke.type === 'text') {
        const p0 = activeStroke.points[0];
        const p1 = activeStroke.points[activeStroke.points.length - 1];

        const x = Math.min(p0.x, p1.x);
        const y = Math.min(p0.y, p1.y);
        const w = Math.max(0.02, Math.abs(p1.x - p0.x));
        const h = Math.max(0.015, Math.abs(p1.y - p0.y));

        updateDisplayScale();
        setTextInput({ x, y, w, h, value: '' });
        setActiveStroke(null);
    } else {
        const updated = [...allStrokes, activeStroke];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
        setActiveStroke(null);
    }
  };

  const handleFinishText = () => {
    if (textInput && textInput.value.trim()) {
        const newTextAnnotation: Stroke = {
            id: crypto.randomUUID(),
            type: 'text',
            points: [
                { x: textInput.x, y: textInput.y },
                { x: textInput.x + textInput.w, y: textInput.y + textInput.h }
            ],
            color: selectedColor,
            width: selectedWidth,
            fontFamily: selectedFont,
            text: textInput.value,
            fileIndex: activeFileIndex,
            pageIndex: subPageIndex
        };
        const updated = [...allStrokes, newTextAnnotation];
        setAllStrokes(updated);
        storage.saveAnnotation(sheetId, updated);
    }
    setTextInput(null);
  };

  const handleNextPage = () => {
    if (isPdf && subPageIndex < numSubPages - 1) {
        setSubPageIndex(prev => prev + 1);
        currentViewRef.current.pageIndex++;
    } else if (sheet && sheet.pages && activeFileIndex < sheet.pages.length - 1) {
        setActiveFileIndex(prev => prev + 1);
        setSubPageIndex(0);
        currentViewRef.current.fileIndex++;
        currentViewRef.current.pageIndex = 0;
    } else if (hasNext) {
        onNext();
    }
  };

  const handlePrevPage = () => {
    if (isPdf && subPageIndex > 0) {
        setSubPageIndex(prev => prev - 1);
        currentViewRef.current.pageIndex--;
    } else if (activeFileIndex > 0) {
        setActiveFileIndex(prev => prev - 1);
        setSubPageIndex(-1);
        currentViewRef.current.fileIndex--;
        currentViewRef.current.pageIndex = -1;
    } else if (hasPrev) {
        onPrev();
    }
  };

  const handleJumpPage = (e?: React.FormEvent) => {
    e?.preventDefault();
    const val = parseInt(jumpInputValue);
    if (!isNaN(val) && val >= 1 && val <= totalDisplayPages) {
        if (isPdf) {
            setSubPageIndex(val - 1);
            currentViewRef.current.pageIndex = val - 1;
        } else {
            setActiveFileIndex(val - 1);
            currentViewRef.current.fileIndex = val - 1;
        }
        setShowJumpDropdown(false);
        setJumpInputValue('');
    }
  };

  useEffect(() => {
    if (showJumpDropdown) {
        setTimeout(() => jumpInputRef.current?.focus(), 50);
    }
  }, [showJumpDropdown]);

  useEffect(() => {
    if (textInput && inlineTextRef.current) {
        inlineTextRef.current.focus();
    }
  }, [textInput]);

  useEffect(() => {
    if (showFontPicker && fontSearchInputRef.current) {
        fontSearchInputRef.current.focus();
    }
  }, [showFontPicker]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (textInput) {
          if (e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              handleFinishText();
          }
          if (e.key === 'Escape') {
              setTextInput(null);
          }
          return;
      }
      if (PAGE_TURN_KEYS.NEXT.includes(e.key)) handleNextPage();
      else if (PAGE_TURN_KEYS.PREV.includes(e.key)) handlePrevPage();
      else if (e.key === 'Escape') {
          if (showJumpDropdown) setShowJumpDropdown(false);
          else if (showQueue) setShowQueue(false);
          else if (showFontPicker) setShowFontPicker(false);
          else onClose();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNextPage, handlePrevPage, onClose, showJumpDropdown, showQueue, textInput, showFontPicker]);

  const handleContainerClick = (e: React.MouseEvent) => {
    if (isAnnotating || showJumpDropdown || showQueue || textInput || showFontPicker) {
        if (showJumpDropdown) setShowJumpDropdown(false);
        if (showQueue) setShowQueue(false);
        if (showFontPicker) setShowFontPicker(false);
        return;
    }
    const x = e.clientX / window.innerWidth;
    if (x < 0.2) handlePrevPage();
    else if (x > 0.8) handleNextPage();
    else setShowControls(!showControls);
  };

  const filteredFonts = FONTS.filter(f => 
    f.label.toLowerCase().includes(fontSearchQuery.toLowerCase())
  );

  const renderAnnotation = (anno: Stroke, key: string | number, isGhost = false) => {
      const { type = 'path', points, color, width, text, fontFamily } = anno;
      if (points.length === 0) return null;

      const p0 = points[0];
      const p1 = points[points.length - 1];

      const x0 = p0.x * dimensions.width;
      const y0 = p0.y * dimensions.height;
      const x1 = p1.x * dimensions.width;
      const y1 = p1.y * dimensions.height;

      const strokeProps = {
          key,
          stroke: color,
          strokeWidth: width,
          fill: 'none',
          strokeLinecap: 'round' as const,
          strokeLinejoin: 'round' as const,
          className: isGhost ? 'opacity-50' : ''
      };

      if (isGhost && type === 'text') {
        return (
            <rect 
                key={key}
                x={Math.min(x0, x1)}
                y={Math.min(y0, y1)}
                width={Math.max(2, Math.abs(x1 - x0))}
                height={Math.max(2, Math.abs(y1 - y0))}
                stroke={color}
                strokeWidth={2}
                fill={`${color}22`}
                strokeDasharray="5,5"
                className="opacity-60"
            />
        );
      }

      switch (type) {
          case 'path':
              return (
                  <path 
                    {...strokeProps}
                    d={points.map((p, j) => `${j === 0 ? 'M' : 'L'} ${p.x * dimensions.width} ${p.y * dimensions.height}`).join(' ')}
                  />
              );
          case 'rect':
              return (
                  <rect 
                    {...strokeProps}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1)}
                    width={Math.abs(x1 - x0)}
                    height={Math.abs(y1 - y0)}
                  />
              );
          case 'circle':
              const rx = Math.abs(x1 - x0) / 2;
              const ry = Math.abs(y1 - y0) / 2;
              return (
                  <ellipse 
                    {...strokeProps}
                    cx={Math.min(x0, x1) + rx}
                    cy={Math.min(y0, y1) + ry}
                    rx={rx}
                    ry={ry}
                  />
              );
          case 'text':
              const fs = getNaturalFontSize(width);
              return (
                  <text 
                    key={key}
                    x={Math.min(x0, x1)}
                    y={Math.min(y0, y1) + (fs * 0.8)}
                    fill={color}
                    fontSize={fs}
                    fontFamily={fontFamily || 'sans-serif'}
                    fontWeight="bold"
                    className={isGhost ? 'opacity-30' : ''}
                  >
                      {text}
                  </text>
              );
          default:
              return null;
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 flex flex-col z-50 overflow-hidden touch-none select-none">
      {/* HUD */}
      <div className={`absolute top-0 left-0 right-0 p-4 bg-gradient-to-b from-black/80 to-transparent z-50 flex items-center justify-between transition-opacity duration-200 ${showControls || isAnnotating ? 'opacity-100' : 'opacity-0'}`}>
        <div className="flex items-center gap-3">
             <button onClick={onClose} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"><X size={20} /></button>
             <div className="text-white relative">
                <h2 className="font-bold text-lg truncate max-w-[150px] sm:max-w-md">{title}</h2>
                <button 
                  onClick={(e) => { e.stopPropagation(); if (!loading) setShowJumpDropdown(!showJumpDropdown); }}
                  className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${loading ? 'text-slate-600 cursor-wait' : 'text-slate-400 hover:text-blue-400'}`}
                >
                    {loading ? (
                        <span>Synchronizing...</span>
                    ) : (
                        <span className="bg-white/5 px-2 py-1 rounded flex items-center gap-1.5 active:bg-white/10">
                            PAGE {currentDisplayPage} OF {totalDisplayPages} <ChevronDown size={10}/>
                        </span>
                    )}
                </button>
                {showJumpDropdown && (
                    <div className="absolute top-full left-0 mt-2 w-48 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl p-4 animate-in slide-in-from-top-2 duration-200 z-[110]" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center gap-2 mb-3 text-slate-400"><BookOpen size={14} /><span className="text-[10px] font-black uppercase tracking-widest">Go to page</span></div>
                        <form onSubmit={handleJumpPage} className="flex gap-2">
                            <input ref={jumpInputRef} type="number" min="1" max={totalDisplayPages} value={jumpInputValue} onChange={e => setJumpInputValue(e.target.value)} placeholder={`1-${totalDisplayPages}`} className="flex-1 bg-slate-800 border border-white/5 rounded-xl px-3 py-2 text-white font-bold text-lg outline-none focus:ring-1 focus:ring-blue-500" />
                            <button type="submit" className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-500 transition-colors"><ArrowRight size={20} /></button>
                        </form>
                    </div>
                )}
             </div>
        </div>
        <div className="flex items-center gap-2">
             <button onClick={() => { setIsAnnotating(!isAnnotating); if (!isAnnotating && currentTool === 'eraser') setCurrentTool('path'); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool !== 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><PenTool size={20} /></button>
             <button onClick={() => { setCurrentTool('eraser'); setIsAnnotating(true); }} className={`p-3 rounded-full transition-all ${isAnnotating && currentTool === 'eraser' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white/10 text-white'}`}><Eraser size={20} /></button>
             <button onClick={(e) => { e.stopPropagation(); setShowQueue(!showQueue); }} className={`p-3 rounded-full transition-colors ${showQueue ? 'bg-blue-600 text-white' : 'bg-white/10 text-white'}`}><List size={20} /></button>
        </div>
      </div>

      <div ref={containerRef} className={`flex-1 relative flex items-center justify-center bg-zinc-950 ${isAnnotating ? 'cursor-crosshair' : 'cursor-default'}`} onClick={handleContainerClick} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}>
        {(loading || !sheet || subPageIndex === -1) && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-40">
                <Loader2 className="animate-spin text-blue-500 mb-4" size={48} />
                <p className="text-slate-500 text-xs font-black uppercase tracking-widest animate-pulse">Synchronizing Piece...</p>
            </div>
        )}
        <canvas ref={pdfCanvasRef} className={`max-w-full max-h-full object-contain shadow-2xl transition-opacity duration-300 pointer-events-none ${isPdf ? 'block' : 'hidden'}`} style={{ opacity: loading || !sheet || subPageIndex === -1 ? 0 : 1 }} />
        {!loading && sheet && currentFile && !isPdf && (
            <img ref={imageRef} src={URL.createObjectURL(currentFile.blob)} className="max-w-full max-h-full object-contain shadow-2xl pointer-events-none" alt="Sheet Page" onLoad={(e) => { const img = e.target as HTMLImageElement; setDimensions({ width: img.naturalWidth, height: img.naturalHeight }); setTimeout(updateDisplayScale, 100); }} />
        )}
        {!loading && sheet && subPageIndex !== -1 && (
            <svg className="absolute inset-0 w-full h-full pointer-events-none z-10" viewBox={`0 0 ${dimensions.width} ${dimensions.height}`} preserveAspectRatio="none">
                {allStrokes.filter(s => s.fileIndex === activeFileIndex && s.pageIndex === subPageIndex).map((stroke, i) => renderAnnotation(stroke, i))}
                {activeStroke && renderAnnotation(activeStroke, 'active', true)}
            </svg>
        )}
        {textInput && (
            <div className="absolute z-50 flex items-center pointer-events-auto" style={{ left: `${textInput.x * 100}%`, top: `${textInput.y * 100}%`, width: `${textInput.w * 100}%`, height: `${textInput.h * 100}%` }} onPointerDown={e => e.stopPropagation()}>
                <textarea 
                    ref={inlineTextRef}
                    value={textInput.value}
                    onChange={e => setTextInput({ ...textInput, value: e.target.value })}
                    onBlur={handleFinishText}
                    className="w-full h-full bg-slate-900/90 border-2 border-blue-500 rounded px-2 py-1 text-white font-bold outline-none shadow-2xl resize-none overflow-hidden"
                    style={{ 
                        color: selectedColor,
                        fontSize: `${getNaturalFontSize(selectedWidth) * displayScale}px`,
                        fontFamily: selectedFont,
                        lineHeight: '1.2'
                    }}
                />
            </div>
        )}
      </div>

      {isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-slate-900/95 backdrop-blur-2xl border border-white/10 p-4 rounded-[3rem] shadow-[0_25px_60px_rgba(0,0,0,0.6)] flex items-center gap-6 z-50 animate-in slide-in-from-bottom-8 duration-300 max-w-[98vw] overflow-x-auto no-scrollbar relative min-h-[72px]">

              {/* Tool Selection */}
              <div className="flex items-center bg-black/40 rounded-full p-1.5 shrink-0">
                  <button onClick={() => setCurrentTool('path')} className={`p-3 rounded-full transition-all ${currentTool === 'path' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><PenTool size={20} /></button>
                  <button onClick={() => setCurrentTool('text')} className={`p-3 rounded-full transition-all ${currentTool === 'text' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Type size={20} /></button>
                  <button onClick={() => setCurrentTool('rect')} className={`p-3 rounded-full transition-all ${currentTool === 'rect' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Square size={20} /></button>
                  <button onClick={() => setCurrentTool('circle')} className={`p-3 rounded-full transition-all ${currentTool === 'circle' ? 'bg-blue-600 text-white shadow-lg scale-110' : 'text-slate-500 hover:text-slate-300'}`}><Circle size={20} /></button>
              </div>

              <div className="w-px h-10 bg-white/10 shrink-0" />

              {/* Color Selection */}
              <div className="flex items-center gap-3 shrink-0">
                  {COLORS.map(c => (
                      <button key={c} onClick={() => { setSelectedColor(c); if (currentTool === 'eraser') setCurrentTool('path'); }} className={`w-8 h-8 rounded-full border-2 transition-all ${selectedColor === c && currentTool !== 'eraser' ? 'scale-125 border-white shadow-xl' : 'border-transparent scale-100 opacity-50'}`} style={{ backgroundColor: c }} />
                  ))}
              </div>

              <div className="w-px h-10 bg-white/10 shrink-0" />

              {/* Stroke Width Selection */}
              <div className="flex items-center gap-4 shrink-0 px-1">
                  {[3, 6, 12].map(w => (
                      <button key={w} onClick={() => { setSelectedWidth(w); if (currentTool === 'eraser') setCurrentTool('path'); }} className={`flex items-center justify-center transition-all ${selectedWidth === w && currentTool !== 'eraser' ? 'text-blue-400 scale-125' : 'text-slate-500'}`}>
                          <div className="rounded-full bg-current" style={{ width: Math.max(8, w + 4), height: Math.max(8, w + 4) }} />
                      </button>
                  ))}
              </div>

              {/* Font Picker Dropdown Trigger */}
              {currentTool === 'text' && (
                  <>
                    <div className="w-px h-10 bg-white/10 shrink-0" />
                    <div className="relative shrink-0">
                        <button 
                            onClick={(e) => { e.stopPropagation(); setShowFontPicker(!showFontPicker); }}
                            className={`flex items-center gap-3 px-6 py-3 rounded-full border transition-all ${showFontPicker ? 'bg-blue-600 text-white border-blue-500' : 'bg-black/40 text-slate-400 border-white/10'}`}
                        >
                            <span className="text-xs font-black uppercase tracking-wider truncate max-w-[100px]" style={{ fontFamily: selectedFont }}>
                                {FONTS.find(f => f.value === selectedFont)?.label || 'Font'}
                            </span>
                            {showFontPicker ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                        </button>

                        {/* Searchable Font Picker Dropdown */}
                        {showFontPicker && (
                            <div 
                                className="absolute bottom-full left-0 mb-6 w-72 bg-slate-900/98 backdrop-blur-3xl border border-white/10 rounded-3xl shadow-[0_25px_50px_-12px_rgba(0,0,0,0.9)] overflow-hidden animate-in slide-in-from-bottom-4 duration-200"
                                onClick={e => e.stopPropagation()}
                            >
                                <div className="p-4 border-b border-white/5 relative">
                                    <Search className="absolute left-7 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                                    <input 
                                        ref={fontSearchInputRef}
                                        type="text" 
                                        placeholder="Search fonts..."
                                        className="w-full bg-black/40 border border-white/10 rounded-2xl pl-11 pr-4 py-3 text-sm text-white outline-none focus:ring-1 focus:ring-blue-500"
                                        value={fontSearchQuery}
                                        onChange={e => setFontSearchQuery(e.target.value)}
                                    />
                                </div>
                                <div className="max-h-72 overflow-y-auto py-3 no-scrollbar">
                                    {filteredFonts.length > 0 ? (
                                        filteredFonts.map(f => (
                                            <button 
                                                key={f.value}
                                                onClick={() => { setSelectedFont(f.value); setShowFontPicker(false); setFontSearchQuery(''); }}
                                                className={`w-full flex items-center justify-between px-6 py-4 hover:bg-white/10 transition-colors text-left ${selectedFont === f.value ? 'text-blue-400' : 'text-slate-300'}`}
                                            >
                                                <span className="text-base font-medium" style={{ fontFamily: f.value }}>{f.label}</span>
                                                {selectedFont === f.value && <Check size={18} />}
                                            </button>
                                        ))
                                    ) : (
                                        <div className="px-6 py-12 text-center text-slate-500 text-sm italic">No fonts found</div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                  </>
              )}

              <div className="w-px h-10 bg-white/10 shrink-0" />

              <button onClick={() => { const updated = allStrokes.filter(s => s.fileIndex !== activeFileIndex || s.pageIndex !== subPageIndex); setAllStrokes(updated); storage.saveAnnotation(sheetId, updated); }} className="p-3 text-slate-500 hover:text-red-400 transition-colors shrink-0" title="Clear Page"><RotateCcw size={22} /></button>

              <button onClick={() => { setIsAnnotating(false); setShowFontPicker(false); }} className="bg-white/10 hover:bg-blue-600 text-white px-8 py-3 rounded-full text-xs font-black uppercase tracking-[0.25em] transition-all shrink-0 active:scale-95 shadow-lg">Done</button>
          </div>
      )}

      {showQueue && queue && (
          <div className="absolute top-20 right-4 z-[100] w-64 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-4 duration-200">
              <div className="p-4 border-b border-white/5 flex items-center justify-between"><h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.2em]">Queue</h3><button onClick={() => setShowQueue(false)} className="text-slate-500 hover:text-white"><X size={16}/></button></div>
              <div className="overflow-y-auto no-scrollbar py-2 max-h-[60vh]">
                  {queue.map((item, idx) => (
                      <button key={idx} onClick={() => { onJumpTo(idx); setShowQueue(false); }} className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/5 transition-colors text-left ${idx === currentQueueIndex ? 'bg-blue-600/20 text-blue-400 border-l-4 border-blue-500' : 'text-slate-300'}`}><span className="text-[10px] font-mono text-slate-500 w-4">{idx + 1}</span><span className="text-sm font-medium truncate flex-1">{item.name}</span></button>
                  ))}
              </div>
          </div>
      )}
      {!loading && sheet && !isAnnotating && (
          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur-md rounded-full text-[10px] font-black tracking-[0.2em] text-slate-400 border border-white/10 pointer-events-none z-30 uppercase shadow-2xl">Piece {currentQueueIndex + 1} of {queue.length}</div>
      )}
    </div>
  );
};

export default Viewer;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, ListMusic, Trash2, Play, X, Check, Pencil, GripVertical, Search, Import, AlertTriangle, FileWarning, RefreshCw, Copy, FileText } from 'lucide-react';
import { Setlist, Sheet } from '../types';
import { storage } from '../services/storage';
import { processBatchImport } from '../utils/fileProcessor';

interface SetlistsProps {
  setlists: Setlist[];
  sheets: Sheet[];
  onRefresh: () => void;
  onPlay: (setlist: Setlist) => void;
}

interface DeleteModalState {
    isOpen: boolean;
    setlist: Setlist | null;
}

interface ConflictState {
    newSheets: Sheet[];
    duplicates: Sheet[];
    setlistName?: string;
}

const Setlists: React.FC<SetlistsProps> = ({ setlists, sheets, onRefresh, onPlay }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newSetName, setNewSetName] = useState('');
  const [selectedSheetIds, setSelectedSheetIds] = useState<string[]>([]);

  // DRAG STATE
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);
  const [hoverIndex, setHoverIndex] = useState<number | null>(null);
  const [dragOffset, setDragOffset] = useState(0);
  const startPointerY = useRef(0);
  const itemHeights = useRef<number[]>([]);
  const containerRect = useRef<DOMRect | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [deleteModal, setDeleteModal] = useState<DeleteModalState>({ isOpen: false, setlist: null });
  const [conflictData, setConflictData] = useState<ConflictState | null>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const [listSearch, setListSearch] = useState('');
  const [librarySearch, setLibrarySearch] = useState('');

  const startCreate = () => {
    setEditingId(null);
    setNewSetName('');
    setSelectedSheetIds([]);
    setIsEditing(true);
  };

  const startEdit = (setlist: Setlist) => {
    setEditingId(setlist.id);
    setNewSetName(setlist.name);
    setSelectedSheetIds([...setlist.sheetIds]);
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newSetName.trim()) return;
    const existingSetlist = editingId ? setlists.find(s => s.id === editingId) : null;
    const setlist: Setlist = {
      id: editingId || crypto.randomUUID(),
      name: newSetName,
      sheetIds: selectedSheetIds,
      dateCreated: existingSetlist ? existingSetlist.dateCreated : Date.now(),
    };
    await storage.saveSetlist(setlist);
    setIsEditing(false);
    onRefresh();
  };

  const toggleSelection = (id: string) => {
    setSelectedSheetIds(prev => 
      prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
    );
  };

  // --- REORDERING LOGIC ---

  const handlePointerDown = (e: React.PointerEvent, index: number) => {
    const target = e.currentTarget as HTMLElement;
    target.setPointerCapture(e.pointerId);

    if (containerRef.current) {
        containerRect.current = containerRef.current.getBoundingClientRect();
        const children = Array.from(containerRef.current.children);
        // Fix: Cast child to HTMLElement to avoid 'unknown' type error in getBoundingClientRect call
        itemHeights.current = children.map(child => (child as HTMLElement).getBoundingClientRect().height + 8); 
    }

    startPointerY.current = e.clientY;
    setDraggedIndex(index);
    setHoverIndex(index);
    setDragOffset(0);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (draggedIndex === null || !containerRect.current) return;

    const currentY = e.clientY;
    const deltaY = currentY - startPointerY.current;
    setDragOffset(deltaY);

    const relativeY = currentY - containerRect.current.top + (containerRef.current?.scrollTop || 0);

    let currentTotalHeight = 0;
    let newHoverIndex = 0;

    for (let i = 0; i < itemHeights.current.length; i++) {
        const h = itemHeights.current[i];
        if (relativeY > currentTotalHeight + h / 2) {
            newHoverIndex = i;
        }
        currentTotalHeight += h;
    }

    const clampedIndex = Math.max(0, Math.min(newHoverIndex, selectedSheetIds.length - 1));
    if (clampedIndex !== hoverIndex) {
        setHoverIndex(clampedIndex);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (draggedIndex !== null && hoverIndex !== null && draggedIndex !== hoverIndex) {
        const newIds = [...selectedSheetIds];
        const [removed] = newIds.splice(draggedIndex, 1);
        newIds.splice(hoverIndex, 0, removed);
        setSelectedSheetIds(newIds);
    }

    const target = e.currentTarget as HTMLElement;
    if (target.hasPointerCapture(e.pointerId)) {
        target.releasePointerCapture(e.pointerId);
    }
    setDraggedIndex(null);
    setHoverIndex(null);
    setDragOffset(0);
  };

  const getItemStyle = (index: number) => {
    if (draggedIndex === null || hoverIndex === null) return {};

    if (index === draggedIndex) {
        return {
            transform: `translateY(${dragOffset}px) scale(1.03)`,
            zIndex: 50,
            boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.8)',
            borderColor: '#3b82f6', 
            backgroundColor: '#1e293b', 
            transition: 'none',
        };
    }

    let shift = 0;
    const height = itemHeights.current[draggedIndex] || 64;

    if (draggedIndex < hoverIndex) {
        if (index > draggedIndex && index <= hoverIndex) shift = -height;
    } else if (draggedIndex > hoverIndex) {
        if (index < draggedIndex && index >= hoverIndex) shift = height;
    }

    return {
        transform: `translateY(${shift}px)`,
        transition: 'transform 0.25s cubic-bezier(0.2, 0, 0, 1)',
    };
  };

  const handleDeleteClick = (e: React.MouseEvent, setlist: Setlist) => {
    e.stopPropagation();
    setDeleteModal({ isOpen: true, setlist });
  };

  const confirmDelete = async () => {
      if (deleteModal.setlist) {
          await storage.deleteSetlist(deleteModal.setlist.id);
          setDeleteModal({ isOpen: false, setlist: null });
          onRefresh();
      }
  };

  const handleImportSetlist = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
        const result = await processBatchImport(e.target.files);
        if (result.sheets.length > 0) {
            const currentSheets = await storage.getAllSheets();
            const duplicates = result.sheets.filter(newSheet => 
                currentSheets.some(existing => existing.name.trim().toLowerCase() === newSheet.name.trim().toLowerCase())
            );

            if (duplicates.length > 0) {
                setConflictData({ 
                    newSheets: result.sheets, 
                    duplicates, 
                    setlistName: result.setlistName 
                });
            } else {
                await finalizeSetlistImport(result.sheets, false, result.setlistName);
            }
        } else if (result.error) {
            alert(result.error);
        }
    }
    if (e.target) e.target.value = '';
  };

  const finalizeSetlistImport = async (newSheets: Sheet[], overwrite: boolean, setlistName?: string) => {
      const currentSheets = await storage.getAllSheets();
      const finalSheetIds: string[] = [];

      for (const sheet of newSheets) {
          const existing = currentSheets.find(s => s.name.trim().toLowerCase() === sheet.name.trim().toLowerCase());
          let sheetToSave = sheet;

          if (existing && overwrite) {
              sheetToSave = {
                  ...sheet,
                  id: existing.id, 
                  tags: existing.tags,
                  tagIcons: existing.tagIcons,
                  dateAdded: Date.now()
              };
          }
          await storage.addSheet(sheetToSave);
          finalSheetIds.push(sheetToSave.id);
      }

      finalSheetIds.sort((a, b) => {
          const sA = newSheets.find(s => s.id === a || (overwrite && s.name === currentSheets.find(ex => ex.id === a)?.name));
          const sB = newSheets.find(s => s.id === b || (overwrite && s.name === currentSheets.find(ex => ex.id === b)?.name));
          return (sA?.name || '').localeCompare(sB?.name || '', undefined, { numeric: true });
      });

      const newSetlist: Setlist = {
          id: crypto.randomUUID(),
          name: setlistName || "Imported Setlist",
          sheetIds: finalSheetIds,
          dateCreated: Date.now()
      };

      await storage.saveSetlist(newSetlist);
      setConflictData(null);
      onRefresh();
  };

  const filteredSetlists = useMemo(() => {
    const q = listSearch.toLowerCase();
    return setlists.filter(l => l.name.toLowerCase().includes(q));
  }, [setlists, listSearch]);

  const filteredLibrary = useMemo(() => {
    const q = librarySearch.toLowerCase();
    return sheets.filter(s => s.name.toLowerCase().includes(q) || (s.tags && s.tags.some(t => t.toLowerCase().includes(q))));
  }, [sheets, librarySearch]);

  if (isEditing) {
    return (
      <div className="p-6 h-full flex flex-col">
        <div className="flex items-center justify-between mb-6">
           <h2 className="text-2xl font-bold text-white tracking-tight">{editingId ? 'Edit Setlist' : 'New Setlist'}</h2>
           <div className="flex gap-2">
             <button onClick={() => setIsEditing(false)} className="px-4 py-2 text-slate-400 hover:text-white transition-colors font-medium">Cancel</button>
             <button onClick={handleSave} disabled={!newSetName || selectedSheetIds.length === 0} className="flex items-center gap-2 bg-green-600 text-white px-5 py-2.5 rounded-xl hover:bg-green-500 disabled:opacity-50 transition-all shadow-lg shadow-green-900/20 active:scale-95">
                <Check size={18} /> <span className="font-bold">Save Setlist</span>
             </button>
           </div>
        </div>

        <div className="relative mb-6">
            <input 
                type="text" 
                placeholder="Ex: Tonight's Performance, Jazz Set, etc." 
                className="w-full bg-slate-800 border-2 border-slate-700 rounded-xl p-4 text-xl text-white focus:border-blue-500 outline-none transition-colors" 
                value={newSetName} 
                onChange={e => setNewSetName(e.target.value)} 
            />
        </div>

        <div className="flex-1 flex flex-col md:flex-row gap-6 overflow-hidden">
            <div className="flex-1 overflow-hidden flex flex-col bg-slate-800/40 rounded-2xl p-4 border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Add Library Pieces</h3>
                <div className="relative mb-4">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                    <input type="text" placeholder="Search library..." className="w-full bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2.5 text-sm text-slate-200 outline-none focus:ring-1 focus:ring-blue-500" value={librarySearch} onChange={(e) => setLibrarySearch(e.target.value)} />
                </div>
                <div className="overflow-y-auto space-y-2 flex-1 no-scrollbar">
                    {filteredLibrary.map(sheet => {
                        const isSelected = selectedSheetIds.includes(sheet.id);
                        return (
                            <button 
                                key={sheet.id} 
                                onClick={() => !isSelected && toggleSelection(sheet.id)} 
                                className={`w-full flex items-center p-3 rounded-xl border-2 transition-all text-left ${isSelected ? 'opacity-40 border-slate-700 bg-transparent grayscale' : 'cursor-pointer bg-slate-800 border-transparent hover:bg-slate-700 hover:border-blue-500/30'}`}
                            >
                                <div className={`w-7 h-7 rounded-lg flex items-center justify-center mr-3 shrink-0 transition-colors ${isSelected ? 'bg-slate-700' : 'bg-blue-600'}`}>
                                    {isSelected ? <Check size={14}/> : <Plus size={14} />}
                                </div>
                                <span className="text-slate-200 text-sm font-medium truncate">{sheet.name}</span>
                            </button>
                        );
                    })}
                </div>
            </div>

            <div className="flex-[1.5] overflow-y-auto min-h-0 bg-slate-800/40 rounded-2xl p-4 no-scrollbar border border-slate-700/50">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4">Performance Order</h3>
                {selectedSheetIds.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-48 text-slate-500 italic text-sm">
                        <ListMusic size={32} className="mb-2 opacity-20" />
                        Select pieces from the library to build your set
                    </div>
                ) : (
                    <div ref={containerRef} className="space-y-2 select-none relative pb-10">
                        {selectedSheetIds.map((id, index) => {
                            const sheet = sheets.find(s => s.id === id);
                            if (!sheet) return null;
                            const isBeingDragged = draggedIndex === index;
                            return (
                                <div 
                                    key={`${id}-${index}`} 
                                    style={getItemStyle(index)}
                                    className="flex items-center bg-slate-800 p-2 rounded-xl border border-slate-700 relative group"
                                >
                                    <div 
                                        className="p-3 text-slate-500 cursor-grab active:cursor-grabbing touch-none transition-colors hover:text-white"
                                        onPointerDown={(e) => handlePointerDown(e, index)}
                                        onPointerMove={handlePointerMove}
                                        onPointerUp={handlePointerUp}
                                    >
                                        <GripVertical size={20} />
                                    </div>
                                    <div className={`flex items-center flex-1 min-w-0 ${isBeingDragged ? 'pointer-events-none' : ''}`}>
                                        <div className="w-6 h-6 flex items-center justify-center text-[10px] font-black text-slate-600 bg-slate-900 rounded-md shrink-0">
                                            {index + 1}
                                        </div>
                                        <span className="flex-1 truncate mx-3 text-sm font-semibold text-white">{sheet.name}</span>
                                    </div>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); toggleSelection(id); }} 
                                        className={`p-3 text-slate-500 hover:text-red-500 transition-all ${isBeingDragged ? 'pointer-events-none opacity-0' : 'opacity-0 group-hover:opacity-100'}`}
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 pb-24">
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 gap-6">
        <div>
            <h1 className="text-4xl font-black text-white mb-2">Setlists</h1>
            <p className="text-slate-400 text-sm">Performance ready repertoire lists</p>
        </div>
        <div className="flex gap-3 items-center flex-wrap">
            <div className="relative group">
                <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-blue-500 transition-colors" />
                <input type="text" placeholder="Search sets..." className="bg-slate-800 border border-slate-700 rounded-xl pl-10 pr-4 py-2.5 text-white focus:border-blue-500 outline-none transition-all w-full md:w-48 lg:w-64" value={listSearch} onChange={(e) => setListSearch(e.target.value)} />
            </div>

            <button onClick={() => importInputRef.current?.click()} className="flex items-center gap-2 bg-indigo-600/10 text-indigo-400 border border-indigo-600/20 px-4 py-2 rounded-xl hover:bg-indigo-600 hover:text-white transition-all shadow-lg active:scale-95">
                <Import size={16} />
                <span className="font-bold text-xs">Import Set</span>
            </button>

            <button onClick={startCreate} className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2 rounded-xl hover:bg-blue-500 transition-all shadow-xl shadow-blue-900/20 active:scale-95">
                <Plus size={18} />
                <span className="font-bold text-xs">Create New</span>
            </button>

            <input type="file" ref={importInputRef} className="hidden" 
                // @ts-ignore
                webkitdirectory="" directory="" multiple onChange={handleImportSetlist} 
            />
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
          {filteredSetlists.map(list => (
            <div key={list.id} className="bg-slate-800/80 rounded-2xl p-4 sm:p-5 flex items-center justify-between hover:bg-slate-800 hover:shadow-2xl transition-all border border-slate-700/50 group">
               <div className="flex items-center gap-4 sm:gap-5 cursor-pointer flex-1 min-w-0" onClick={() => onPlay(list)}>
                  <div className="p-3 bg-slate-900 rounded-2xl text-slate-500 group-hover:text-blue-400 transition-colors shrink-0"><ListMusic size={24} /></div>
                  <div className="min-w-0">
                      <h3 className="text-lg font-bold text-white group-hover:text-blue-400 transition-colors truncate">{list.name}</h3>
                      <div className="flex items-center flex-wrap gap-x-2 gap-y-1 mt-1">
                          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest whitespace-nowrap">{list.sheetIds.length} pieces</span>
                          <span className="w-1 h-1 rounded-full bg-slate-700 hidden xs:block" />
                          <span className="text-[10px] text-slate-500 whitespace-nowrap">{new Date(list.dateCreated).toLocaleDateString()}</span>
                      </div>
                  </div>
               </div>
               <div className="flex items-center gap-2 ml-4 shrink-0">
                   <button onClick={() => onPlay(list)} className="p-2 px-3 bg-green-600 text-white rounded-xl hover:bg-green-500 transition-all shadow-lg shadow-green-900/20 active:scale-90 flex items-center gap-1.5 group/play">
                       <Play size={16} fill="currentColor" />
                       <span className="font-black text-[9px] uppercase tracking-widest hidden sm:block">Start Gig</span>
                   </button>
                   <div className="w-px h-6 bg-slate-700 mx-1 hidden md:block" />
                   <button onClick={() => startEdit(list)} className="p-2 text-slate-500 hover:text-blue-400 hover:bg-blue-400/10 rounded-xl transition-all"><Pencil size={16} /></button>
                   <button onClick={(e) => handleDeleteClick(e, list)} className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"><Trash2 size={16} /></button>
               </div>
            </div>
          ))}

          {filteredSetlists.length === 0 && (
              <div className="py-24 text-center">
                  <p className="text-slate-500 font-medium">No setlists found matching "{listSearch}"</p>
              </div>
          )}
      </div>

      {/* Duplicate Conflict Resolution Modal */}
      {conflictData && (
          <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
              <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 w-full max-w-lg shadow-2xl animate-in zoom-in-95 duration-200">
                  <div className="w-16 h-16 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                      <FileWarning size={32} className="text-amber-500" />
                  </div>
                  <h2 className="text-2xl font-bold text-white text-center mb-2">Duplicate Sheets in Setlist</h2>
                  <p className="text-slate-400 text-center text-sm mb-6 leading-relaxed">
                      The following sheets in your imported setlist already exist in your library.
                  </p>

                  <div className="max-h-48 overflow-y-auto mb-8 pr-2 space-y-2 no-scrollbar">
                      {conflictData.duplicates.map(d => (
                          <div key={d.id} className="flex items-center gap-3 p-3 bg-slate-800/50 rounded-xl border border-slate-700/50">
                              <FileText size={16} className="text-slate-500" />
                              <span className="text-sm font-medium text-white truncate flex-1">{d.name}</span>
                              <span className="text-[10px] font-black uppercase tracking-tighter text-amber-500 bg-amber-500/10 px-2 py-0.5 rounded">Conflict</span>
                          </div>
                      ))}
                  </div>

                  <div className="flex flex-col gap-3">
                      <button 
                        onClick={() => finalizeSetlistImport(conflictData.newSheets, true, conflictData.setlistName)} 
                        className="w-full flex items-center justify-center gap-2 py-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-500 transition-all font-bold shadow-lg shadow-blue-900/20"
                      >
                          <RefreshCw size={20} /> Overwrite Library Content
                      </button>
                      <button 
                        onClick={() => finalizeSetlistImport(conflictData.newSheets, false, conflictData.setlistName)} 
                        className="w-full flex items-center justify-center gap-2 py-4 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold"
                      >
                          <Copy size={20} /> Keep Both (New Copies)
                      </button>
                      <button 
                        onClick={() => setConflictData(null)} 
                        className="w-full py-3 text-slate-500 hover:text-white transition-colors text-sm font-medium"
                      >
                          Cancel Import
                      </button>
                  </div>
              </div>
          </div>
      )}

      {deleteModal.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setDeleteModal({ isOpen: false, setlist: null })}>
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 w-full max-w-md shadow-2xl animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle size={32} className="text-red-500" />
            </div>
            <h2 className="text-2xl font-bold text-white text-center mb-2">Delete Setlist?</h2>
            <p className="text-slate-400 text-center text-sm mb-8 px-4 leading-relaxed">This will remove the "{deleteModal.setlist?.name}" playlist. Your library files and annotations are safe.</p>
            <div className="flex gap-3">
                <button onClick={() => setDeleteModal({ isOpen: false, setlist: null })} className="flex-1 py-3.5 bg-slate-800 text-white rounded-2xl hover:bg-slate-700 transition-all font-bold">Cancel</button>
                <button onClick={confirmDelete} className="flex-1 py-3.5 bg-red-600 text-white rounded-2xl hover:bg-red-500 transition-all font-bold shadow-lg shadow-red-900/20">Delete List</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Setlists;

